INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cell70',
  'med-admission-barrons',
  'medium',
  'G0 phase refers to:',
  'Faza G0 se referă la:',
  '["A phase of active DNA replication","A resting state where cells have exited the cell cycle","The phase after mitosis","The phase of chromosome condensation","The phase of rapid cell growth"]'::jsonb,
  '["O fază de replicare activă a ADN","O stare de repaus unde celulele au ieșit din ciclul celular","Faza de după mitoză","Faza de condensare a cromozomilor","Faza de creștere rapidă a celulei"]'::jsonb,
  1,
  'G0 is a quiescent state where cells have exited the active cell cycle and are not preparing to divide.',
  'G0 este o stare de repaus unde celulele au ieșit din ciclul celular activ și nu se pregătesc să se dividă.',
  'cell-biology',
