INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cell73',
  'med-admission-barrons',
  'hard',
  'A cell with defective p53 tumor suppressor protein would most likely:',
  'O celulă cu proteină supresoare tumorală p53 defectă ar:',
  '["Have enhanced apoptosis","Continue dividing despite DNA damage","Be unable to synthesize proteins","Have increased cell adhesion","Produce excess ATP"]'::jsonb,
  '["Avea apoptoză crescută","Continua să se dividă în ciuda deteriorării ADN","Fi incapabilă să sintetizeze proteine","Avea adeziune celulară crescută","Produce ATP în exces"]'::jsonb,
  1,
  'p53 normally arrests the cell cycle when DNA is damaged and triggers apoptosis if damage cannot be repaired. Loss of p53 leads to uncontrolled division.',
  'p53 oprește în mod normal ciclul celular când ADN-ul este deteriorat și declanșează apoptoza dacă deteriorarea nu poate fi reparată. Pierderea p53 duce la diviziune necontrolată.',
