INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cell77',
  'med-admission-barrons',
  'hard',
  'The spindle assembly checkpoint (SAC) ensures:',
  'Punctul de control al asamblării fusului (SAC) asigură că:',
  '["DNA replication is complete","All chromosomes are properly attached to spindle fibers before anaphase","The cell has enough nutrients","Cytokinesis is complete","The G1 phase is extended"]'::jsonb,
  '["Replicarea ADN este completă","Toți cromozomii sunt atașați corespunzător de fibrele fusului înainte de anafază","Celula are suficienți nutrienți","Citokineza este completă","Faza G1 este prelungită"]'::jsonb,
  1,
  'The SAC prevents anaphase until all chromosomes are attached to spindle microtubules from both poles, preventing aneuploidy.',
  'SAC previne anafaza până când toți cromozomii sunt atașați de microtubulii fusului de la ambii poli, prevenind aneuploidia.',
