INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cell88',
  'med-admission-barrons',
  'hard',
  'Which of the following correctly describes the relationship between Rb, CDKs, and cell cycle progression?',
  'Care dintre următoarele descrie corect relația dintre Rb, CDK-uri și progresia ciclului celular?',
  '["CDKs dephosphorylate Rb to activate it","When CDK-cyclin complexes phosphorylate Rb, E2F is released, allowing S phase entry","Rb activates CDKs to stop the cell cycle","Rb and CDKs function independently","CDKs destroy Rb protein"]'::jsonb,
  '["CDK-urile defosforilează Rb pentru a-l activa","Când complexele CDK-ciclină fosforilează Rb, E2F este eliberat, permițând intrarea în faza S","Rb activează CDK-urile pentru a opri ciclul celular","Rb și CDK-urile funcționează independent","CDK-urile distrug proteina Rb"]'::jsonb,
  1,
  'CDK-cyclin complexes phosphorylate Rb, causing it to release E2F transcription factors that drive expression of S-phase genes.',
  'Complexele CDK-ciclină fosforilează Rb, cauzându-l să elibereze factorii de transcripție E2F care conduc expresia genelor din faza S.',
  'cell-biology',
