INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cell95',
  'med-admission-barrons',
  'hard',
  'The Warburg effect in cancer cells refers to:',
  'Efectul Warburg în celulele canceroase se referă la:',
  '["Increased oxidative phosphorylation","Preference for glycolysis even in the presence of oxygen","Decreased glucose uptake","Enhanced mitochondrial function","Reduced ATP production"]'::jsonb,
  '["Fosforilare oxidativă crescută","Preferința pentru glicoliză chiar și în prezența oxigenului","Absorbție scăzută de glucoză","Funcție mitocondrială îmbunătățită","Producție redusă de ATP"]'::jsonb,
  1,
  'Cancer cells often use aerobic glycolysis (Warburg effect), producing lactate even with oxygen available, supporting rapid growth and biosynthesis.',
  'Celulele canceroase folosesc adesea glicoliza aerobă (efectul Warburg), producând lactat chiar și cu oxigen disponibil, susținând creșterea rapidă și biosinteza.',
