INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss8',
  'med-admission-barrons',
  'hard',
  'Which tissue type is responsible for transmitting electrical signals and processing information?',
  'Care tip de țesut este responsabil de transmiterea semnalelor electrice și procesarea informațiilor?',
  '["Epithelial tissue","Connective tissue","Muscle tissue","Nervous tissue","All of the above equally"]'::jsonb,
  '["Țesut epitelial","Țesut conjunctiv","Țesut muscular","Țesut nervos","Toate în mod egal"]'::jsonb,
  3,
  'Nervous tissue consists of neurons and glial cells and is specialized for generating, conducting, and integrating electrical signals.',
  'Țesutul nervos este format din neuroni și celule gliale și este specializat pentru generarea, conducerea și integrarea semnalelor electrice.',
