INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss9',
  'med-admission-barrons',
  'hard',
  'Which type of cartilage is most abundant in the body and found in joints, the trachea, and the nose?',
  'Care tip de cartilaj este cel mai abundent în organism și se găsește în articulații, trahee și nas?',
  '["Elastic cartilage","Fibrocartilage","Hyaline cartilage","Bone cartilage","Dense cartilage"]'::jsonb,
  '["Cartilaj elastic","Fibrocartilaj","Cartilaj hialin","Cartilaj osos","Cartilaj dens"]'::jsonb,
  2,
  'Hyaline cartilage has a glassy matrix and provides flexible support; it covers articular surfaces and forms the skeleton of the larynx and trachea.',
  'Cartilajul hialin are o matrice sticloasă și oferă suport flexibil; acoperă suprafețele articulare și formează scheletul laringelui și traheei.',
  'tissues',
  1
