INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss11',
  'med-admission-barrons',
  'easy',
  'Which of the four primary tissue types forms glands?',
  'Care dintre cele patru tipuri principale de țesuturi formează glande?',
  '["Connective tissue","Muscle tissue","Nervous tissue","Epithelial tissue","Adipose tissue"]'::jsonb,
  '["Țesut conjunctiv","Țesut muscular","Țesut nervos","Țesut epitelial","Țesut adipos"]'::jsonb,
  3,
  'Epithelial tissue forms glands (glandular epithelium), which can be exocrine (secrete to surface) or endocrine (secrete into blood).',
  'Țesutul epitelial formează glande (epiteliu glandular), care pot fi exocrine (secretă la suprafață) sau endocrine (secretă în sânge).',
