  '["Blood vessels","Skin surface","Kidney tubules and thyroid gland","Stomach lining","Trachea"]'::jsonb,
  '["Vasele de sânge","Suprafața pielii","Tubulii renali și glanda tiroidă","Căptușeala stomacului","Trahee"]'::jsonb,
