INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss18',
  'med-admission-barrons',
  'easy',
  'Which muscle type is found in the walls of hollow organs like the stomach and bladder?',
  'Care tip de mușchi se găsește în pereții organelor cavitare precum stomacul și vezica urinară?',
  '["Skeletal muscle","Cardiac muscle","Smooth muscle","Striated voluntary muscle","Red muscle fibers only"]'::jsonb,
  '["Mușchi scheletic","Mușchi cardiac","Mușchi neted","Mușchi striat voluntar","Doar fibre musculare roșii"]'::jsonb,
  2,
  'Smooth muscle is found in hollow organ walls (viscera), blood vessels, and airways; it is involuntary and non-striated.',
  'Mușchiul neted se găsește în pereții organelor cavitare (viscere), vase de sânge și căi respiratorii; este involuntar și nestriat.',
