INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss20',
  'med-admission-barrons',
  'easy',
  'Pseudostratified columnar epithelium appears stratified because:',
  'Epiteliul columnar pseudostratificat pare stratificat pentru că:',
  '["It has multiple layers of cells","Cell nuclei are at different levels, but all cells touch the basement membrane","It contains goblet cells","It lacks a basement membrane","Cells vary in size"]'::jsonb,
  '["Are mai multe straturi de celule","Nucleii celulari sunt la niveluri diferite, dar toate celulele ating membrana bazală","Conține celule caliciforme","Îi lipsește membrana bazală","Celulele variază în mărime"]'::jsonb,
  1,
  'Pseudostratified epithelium has all cells attached to the basement membrane, but nuclei at different heights create a false layered appearance.',
  'Epiteliul pseudostratificat are toate celulele atașate de membrana bazală, dar nucleii la înălțimi diferite creează o aparență falsă de straturi.',
