INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss22',
  'med-admission-barrons',
  'easy',
  'Cardiac muscle differs from skeletal muscle in that cardiac muscle:',
  'Mușchiul cardiac diferă de mușchiul scheletic prin faptul că mușchiul cardiac:',
  '["Is voluntary","Has intercalated discs and is involuntary","Is non-striated","Has multiple nuclei per cell","Lacks mitochondria"]'::jsonb,
  '["Este voluntar","Are discuri intercalare și este involuntar","Este nestriat","Are nuclei multipli per celulă","Nu are mitocondrii"]'::jsonb,
  1,
  'Cardiac muscle is involuntary, striated, has intercalated discs (with gap junctions for synchronization), and cells are usually single-nucleated.',
  'Mușchiul cardiac este involuntar, striat, are discuri intercalare (cu joncțiuni gap pentru sincronizare) și celulele au de obicei un singur nucleu.',
