INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss27',
  'med-admission-barrons',
  'easy',
  'Simple squamous epithelium is specialized for:',
  'Epiteliul pavimentos simplu este specializat pentru:',
  '["Protection against abrasion","Secretion and absorption","Rapid diffusion and filtration","Ciliary movement","Mucus production"]'::jsonb,
  '["Protecție împotriva abraziunii","Secreție și absorbție","Difuzie rapidă și filtrare","Mișcare ciliară","Producție de mucus"]'::jsonb,
  2,
  'The thin, single layer of flat cells in simple squamous epithelium allows rapid diffusion and filtration (alveoli, capillaries, kidney glomeruli).',
  'Stratul subțire și unic de celule plate din epiteliul pavimentos simplu permite difuzie rapidă și filtrare (alveole, capilare, glomeruli renali).',
  'tissues',
  3
) ON CONFLICT (id) DO UPDATE SET
