INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss41',
  'med-admission-barrons',
  'medium',
  'A biopsy of tissue shows cells with cilia and goblet cells. This tissue is most likely:',
  'O biopsie de țesut arată celule cu cili și celule caliciforme. Acest țesut este cel mai probabil:',
  '["Simple squamous epithelium","Stratified squamous epithelium","Pseudostratified ciliated columnar epithelium","Simple cuboidal epithelium","Transitional epithelium"]'::jsonb,
  '["Epiteliu pavimentos simplu","Epiteliu pavimentos stratificat","Epiteliu columnar ciliat pseudostratificat","Epiteliu cuboidal simplu","Epiteliu de tranziție"]'::jsonb,
  2,
  'Pseudostratified ciliated columnar epithelium with goblet cells lines most of the respiratory tract, where cilia propel mucus.',
  'Epiteliul columnar ciliat pseudostratificat cu celule caliciforme căptușește majoritatea tractului respirator, unde cilii propulsează mucusul.',
  'tissues',
  5
) ON CONFLICT (id) DO UPDATE SET
