  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss42',
  'med-admission-barrons',
  'medium',
  'Tissue repair by scar formation occurs when:',
  'Repararea țesutului prin formarea cicatricei are loc când:',
  '["The injury is minor","The tissue has high regenerative capacity","The tissue cannot regenerate or damage is severe","Only epithelial tissue is damaged","Blood supply is increased"]'::jsonb,
  '["Leziunea este minoră","Țesutul are capacitate de regenerare mare","Țesutul nu se poate regenera sau deteriorarea este severă","Doar țesutul epitelial este deteriorat","Aprovizionarea cu sânge este crescută"]'::jsonb,
  2,
  'Fibrosis (scar tissue formation) occurs when parenchymal cells cannot regenerate or when damage is too extensive, replacing functional tissue with collagen.',
  'Fibroza (formarea țesutului cicatricial) apare când celulele parenchimatoase nu se pot regenera sau când deteriorarea este prea extinsă, înlocuind țesutul funcțional cu colagen.',
  'tissues',
  5
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss43',
  'med-admission-barrons',
  'medium',
  'Which cell type would be most active at a site of chronic infection?',
  'Care tip de celulă ar fi cel mai activ la un loc de infecție cronică?',
  '["Fibroblasts only","Macrophages","Adipocytes","Chondrocytes","Osteoblasts"]'::jsonb,
  '["Doar fibroblaste","Macrofage","Adipocite","Condrocite","Osteoblaste"]'::jsonb,
  1,
  'Macrophages are phagocytic cells that engulf pathogens, dead cells, and debris; they are key players in chronic inflammation and immune response.',
  'Macrofagele sunt celule fagocitare care înghit agenți patogeni, celule moarte și resturi; sunt actori cheie în inflamația cronică și răspunsul imun.',
  'tissues',
  5
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss44',
  'med-admission-barrons',
  'medium',
  'The ground substance of connective tissue contains:',
  'Substanța fundamentală a țesutului conjunctiv conține:',
  '["Only collagen","Proteoglycans and glycosaminoglycans (GAGs)","Only water","Red blood cells","Neurons"]'::jsonb,
  '["Doar colagen","Proteoglicani și glicozaminoglicani (GAG-uri)","Doar apă","Eritrocite","Neuroni"]'::jsonb,
  1,
  'Ground substance is a gel-like material containing water, proteoglycans (with GAG chains like hyaluronic acid and chondroitin sulfate), and adhesion proteins.',
  'Substanța fundamentală este un material gelatinos conținând apă, proteoglicani (cu lanțuri GAG precum acid hialuronic și condroitin sulfat) și proteine de adeziune.',
  'tissues',
  5
) ON CONFLICT (id) DO UPDATE SET
