INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss45',
  'med-admission-barrons',
  'medium',
  'Intercalated discs in cardiac muscle contain:',
  'Discurile intercalare din mușchiul cardiac conțin:',
  '["Only collagen","Gap junctions and desmosomes","Only elastic fibers","Motor end plates","T-tubules only"]'::jsonb,
  '["Doar colagen","Joncțiuni gap și desmozomi","Doar fibre elastice","Plăci motorii terminale","Doar tubuli T"]'::jsonb,
  1,
  'Intercalated discs contain gap junctions (for electrical coupling) and desmosomes (for mechanical attachment), ensuring synchronized contraction.',
  'Discurile intercalare conțin joncțiuni gap (pentru cuplaj electric) și desmozomi (pentru atașare mecanică), asigurând contracție sincronizată.',
  'tissues',
  5
) ON CONFLICT (id) DO UPDATE SET
