INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss46',
  'med-admission-barrons',
  'medium',
  'Keratinized stratified squamous epithelium differs from non-keratinized in that it:',
  'Epiteliul pavimentos stratificat keratinizat diferă de cel nekeratinizat prin faptul că:',
  '["Has fewer cell layers","Has a superficial layer of dead cells filled with keratin","Is found in wet surfaces","Lacks a basement membrane","Is thinner"]'::jsonb,
  '["Are mai puține straturi de celule","Are un strat superficial de celule moarte pline cu keratină","Se găsește pe suprafețe umede","Nu are membrană bazală","Este mai subțire"]'::jsonb,
  1,
  'Keratinized epithelium (epidermis) has surface cells that die and fill with keratin, forming a waterproof protective layer.',
  'Epiteliul keratinizat (epiderma) are celule de suprafață care mor și se umplu cu keratină, formând un strat protector impermeabil.',
  'tissues',
  5
) ON CONFLICT (id) DO UPDATE SET
