INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss47',
  'med-admission-barrons',
  'medium',
  'Smooth muscle can undergo sustained contraction called:',
  'Mușchiul neted poate suferi contracție susținută numită:',
  '["Tetanus","Tonus","Twitch","Fibrillation","Spasm"]'::jsonb,
  '["Tetanos","Tonus","Sacadă","Fibrilație","Spasm"]'::jsonb,
  1,
  'Smooth muscle maintains tonus (tone), a state of partial continuous contraction, without fatigue due to its low energy requirements.',
  'Mușchiul neted menține tonusul (tonicitate), o stare de contracție continuă parțială, fără oboseală datorită cerințelor sale energetice scăzute.',
  'tissues',
  5
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
