INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss58',
  'med-admission-barrons',
  'medium',
  'Exocrine glands differ from endocrine glands in that exocrine glands:',
  'Glandele exocrine diferă de glandele endocrine prin faptul că glandele exocrine:',
  '["Secrete hormones into blood","Secrete products through ducts to body surfaces or cavities","Lack secretory cells","Are only found in the brain","Do not produce any secretions"]'::jsonb,
  '["Secretă hormoni în sânge","Secretă produse prin ducte la suprafețe sau cavități ale corpului","Nu au celule secretoare","Se găsesc doar în creier","Nu produc nicio secreție"]'::jsonb,
  1,
  'Exocrine glands have ducts that carry secretions to epithelial surfaces (sweat, oil, digestive glands); endocrine glands are ductless, secreting into blood.',
  'Glandele exocrine au ducte care transportă secrețiile la suprafețe epiteliale (glande sudoripare, sebacee, digestive); glandele endocrine sunt fără ducte, secretând în sânge.',
  'tissues',
