INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss67',
  'med-admission-barrons',
  'medium',
  'The cutaneous membrane refers to:',
  'Membrana cutanată se referă la:',
  '["Lining of body cavities","The skin","Lining of joints","Lining of blood vessels","Mucosa of digestive tract"]'::jsonb,
  '["Căptușeala cavităților corpului","Pielea","Căptușeala articulațiilor","Căptușeala vaselor de sânge","Mucoasa tractului digestiv"]'::jsonb,
  1,
  'The cutaneous membrane is the skin—a dry membrane consisting of epidermis (keratinized stratified squamous epithelium) and dermis (connective tissue).',
  'Membrana cutanată este pielea—o membrană uscată constând din epidermă (epiteliu pavimentos stratificat keratinizat) și dermă (țesut conjunctiv).',
