INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss71',
  'med-admission-barrons',
  'hard',
  'A patient with Ehlers-Danlos syndrome has defective collagen synthesis. Which tissues would be most affected?',
  'Un pacient cu sindrom Ehlers-Danlos are sinteză defectă de colagen. Care țesuturi ar fi cel mai afectate?',
  '["Nervous tissue only","Skin, blood vessels, and joints","Only bone tissue","Only muscle tissue","Only epithelial tissue"]'::jsonb,
  '["Doar țesut nervos","Piele, vase de sânge și articulații","Doar țesut osos","Doar țesut muscular","Doar țesut epitelial"]'::jsonb,
  1,
  'Ehlers-Danlos syndrome affects collagen-rich tissues, causing hypermobile joints, fragile skin, and fragile blood vessels.',
  'Sindromul Ehlers-Danlos afectează țesuturile bogate în colagen, cauzând articulații hipermobile, piele fragilă și vase de sânge fragile.',
