INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss72',
  'med-admission-barrons',
  'hard',
  'Which type of tissue is most likely to be replaced by scar tissue after injury?',
  'Care tip de țesut este cel mai probabil să fie înlocuit cu țesut cicatricial după leziune?',
  '["Epithelial tissue of skin","Cardiac muscle tissue","Intestinal epithelium","Liver tissue","Bone tissue"]'::jsonb,
  '["Țesut epitelial al pielii","Țesut muscular cardiac","Epiteliu intestinal","Țesut hepatic","Țesut osos"]'::jsonb,
  1,
  'Cardiac muscle has minimal regenerative capacity; after myocardial infarction, dead tissue is replaced by scar (fibrous) tissue.',
  'Mușchiul cardiac are capacitate de regenerare minimă; după infarct miocardic, țesutul mort este înlocuit cu țesut cicatricial (fibros).',
  'tissues',
