INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss73',
  'med-admission-barrons',
  'hard',
  'The difference between labile, stable, and permanent cells relates to their:',
  'Diferența dintre celulele labile, stabile și permanente se referă la:',
  '["Size","Location","Capacity for cell division and regeneration","Shape","Color"]'::jsonb,
  '["Mărime","Locație","Capacitatea de diviziune celulară și regenerare","Formă","Culoare"]'::jsonb,
  2,
  'Labile cells divide continuously (epithelia); stable cells divide when needed (liver); permanent cells rarely/never divide (neurons, cardiac muscle).',
  'Celulele labile se divid continuu (epitelii); celulele stabile se divid când este nevoie (ficat); celulele permanente se divid rar/niciodată (neuroni, mușchi cardiac).',
  'tissues',
  8
