INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss84',
  'med-admission-barrons',
  'hard',
  'Hypertrophy of tissue involves:',
  'Hipertrofia țesutului implică:',
  '["Increase in cell number","Increase in cell size","Change in cell type","Decrease in cell size","Cell death"]'::jsonb,
  '["Creșterea numărului de celule","Creșterea mărimii celulelor","Schimbarea tipului de celulă","Scăderea mărimii celulelor","Moartea celulară"]'::jsonb,
  1,
  'Hypertrophy is an increase in cell size without increase in cell number, common in cardiac and skeletal muscle in response to increased workload.',
  'Hipertrofia este o creștere a mărimii celulelor fără creșterea numărului de celule, frecventă în mușchiul cardiac și scheletic ca răspuns la sarcină crescută.',
