INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss86',
  'med-admission-barrons',
  'hard',
  'The difference between single-unit and multi-unit smooth muscle is:',
  'Diferența dintre mușchiul neted cu o singură unitate și multi-unitar este:',
  '["Single-unit is striated","Single-unit cells are electrically coupled via gap junctions and contract as a unit","Multi-unit is in the digestive tract","There is no difference","Multi-unit shows spontaneous activity"]'::jsonb,
  '["Cel cu o singură unitate este striat","Celulele cu o singură unitate sunt cuplate electric prin joncțiuni gap și se contractă ca o unitate","Cel multi-unitar este în tractul digestiv","Nu există nicio diferență","Cel multi-unitar prezintă activitate spontană"]'::jsonb,
  1,
  'Single-unit (visceral) smooth muscle cells are connected by gap junctions, allowing coordinated contraction; multi-unit cells act independently.',
  'Celulele musculare netede cu o singură unitate (viscerale) sunt conectate prin joncțiuni gap, permițând contracție coordonată; celulele multi-unitare acționează independent.',
  'tissues',
  9
) ON CONFLICT (id) DO UPDATE SET
