INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss90',
  'med-admission-barrons',
  'hard',
  'Which feature of transitional epithelium allows it to stretch?',
  'Care caracteristică a epiteliului de tranziție îi permite să se întindă?',
  '["Cells are fused together","Cells are dome-shaped when relaxed and flatten when stretched","It has only one cell layer","It contains elastic fibers","It has cilia"]'::jsonb,
  '["Celulele sunt fuzionate împreună","Celulele sunt în formă de dom când sunt relaxate și se aplatizează când sunt întinse","Are doar un strat de celule","Conține fibre elastice","Are cili"]'::jsonb,
  1,
  'Transitional epithelium has specialized cells that are rounded when the organ is empty and flatten when stretched, allowing distension.',
  'Epiteliul de tranziție are celule specializate care sunt rotunjite când organul este gol și se aplatizează când este întins, permițând distensiunea.',
