INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss93',
  'med-admission-barrons',
  'hard',
  'Scurvy results from vitamin C deficiency and affects collagen synthesis. Which tissue would show the earliest symptoms?',
  'Scorbutul rezultă din deficiența de vitamina C și afectează sinteza colagenului. Care țesut ar arăta cele mai timpurii simptome?',
  '["Nervous tissue","Connective tissues (gums, skin, blood vessels)","Only bone","Only muscle","Only epithelium"]'::jsonb,
  '["Țesut nervos","Țesuturi conjunctive (gingii, piele, vase de sânge)","Doar os","Doar mușchi","Doar epiteliu"]'::jsonb,
  1,
  'Vitamin C is required for collagen hydroxylation; deficiency causes weak connective tissues, leading to bleeding gums, bruising, and poor wound healing.',
  'Vitamina C este necesară pentru hidroxilarea colagenului; deficiența cauzează țesuturi conjunctive slabe, ducând la gingii sângerânde, vânătăi și vindecare slabă a rănilor.',
  'tissues',
  10
) ON CONFLICT (id) DO UPDATE SET
