INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss94',
  'med-admission-barrons',
  'hard',
  'Which of the following is true regarding tissue engineering?',
  'Care dintre următoarele este adevărat în ceea ce privește ingineria tisulară?',
  '["It cannot create functional tissues","It combines cells, scaffolds, and growth factors to create replacement tissues","It only works for skin","It requires no cells","It is not currently used clinically"]'::jsonb,
  '["Nu poate crea țesuturi funcționale","Combină celule, schele și factori de creștere pentru a crea țesuturi de înlocuire","Funcționează doar pentru piele","Nu necesită celule","Nu este utilizată clinic în prezent"]'::jsonb,
  1,
  'Tissue engineering uses cells (often stem cells), scaffolds (extracellular matrix mimics), and signals (growth factors) to create functional tissues.',
  'Ingineria tisulară folosește celule (adesea celule stem), schele (imitații ale matricei extracelulare) și semnale (factori de creștere) pentru a crea țesuturi funcționale.',
  'tissues',
  10
) ON CONFLICT (id) DO UPDATE SET
