INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'tiss97',
  'med-admission-barrons',
  'hard',
  'Integrins in the basement membrane function to:',
  'Integrinele din membrana bazală funcționează pentru a:',
  '["Store energy","Anchor epithelial cells to the basement membrane","Produce collagen","Conduct impulses","Produce hormones"]'::jsonb,
  '["Stoca energie","Ancora celulele epiteliale de membrana bazală","Produce colagen","Conduce impulsuri","Produce hormoni"]'::jsonb,
  1,
  'Integrins are transmembrane receptors that link the cytoskeleton to extracellular matrix proteins, anchoring cells to the basement membrane.',
  'Integrinele sunt receptori transmembranari care leagă citoscheletul de proteinele matricei extracelulare, ancorând celulele de membrana bazală.',
