  '["Living, actively dividing cells","Dead, keratinized cells","Melanocytes","Nerve endings","Blood vessels"]'::jsonb,
  '["Celule vii, care se divid activ","Celule moarte, keratinizate","Melanocite","Terminații nervoase","Vase de sânge"]'::jsonb,
