INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ26',
  'med-admission-barrons',
  'easy',
  'The papillary layer of the dermis contains:',
  'Stratul papilar al dermei conține:',
  '["Only fat cells","Loose connective tissue with dermal papillae","Dense regular connective tissue","Bone cells","Cartilage"]'::jsonb,
  '["Doar celule grase","Țesut conjunctiv lax cu papile dermice","Țesut conjunctiv dens regulat","Celule osoase","Cartilaj"]'::jsonb,
  1,
  'The papillary layer has loose connective tissue with dermal papillae that interlock with epidermal ridges, increasing adhesion.',
  'Stratul papilar are țesut conjunctiv lax cu papile dermice care se interblochează cu crestele epidermice, crescând adeziunea.',
  'integumentary',
  3
) ON CONFLICT (id) DO UPDATE SET
