INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ28',
  'med-admission-barrons',
  'easy',
  'Merkel cells in the epidermis function as:',
  'Celulele Merkel din epidermă funcționează ca:',
  '["Immune cells","Pigment-producing cells","Touch receptors","Keratin producers","Gland cells"]'::jsonb,
  '["Celule imune","Celule producătoare de pigment","Receptori de atingere","Producători de keratină","Celule glandulare"]'::jsonb,
  2,
  'Merkel cells are mechanoreceptors associated with sensory nerve endings, detecting light touch and texture.',
  'Celulele Merkel sunt mecanoreceptori asociați cu terminații nervoase senzoriale, detectând atingerea ușoară și textura.',
  'integumentary',
  3
