INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ30',
  'med-admission-barrons',
  'easy',
  'Hair grows from a structure called the:',
  'Părul crește dintr-o structură numită:',
  '["Hair shaft","Hair follicle","Sebaceous gland","Arrector pili","Dermis"]'::jsonb,
  '["Tija părului","Foliculul de păr","Glanda sebacee","Mușchiul erector","Derma"]'::jsonb,
  1,
  'Hair follicles are tube-like structures that extend into the dermis; cells in the hair bulb divide to produce the hair shaft.',
  'Foliculii de păr sunt structuri tubulare care se extind în dermă; celulele din bulbul părului se divid pentru a produce tija părului.',
