INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ31',
  'med-admission-barrons',
  'easy',
  'First-degree burns affect:',
  'Arsurile de gradul întâi afectează:',
  '["Only the epidermis","Epidermis and part of dermis","Full thickness of skin","Underlying muscle","Bone"]'::jsonb,
  '["Doar epiderma","Epiderma și o parte a dermei","Întreaga grosime a pielii","Mușchiul subiacent","Osul"]'::jsonb,
  0,
  'First-degree (superficial) burns damage only the epidermis, causing redness and pain but healing without scarring.',
  'Arsurile de gradul întâi (superficiale) afectează doar epiderma, cauzând roșeață și durere dar vindecându-se fără cicatrici.',
