INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ32',
  'med-admission-barrons',
  'easy',
  'The dermis contains all of the following EXCEPT:',
  'Derma conține toate următoarele CU EXCEPȚIA:',
  '["Blood vessels","Nerve endings","Hair follicles","Keratinized dead cells","Sweat glands"]'::jsonb,
  '["Vase de sânge","Terminații nervoase","Foliculi de păr","Celule moarte keratinizate","Glande sudoripare"]'::jsonb,
  3,
  'Keratinized dead cells are found in the epidermis (stratum corneum), not the dermis. The dermis contains blood vessels, nerves, and skin appendages.',
  'Celulele moarte keratinizate se găsesc în epidermă (stratul cornos), nu în dermă. Derma conține vase de sânge, nervi și anexe ale pielii.',
  'integumentary',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ33',
