INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ41',
  'med-admission-barrons',
  'medium',
  'A patient presents with a wound that has damaged the stratum basale. What is the expected outcome for healing?',
  'Un pacient prezintă o rană care a deteriorat stratul bazal. Care este rezultatul așteptat pentru vindecare?',
  '["Rapid regeneration without scarring","Healing with potential scar formation because stem cells are damaged","No healing possible","Only hair will regrow","Immediate skin graft required"]'::jsonb,
  '["Regenerare rapidă fără cicatrici","Vindecare cu potențială formare de cicatrice deoarece celulele stem sunt deteriorate","Vindecare imposibilă","Doar părul va crește la loc","Grefă de piele necesară imediat"]'::jsonb,
  1,
  'Damage to the stratum basale affects the stem cell population, so healing relies more on surrounding cells and may result in scarring.',
  'Deteriorarea stratului bazal afectează populația de celule stem, așa că vindecarea se bazează mai mult pe celulele înconjurătoare și poate rezulta în cicatrizare.',
  'integumentary',
  5
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ42',
  'med-admission-barrons',
  'medium',
  'The ABCDE rule for melanoma assessment includes all of the following EXCEPT:',
  'Regula ABCDE pentru evaluarea melanomului include toate următoarele CU EXCEPȚIA:',
  '["Asymmetry","Border irregularity","Color variation","Diameter greater than 6mm","Firmness"]'::jsonb,
  '["Asimetrie","Neregularitate a marginii","Variație de culoare","Diametru mai mare de 6mm","Fermitate"]'::jsonb,
  4,
  'ABCDE stands for Asymmetry, Border, Color, Diameter, and Evolution (changes over time). Firmness is not part of this assessment.',
  'ABCDE reprezintă Asimetrie, Margine, Culoare, Diametru și Evoluție (modificări în timp). Fermitatea nu face parte din această evaluare.',
  'integumentary',
  5
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
