INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ46',
  'med-admission-barrons',
  'medium',
  'Acne vulgaris primarily involves:',
  'Acneea vulgară implică în principal:',
  '["Eccrine sweat glands","Sebaceous glands and hair follicles","Apocrine sweat glands","Ceruminous glands","Mammary glands"]'::jsonb,
  '["Glande sudoripare ecrine","Glande sebacee și foliculi de păr","Glande sudoripare apocrine","Glande ceruminoase","Glande mamare"]'::jsonb,
  1,
  'Acne results from blocked sebaceous gland ducts, leading to bacterial growth (Propionibacterium acnes) and inflammation.',
  'Acneea rezultă din ductele blocate ale glandelor sebacee, ducând la creștere bacteriană (Propionibacterium acnes) și inflamație.',
  'integumentary',
  5
) ON CONFLICT (id) DO UPDATE SET
