INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ47',
  'med-admission-barrons',
  'medium',
  'Skin color differences among individuals are primarily due to differences in:',
  'Diferențele de culoare a pielii între indivizi se datorează în principal diferențelor în:',
  '["Number of melanocytes","Amount and type of melanin produced","Thickness of epidermis","Blood vessel density","Keratin content"]'::jsonb,
  '["Numărul de melanocite","Cantitatea și tipul de melanină produsă","Grosimea epidermei","Densitatea vaselor de sânge","Conținutul de keratină"]'::jsonb,
  1,
  'All humans have similar melanocyte numbers; color differences result from the amount and type of melanin (eumelanin vs. pheomelanin) produced.',
  'Toți oamenii au numere similare de melanocite; diferențele de culoare rezultă din cantitatea și tipul de melanină (eumelanină vs. feomelanină) produsă.',
  'integumentary',
  5
) ON CONFLICT (id) DO UPDATE SET
