INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ48',
  'med-admission-barrons',
  'medium',
  'Psoriasis is characterized by:',
  'Psoriazisul este caracterizat de:',
  '["Decreased skin cell turnover","Rapid keratinocyte proliferation with abnormal differentiation","Loss of melanocytes","Excessive hair growth","Loss of sebaceous glands"]'::jsonb,
  '["Turnover celular al pielii scăzut","Proliferare rapidă a keratinocitelor cu diferențiere anormală","Pierderea melanocitelor","Creștere excesivă a părului","Pierderea glandelor sebacee"]'::jsonb,
  1,
  'Psoriasis involves accelerated keratinocyte proliferation (up to 7 times faster), causing thick, scaly plaques.',
  'Psoriazisul implică proliferare accelerată a keratinocitelor (de până la 7 ori mai rapidă), cauzând plăci groase și scuamoase.',
  'integumentary',
  5
) ON CONFLICT (id) DO UPDATE SET
