INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ49',
  'med-admission-barrons',
  'medium',
  'The stratum spinosum is named for its:',
  'Stratul spinos este numit astfel pentru:',
  '["Spiny shape of keratinocytes due to desmosomes in prepared slides","Presence of spines on cell surfaces","Location near the spine","Spiny hair follicles","Pointed cells"]'::jsonb,
  '["Forma spinoasă a keratinocitelor datorită desmozomilor în preparatele microscopice","Prezența spinilor pe suprafețele celulare","Locația aproape de coloană","Foliculi de păr spinoși","Celule ascuțite"]'::jsonb,
  0,
  'Cells in prepared slides appear spiny due to desmosomes connecting neighboring cells, which remain attached during fixation and processing.',
  'Celulele din preparatele microscopice par spinoase datorită desmozomilor care conectează celulele vecine, care rămân atașate în timpul fixării și procesării.',
  'integumentary',
  5
) ON CONFLICT (id) DO UPDATE SET
