INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ50',
  'med-admission-barrons',
  'medium',
  'Cleavage lines (Langer''s lines) in the skin indicate:',
  'Liniile de clivaj (liniile Langer) din piele indică:',
  '["Direction of sweat gland openings","Direction of underlying collagen fiber bundles","Blood vessel distribution","Hair growth patterns","Nerve pathways"]'::jsonb,
  '["Direcția deschiderilor glandelor sudoripare","Direcția fasciculelor de fibre de colagen subiacente","Distribuția vaselor de sânge","Modelele de creștere a părului","Căile nervoase"]'::jsonb,
  1,
  'Langer''s lines represent the predominant direction of collagen fibers in the dermis; surgical incisions parallel to these heal better.',
  'Liniile Langer reprezintă direcția predominantă a fibrelor de colagen din dermă; inciziile chirurgicale paralele cu acestea se vindecă mai bine.',
  'integumentary',
  5
) ON CONFLICT (id) DO UPDATE SET
