INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ51',
  'med-admission-barrons',
  'medium',
  'Jaundice (yellow skin) is caused by elevated levels of:',
  'Icterul (pielea galbenă) este cauzat de niveluri crescute de:',
  '["Carotene","Melanin","Bilirubin","Hemoglobin","Keratin"]'::jsonb,
  '["Caroten","Melanină","Bilirubină","Hemoglobină","Keratină"]'::jsonb,
  2,
  'Jaundice results from accumulated bilirubin (a hemoglobin breakdown product) in blood and tissues, often indicating liver dysfunction.',
  'Icterul rezultă din acumularea de bilirubină (un produs de degradare a hemoglobinei) în sânge și țesuturi, adesea indicând disfuncție hepatică.',
  'integumentary',
  6
) ON CONFLICT (id) DO UPDATE SET
