INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ52',
  'med-admission-barrons',
  'medium',
  'Hair growth phases include all EXCEPT:',
  'Fazele de creștere a părului includ toate CU EXCEPȚIA:',
  '["Anagen (growth phase)","Catagen (regression phase)","Telogen (resting phase)","Exogen (shedding phase)","Mitogen (multiplication phase)"]'::jsonb,
  '["Anagen (faza de creștere)","Catagen (faza de regresie)","Telogen (faza de repaus)","Exogen (faza de cădere)","Mitogen (faza de multiplicare)"]'::jsonb,
  4,
  'Hair cycles through anagen (active growth), catagen (transition/regression), telogen (rest), and exogen (shedding). "Mitogen" is not a hair phase.',
  'Părul ciclează prin anagen (creștere activă), catagen (tranziție/regresie), telogen (repaus) și exogen (cădere). „Mitogen" nu este o fază a părului.',
  'integumentary',
  6
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
