INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ53',
  'med-admission-barrons',
  'medium',
  'The difference between thick and thin skin is:',
  'Diferența dintre pielea groasă și subțire este:',
  '["Thick skin has all five epidermal layers; thin skin lacks stratum lucidum","Thin skin has more hair follicles","Thick skin is found on the back","Thin skin is thicker overall","There is no difference"]'::jsonb,
  '["Pielea groasă are toate cele cinci straturi epidermice; pielea subțire nu are stratul lucid","Pielea subțire are mai mulți foliculi de păr","Pielea groasă se găsește pe spate","Pielea subțire este mai groasă în general","Nu există nicio diferență"]'::jsonb,
  0,
  'Thick skin (palms, soles) has all 5 epidermal layers including stratum lucidum and lacks hair; thin skin has 4 layers and has hair.',
  'Pielea groasă (palme, tălpi) are toate cele 5 straturi epidermice inclusiv stratul lucid și nu are păr; pielea subțire are 4 straturi și are păr.',
  'integumentary',
  6
