INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ56',
  'med-admission-barrons',
  'medium',
  'The function of keratin in the epidermis is to:',
  'Funcția keratinei în epidermă este de a:',
  '["Produce color","Provide waterproofing and protection against abrasion","Conduct nerve impulses","Produce sweat","Store fat"]'::jsonb,
  '["Produce culoare","Oferi impermeabilizare și protecție împotriva abraziunii","Conduce impulsuri nervoase","Produce transpirație","Stoca grăsime"]'::jsonb,
  1,
  'Keratin is a tough, fibrous protein that waterproofs the skin and protects underlying tissues from physical, chemical, and biological damage.',
  'Keratina este o proteină fibroasă și rezistentă care impermeabilizează pielea și protejează țesuturile subiacente de deteriorare fizică, chimică și biologică.',
