INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ61',
  'med-admission-barrons',
  'medium',
  'Decubitus ulcers (pressure sores) typically develop over:',
  'Ulcerele de decubit (escare) se dezvoltă de obicei peste:',
  '["Areas with thick fat layers","Bony prominences where pressure restricts blood flow","Hair-covered areas","Areas with many sweat glands","Well-vascularized regions"]'::jsonb,
  '["Zone cu straturi groase de grăsime","Proeminențe osoase unde presiunea restricționează fluxul sanguin","Zone acoperite cu păr","Zone cu multe glande sudoripare","Regiuni bine vascularizate"]'::jsonb,
  1,
  'Pressure ulcers form over bony prominences (sacrum, heels, hips) where prolonged pressure compresses blood vessels, causing tissue ischemia.',
  'Ulcerele de presiune se formează peste proeminențe osoase (sacru, călcâie, șolduri) unde presiunea prelungită comprimă vasele de sânge, cauzând ischemie tisulară.',
