  'med-admission-barrons',
  'medium',
  'Alopecia refers to:',
  'Alopecia se referă la:',
  '["Excessive hair growth","Hair loss","Nail disorders","Skin pigmentation disorders","Excessive sweating"]'::jsonb,
  '["Creștere excesivă a părului","Căderea părului","Afecțiuni ale unghiilor","Tulburări de pigmentare a pielii","Transpirație excesivă"]'::jsonb,
