  'Placa unghială crește din:',
  '["Nail bed","Nail matrix","Cuticle","Hyponychium","Eponychium"]'::jsonb,
  '["Patul unghial","Matricea unghială","Cuticulă","Hiponichiu","Eponichiu"]'::jsonb,
