INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ65',
  'med-admission-barrons',
  'medium',
  'Thermoregulation through the skin involves:',
  'Termoreglarea prin piele implică:',
  '["Only sweat production","Vasodilation, vasoconstriction, sweating, and shivering reflex","Only hair growth","Melanin production","Keratin synthesis"]'::jsonb,
  '["Doar producția de transpirație","Vasodilație, vasoconstricție, transpirație și reflexul de frison","Doar creșterea părului","Producția de melanină","Sinteza keratinei"]'::jsonb,
  1,
  'Skin regulates temperature through vasodilation (heat loss), vasoconstriction (heat conservation), sweating (evaporative cooling), and coordinating with shivering.',
  'Pielea reglează temperatura prin vasodilație (pierdere de căldură), vasoconstricție (conservare de căldură), transpirație (răcire prin evaporare) și coordonare cu frisonul.',
  'integumentary',
