INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ71',
  'med-admission-barrons',
  'hard',
  'A patient with extensive burns has lost fluid and is at risk for hypovolemic shock. This illustrates which function of the skin?',
  'Un pacient cu arsuri extinse a pierdut lichid și este în risc de șoc hipovolemic. Aceasta ilustrează care funcție a pielii?',
  '["Temperature regulation","Protection and fluid barrier function","Vitamin D synthesis","Sensation","Excretion"]'::jsonb,
  '["Reglarea temperaturii","Funcția de protecție și barieră de fluide","Sinteza vitaminei D","Senzație","Excreție"]'::jsonb,
  1,
  'Extensive burns damage the skin''s barrier function, leading to massive fluid loss and risk of shock, demonstrating the skin''s role in maintaining fluid balance.',
  'Arsurile extinse afectează funcția de barieră a pielii, ducând la pierdere masivă de lichid și risc de șoc, demonstrând rolul pielii în menținerea echilibrului de fluide.',
  'integumentary',
  8
) ON CONFLICT (id) DO UPDATE SET
