  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ72',
  'med-admission-barrons',
  'hard',
  'Basal cell carcinoma typically arises from cells in the:',
  'Carcinomul bazocelular apare de obicei din celulele din:',
  '["Stratum corneum","Stratum basale","Dermis","Hypodermis","Hair follicle"]'::jsonb,
  '["Stratul cornos","Stratul bazal","Dermă","Hipodermă","Foliculul de păr"]'::jsonb,
  1,
  'Basal cell carcinoma, the most common skin cancer, arises from cells in the stratum basale, usually due to UV damage.',
  'Carcinomul bazocelular, cel mai frecvent cancer de piele, apare din celulele stratului bazal, de obicei din cauza deteriorării UV.',
  'integumentary',
  8
) ON CONFLICT (id) DO UPDATE SET
