INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ73',
  'med-admission-barrons',
  'hard',
  'The process of keratinization involves:',
  'Procesul de keratinizare implică:',
  '["Cells accumulating melanin","Cells filling with keratin, losing organelles, and dying as they move superficially","Cells dividing rapidly","Cells producing sebum","Cells forming blood vessels"]'::jsonb,
  '["Celulele acumulează melanină","Celulele se umplu cu keratină, pierd organele și mor pe măsură ce se mișcă superficial","Celulele se divid rapid","Celulele produc sebum","Celulele formează vase de sânge"]'::jsonb,
  1,
  'During keratinization, keratinocytes fill with keratin filaments, lose organelles, and die, forming the protective stratum corneum.',
  'În timpul keratinizării, keratinocitele se umplu cu filamente de keratină, pierd organele și mor, formând stratul cornos protector.',
  'integumentary',
  8
) ON CONFLICT (id) DO UPDATE SET
