INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ74',
  'med-admission-barrons',
  'hard',
  'Transepidermal water loss (TEWL) is primarily prevented by:',
  'Pierderea transepidermică de apă (TEWL) este prevenită în principal de:',
  '["Melanin","Lipids secreted by lamellar bodies in the stratum granulosum","Collagen in dermis","Sebaceous gland secretions only","Hair"]'::jsonb,
  '["Melanină","Lipidele secretate de corpurile lamelate din stratul granulos","Colagenul din dermă","Doar secrețiile glandelor sebacee","Părul"]'::jsonb,
  1,
  'Lamellar bodies in stratum granulosum release lipids (ceramides, fatty acids, cholesterol) that form the epidermal water barrier.',
  'Corpurile lamelate din stratul granulos eliberează lipide (ceramide, acizi grași, colesterol) care formează bariera epidermică de apă.',
  'integumentary',
  8
) ON CONFLICT (id) DO UPDATE SET
