INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ75',
  'med-admission-barrons',
  'hard',
  'A patient taking immunosuppressive drugs is at increased risk for which skin condition?',
  'Un pacient care ia medicamente imunosupresoare are risc crescut pentru care afecțiune a pielii?',
  '["Increased melanin production","Increased susceptibility to skin infections and skin cancers","Excessive sweating","Thicker epidermis","Increased hair growth"]'::jsonb,
  '["Producție crescută de melanină","Susceptibilitate crescută la infecții ale pielii și cancere de piele","Transpirație excesivă","Epidermă mai groasă","Creștere crescută a părului"]'::jsonb,
  1,
  'Immunosuppression impairs Langerhans cell and other immune functions, increasing susceptibility to infections and reducing cancer surveillance.',
  'Imunosupresia afectează funcțiile celulelor Langerhans și ale altor celule imune, crescând susceptibilitatea la infecții și reducând supravegherea cancerului.',
  'integumentary',
  8
) ON CONFLICT (id) DO UPDATE SET
