  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ76',
  'med-admission-barrons',
  'hard',
  'Eccrine sweat glands are innervated by:',
  'Glandele sudoripare ecrine sunt inervate de:',
  '["Somatic motor neurons","Sympathetic cholinergic neurons","Parasympathetic neurons","Sensory neurons only","Sympathetic adrenergic neurons only"]'::jsonb,
  '["Neuroni motori somatici","Neuroni simpatici colinergici","Neuroni parasimpatici","Doar neuroni senzoriali","Doar neuroni simpatici adrenergici"]'::jsonb,
  1,
  'Eccrine sweat glands are unique in that they are innervated by sympathetic cholinergic (acetylcholine-releasing) neurons, unlike most sympathetic targets.',
  'Glandele sudoripare ecrine sunt unice în sensul că sunt inervate de neuroni simpatici colinergici (eliberatori de acetilcolină), spre deosebire de majoritatea țintelor simpatice.',
  'integumentary',
  8
) ON CONFLICT (id) DO UPDATE SET
