INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ77',
  'med-admission-barrons',
  'hard',
  'Melanin transfer from melanocytes to keratinocytes occurs via:',
  'Transferul de melanină de la melanocite la keratinocite are loc prin:',
  '["Direct cell fusion","Transfer of melanosomes through dendritic processes","Blood circulation","Diffusion through extracellular matrix","Nerve conduction"]'::jsonb,
  '["Fuziune celulară directă","Transferul melanozomilor prin procese dendritice","Circulație sanguină","Difuzie prin matricea extracelulară","Conducere nervoasă"]'::jsonb,
  1,
  'Melanocytes have dendritic processes that contact keratinocytes; melanosomes are transferred via these processes and phagocytosed by keratinocytes.',
  'Melanocitele au procese dendritice care contactează keratinocitele; melanozomii sunt transferați prin aceste procese și fagocitați de keratinocite.',
  'integumentary',
  8
) ON CONFLICT (id) DO UPDATE SET
