INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ78',
  'med-admission-barrons',
  'hard',
  'The epidermal-dermal junction (basement membrane zone) is important for:',
  'Joncțiunea epidermo-dermică (zona membranei bazale) este importantă pentru:',
  '["Hair growth only","Anchoring epidermis to dermis and selective permeability","Melanin production","Sweat secretion","Nail formation"]'::jsonb,
  '["Doar creșterea părului","Ancorarea epidermei de dermă și permeabilitate selectivă","Producția de melanină","Secreția de transpirație","Formarea unghiilor"]'::jsonb,
  1,
  'The basement membrane zone anchors epidermis to dermis (via hemidesmosomes, anchoring fibrils) and acts as a selective barrier for molecules.',
  'Zona membranei bazale ancorează epiderma de dermă (prin hemidesmozomi, fibrile de ancorare) și acționează ca o barieră selectivă pentru molecule.',
  'integumentary',
  8
) ON CONFLICT (id) DO UPDATE SET
