INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ79',
  'med-admission-barrons',
  'hard',
  'Squamous cell carcinoma of the skin most commonly develops from:',
  'Carcinomul scuamos al pielii se dezvoltă cel mai frecvent din:',
  '["Melanocytes","Keratinocytes in the stratum spinosum","Merkel cells","Fibroblasts","Adipocytes"]'::jsonb,
  '["Melanocite","Keratinocite din stratul spinos","Celule Merkel","Fibroblaste","Adipocite"]'::jsonb,
  1,
  'Squamous cell carcinoma arises from keratinocytes, typically in sun-damaged skin, often preceded by actinic keratosis.',
  'Carcinomul scuamos apare din keratinocite, de obicei în piele deteriorată de soare, adesea precedat de keratoza actinică.',
  'integumentary',
  8
) ON CONFLICT (id) DO UPDATE SET
