  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ80',
  'med-admission-barrons',
  'hard',
  'Wound contraction during healing is primarily mediated by:',
  'Contracția rănii în timpul vindecării este mediată în principal de:',
  '["Keratinocytes","Myofibroblasts","Neutrophils","Melanocytes","Mast cells"]'::jsonb,
  '["Keratinocite","Miofibroblaste","Neutrofile","Melanocite","Mastocite"]'::jsonb,
  1,
  'Myofibroblasts (fibroblasts with contractile properties) in granulation tissue contract to pull wound edges together.',
  'Miofibroblastele (fibroblaste cu proprietăți contractile) din țesutul de granulație se contractă pentru a trage marginile rănii împreună.',
  'integumentary',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
