-- Set 9 (Hard)
INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ81',
  'med-admission-barrons',
  'hard',
  'The difference in healing between fetal skin and adult skin is that fetal wounds:',
  'Diferența în vindecare între pielea fetală și cea adultă este că rănile fetale:',
  '["Always heal with scarring","Can heal without scarring (scarless healing)","Do not heal at all","Take longer to heal","Always require surgery"]'::jsonb,
  '["Se vindecă întotdeauna cu cicatrice","Se pot vindeca fără cicatrice (vindecare fără cicatrici)","Nu se vindecă deloc","Durează mai mult să se vindece","Necesită întotdeauna intervenție chirurgicală"]'::jsonb,
  1,
  'Early fetal wounds can heal without scarring due to different cytokine profiles, minimal inflammation, and regeneration rather than repair.',
  'Rănile fetale timpurii se pot vindeca fără cicatrice datorită profilurilor diferite de citokine, inflamației minime și regenerării în loc de reparare.',
  'integumentary',
  9
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
