  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ82',
  'med-admission-barrons',
  'hard',
  'Contact dermatitis is an example of:',
  'Dermatita de contact este un exemplu de:',
  '["Type I hypersensitivity","Type IV (delayed-type) hypersensitivity","Autoimmune disease","Bacterial infection","Fungal infection"]'::jsonb,
  '["Hipersensibilitate de tip I","Hipersensibilitate de tip IV (întârziată)","Boală autoimună","Infecție bacteriană","Infecție fungică"]'::jsonb,
  1,
  'Contact dermatitis (poison ivy reaction, nickel allergy) is a Type IV (delayed-type) hypersensitivity mediated by T cells and Langerhans cells.',
  'Dermatita de contact (reacție la iederă otrăvitoare, alergie la nichel) este o hipersensibilitate de tip IV (întârziată) mediată de celule T și celule Langerhans.',
  'integumentary',
  9
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ83',
  'med-admission-barrons',
  'hard',
  'Age-related changes in skin include all EXCEPT:',
  'Modificările legate de vârstă ale pielii includ toate CU EXCEPȚIA:',
  '["Thinning of epidermis","Decreased collagen and elastic fiber","Decreased melanocyte activity","Increased sebaceous gland activity","Reduced wound healing capacity"]'::jsonb,
  '["Subțierea epidermei","Scăderea colagenului și a fibrelor elastice","Scăderea activității melanocitelor","Creșterea activității glandelor sebacee","Capacitate redusă de vindecare a rănilor"]'::jsonb,
  3,
  'Aging typically decreases sebaceous gland activity, leading to drier skin. Other changes include thinning, reduced elasticity, and slower healing.',
  'Îmbătrânirea reduce de obicei activitatea glandelor sebacee, ducând la piele mai uscată. Alte modificări includ subțierea, elasticitate redusă și vindecare mai lentă.',
  'integumentary',
  9
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
