INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ86',
  'med-admission-barrons',
  'hard',
  'Melanoma is the most dangerous form of skin cancer because it:',
  'Melanomul este cea mai periculoasă formă de cancer de piele deoarece:',
  '["Is the most common","Has high metastatic potential","Never causes symptoms","Only affects elderly people","Is always visible"]'::jsonb,
  '["Este cel mai frecvent","Are potențial metastatic ridicat","Nu cauzează niciodată simptome","Afectează doar persoanele în vârstă","Este întotdeauna vizibil"]'::jsonb,
  1,
  'Melanoma, arising from melanocytes, has high metastatic potential and can spread rapidly to lymph nodes and other organs if not detected early.',
  'Melanomul, care apare din melanocite, are potențial metastatic ridicat și se poate răspândi rapid la ganglionii limfatici și alte organe dacă nu este detectat devreme.',
