INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ87',
  'med-admission-barrons',
  'hard',
  'Filaggrin is important in the epidermis because it:',
  'Filagrina este importantă în epidermă deoarece:',
  '["Produces melanin","Aggregates keratin filaments and contributes to the skin barrier","Secretes sweat","Forms hair","Conducts nerve impulses"]'::jsonb,
  '["Produce melanină","Agregă filamentele de keratină și contribuie la bariera pielii","Secretă transpirație","Formează părul","Conduce impulsuri nervoase"]'::jsonb,
  1,
  'Filaggrin aggregates keratin filaments in the stratum corneum and its breakdown products contribute to natural moisturizing factors.',
  'Filagrina agregă filamentele de keratină în stratul cornos și produșii săi de degradare contribuie la factorii de hidratare naturală.',
