INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'integ88',
  'med-admission-barrons',
  'hard',
  'Which of the following best describes the blood supply to the epidermis?',
  'Care dintre următoarele descrie cel mai bine aprovizionarea cu sânge a epidermei?',
  '["Dense capillary network throughout","No blood vessels; nutrients diffuse from dermal capillaries","One large artery supplies the entire epidermis","Blood flows directly from heart to epidermis","Lymphatic vessels only"]'::jsonb,
  '["Rețea capilară densă în tot","Fără vase de sânge; nutrienții difuzează din capilarele dermice","O singură arteră mare aprovizionează întreaga epidermă","Sângele curge direct de la inimă la epidermă","Doar vase limfatice"]'::jsonb,
  1,
  'The epidermis is avascular; dermal papillary capillaries deliver nutrients that diffuse through the basement membrane to epidermal cells.',
  'Epiderma este avasculară; capilarele papilare dermice livrează nutrienți care difuzează prin membrana bazală către celulele epidermice.',
  'integumentary',
  9
) ON CONFLICT (id) DO UPDATE SET
