INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'skel2',
  'med-admission-barrons',
  'easy',
  'Which part of a long bone contains the red bone marrow in adults?',
  'Care parte a unui os lung conține măduva osoasă roșie la adulți?',
  '["Compact bone only","Epiphysis (spongy bone regions)","Diaphysis shaft only","Periosteum","Articular cartilage only"]'::jsonb,
  '["Doar osul compact","Epifiza (regiunile de os spongios)","Doar diafiza","Periost","Doar cartilajul articular"]'::jsonb,
  1,
  'Red bone marrow, which produces blood cells, is found in the spongy bone of the epiphyses and in flat and irregular bones.',
