INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc1',
  'med-admission-barrons',
  'easy',
  'Which protein in muscle fibers directly binds to calcium and initiates contraction by moving tropomyosin?',
  'Care proteină din fibrele musculare se leagă direct de calciu și inițiază contracția deplasând tropomiozina?',
  '["Myosin","Actin","Troponin","Tropomyosin","Titin"]'::jsonb,
  '["Miozina","Actina","Troponina","Tropomiozina","Titina"]'::jsonb,
  2,
  'Troponin binds Ca²⁺; this causes tropomyosin to move and expose myosin-binding sites on actin, allowing the cross-bridge cycle.',
  'Troponina se leagă de Ca²⁺; aceasta face ca tropomiozina să se deplaseze și să expună site-urile de legare pentru miozină pe actină, permițând ciclul podurilor în cruce.',
  'muscular',
  1
) ON CONFLICT (id) DO UPDATE SET
