  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc2',
  'med-admission-barrons',
  'easy',
  'Which of the following is the functional unit of skeletal muscle contraction?',
  'Care dintre următoarele este unitatea funcțională a contracției musculare scheletice?',
  '["Whole muscle","Muscle fiber","Sarcomere","Myofibril only","Fascicle"]'::jsonb,
  '["Mușchiul întreg","Fibra musculară","Sarcomerul","Doar miofibrila","Fasciculul"]'::jsonb,
  2,
  'The sarcomere is the repeating unit between two Z discs and is the smallest contractile unit; it shortens when myosin pulls actin.',
  'Sarcomerul este unitatea repetată între două discuri Z și este cea mai mică unitate contractilă; se scurtează când miozina trage actina.',
  'muscular',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
