INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc3',
  'med-admission-barrons',
  'easy',
  'Which neurotransmitter is released at the neuromuscular junction to stimulate skeletal muscle contraction?',
  'Care neurotransmițător este eliberat la joncțiunea neuromusculară pentru a stimula contracția musculară scheletică?',
  '["Dopamine","Serotonin","Acetylcholine","Norepinephrine","GABA"]'::jsonb,
  '["Dopamina","Serotonina","Acetilcolina","Noradrenalina","GABA"]'::jsonb,
  2,
  'Acetylcholine (ACh) is released from motor neuron terminals, binds to receptors on the muscle, and triggers an action potential and contraction.',
  'Acetilcolina (ACh) este eliberată din terminalele neuronului motor, se leagă de receptori pe mușchi și declanșează un potențial de acțiune și contracția.',
  'muscular',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
