  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc4',
  'med-admission-barrons',
  'medium',
  'Where is calcium stored in a skeletal muscle fiber and released in response to an action potential?',
  'Unde este stocat calciul într-o fibră musculară scheletică și eliberat ca răspuns la un potențial de acțiune?',
  '["Mitochondria","Sarcoplasmic reticulum","Nucleus","Golgi apparatus","Cytoplasm only"]'::jsonb,
  '["Mitocondrii","Reticulul sarcoplasmic","Nucleu","Aparatul Golgi","Doar citoplasma"]'::jsonb,
  1,
  'The sarcoplasmic reticulum (SR) stores Ca²⁺; when the muscle is depolarized, the SR releases Ca²⁺ into the cytosol to initiate contraction.',
  'Reticulul sarcoplasmic (RS) stochează Ca²⁺; când mușchiul este depolarizat, RS eliberează Ca²⁺ în citosol pentru a iniția contracția.',
  'muscular',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc5',
  'med-admission-barrons',
  'medium',
  'Which type of muscle contraction occurs when the muscle develops tension but does not change length?',
  'Care tip de contracție musculară are loc când mușchiul dezvoltă tensiune dar nu își schimbă lungimea?',
  '["Isotonic concentric","Isotonic eccentric","Isometric","Twitch only","Tetanic only"]'::jsonb,
  '["Izotonică concentrică","Izotonică excentrică","Izometrică","Doar contracție simplă","Doar tetanică"]'::jsonb,
  2,
  'In an isometric contraction, tension is produced but the muscle length does not change (e.g., holding a weight in a fixed position).',
  'Într-o contracție izometrică se produce tensiune dar lungimea mușchiului nu se schimbă (ex. ținerea unei greutăți într-o poziție fixă).',
  'muscular',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc6',
  'med-admission-barrons',
  'medium',
  'Which structure connects a skeletal muscle to a bone?',
  'Care structură leagă un mușchi scheletic de un os?',
  '["Ligament","Tendon","Aponeurosis only","Fascia only","Cartilage"]'::jsonb,
  '["Ligament","Tendon","Doar aponevroză","Doar fascie","Cartilaj"]'::jsonb,
  1,
  'Tendons are dense connective tissue that attach muscle to bone and transmit the force of contraction to the skeleton.',
  'Tendonii sunt țesut conjunctiv dens care atașează mușchiul de os și transmit forța contracției la schelet.',
  'muscular',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
