  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc7',
  'med-admission-barrons',
  'medium',
  'Which of the following is a direct source of energy for muscle contraction?',
  'Care dintre următoarele este o sursă directă de energie pentru contracția musculară?',
  '["Glucose only","ATP","Glycogen only","Fatty acids only","Creatine only (no ATP)"]'::jsonb,
  '["Doar glucoză","ATP","Doar glicogen","Doar acizi grași","Doar creatină (fără ATP)"]'::jsonb,
  1,
  'ATP is hydrolyzed by myosin ATPase to provide energy for the cross-bridge cycle; other compounds (creatine phosphate, glucose) replenish ATP.',
  'ATP este hidrolizat de miozina ATPază pentru a furniza energie ciclului podurilor în cruce; alte compuși (fosfat de creatină, glucoză) refac ATP-ul.',
  'muscular',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
