  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc8',
  'med-admission-barrons',
  'hard',
  'Which band of the sarcomere shortens during muscle contraction?',
  'Care bandă a sarcomerului se scurtează în timpul contracției musculare?',
  '["A band","I band","H zone","Both I band and H zone","Z disc"]'::jsonb,
  '["Banda A","Banda I","Zona H","Atât banda I cât și zona H","Discul Z"]'::jsonb,
  3,
  'When the sarcomere shortens, the I band (only thin filaments) and the H zone (only thick filaments) shorten; the A band (length of thick filaments) stays the same.',
  'Când sarcomerul se scurtează, banda I (doar filamente subțiri) și zona H (doar filamente groase) se scurtează; banda A (lungimea filamentelor groase) rămâne aceeași.',
  'muscular',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc9',
  'med-admission-barrons',
  'hard',
  'Which characteristic distinguishes smooth muscle from skeletal muscle?',
  'Care caracteristică diferențiază mușchiul neted de mușchiul scheletic?',
  '["Smooth muscle is always under voluntary control","Smooth muscle lacks actin and myosin","Smooth muscle has no troponin and has different regulation (e.g., calmodulin)","Smooth muscle is only found in the heart","Smooth muscle has the same sarcomere structure as skeletal muscle"]'::jsonb,
  '["Mușchiul neted este întotdeauna sub control voluntar","Mușchiul neted nu are actină și miozină","Mușchiul neted nu are troponină și are reglare diferită (ex. calmodulină)","Mușchiul neted se găsește doar în inimă","Mușchiul neted are aceeași structură de sarcomer ca mușchiul scheletic"]'::jsonb,
  2,
  'Smooth muscle has no troponin; Ca²⁺ binds calmodulin, which activates myosin light-chain kinase to phosphorylate myosin and allow contraction.',
  'Mușchiul neted nu are troponină; Ca²⁺ se leagă de calmodulină, care activează kinaza lanțului ușor al miozinei pentru a fosforila miozina și permite contracția.',
  'muscular',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc10',
  'med-admission-barrons',
  'hard',
  'What is the role of the T-tubules (transverse tubules) in skeletal muscle?',
  'Care este rolul tubulilor T (tubuli transversali) în mușchiul scheletic?',
  '["They store calcium for contraction","They conduct the action potential deep into the muscle fiber to trigger Ca²⁺ release from the SR","They synthesize ATP","They attach the muscle to the bone","They form the Z disc"]'::jsonb,
  '["Stochează calciul pentru contracție","Conduc potențialul de acțiune în profunzimea fibrei musculare pentru a declanșa eliberarea de Ca²⁺ din RS","Sintetizează ATP","Atașează mușchiul de os","Formează discul Z"]'::jsonb,
  1,
  'T-tubules are invaginations of the sarcolemma that carry the action potential into the fiber; they lie close to the SR and trigger Ca²⁺ release.',
  'Tubulii T sunt invaginații ale sarcolemei care conduc potențialul de acțiune în fibră; sunt aproape de RS și declanșează eliberarea de Ca²⁺.',
  'muscular',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
