INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc11',
  'med-admission-barrons',
  'easy',
  'The basic contractile unit of skeletal muscle is the:',
  'Unitatea contractilă de bază a mușchiului scheletic este:',
  '["Myofibril","Sarcomere","Muscle fiber","Fascicle","Muscle belly"]'::jsonb,
  '["Miofibrilă","Sarcomer","Fibră musculară","Fascicul","Corpul muscular"]'::jsonb,
  1,
  'The sarcomere is the functional unit of contraction, extending from one Z disc to the next and containing the myofilaments.',
  'Sarcomerul este unitatea funcțională de contracție, extinzându-se de la un disc Z la următorul și conținând miofilamentele.',
