INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc14',
  'med-admission-barrons',
  'easy',
  'During muscle contraction, the sarcomere:',
  'În timpul contracției musculare, sarcomerul:',
  '["Lengthens","Shortens","Stays the same length","Disappears","Moves to the nucleus"]'::jsonb,
  '["Se alungește","Se scurtează","Rămâne la aceeași lungime","Dispare","Se mută la nucleu"]'::jsonb,
  1,
  'During contraction, thin filaments slide over thick filaments, bringing Z discs closer together and shortening the sarcomere.',
  'În timpul contracției, filamentele subțiri alunecă peste filamentele groase, apropiind discurile Z și scurtând sarcomerul.',
