INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc15',
  'med-admission-barrons',
  'easy',
  'The neuromuscular junction is the synapse between:',
  'Joncțiunea neuromusculară este sinapsa între:',
  '["Two neurons","A motor neuron and a muscle fiber","Two muscle fibers","A sensory neuron and skin","Two bones"]'::jsonb,
  '["Doi neuroni","Un neuron motor și o fibră musculară","Două fibre musculare","Un neuron senzitiv și pielea","Două oase"]'::jsonb,
  1,
  'The neuromuscular junction is where a motor neuron axon terminal meets the motor end plate of a muscle fiber.',
