INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc17',
  'med-admission-barrons',
  'easy',
  'Calcium ions required for skeletal muscle contraction are stored in:',
  'Ionii de calciu necesari pentru contracția mușchiului scheletic sunt stocați în:',
  '["Mitochondria","Sarcoplasmic reticulum","Nucleus","Golgi apparatus","Cytoplasm"]'::jsonb,
