INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc18',
  'med-admission-barrons',
  'easy',
  'Skeletal muscle is also known as:',
  'Mușchiul scheletic este cunoscut și ca:',
  '["Involuntary muscle","Striated voluntary muscle","Smooth muscle","Cardiac muscle","Visceral muscle"]'::jsonb,
  '["Mușchi involuntar","Mușchi striat voluntar","Mușchi neted","Mușchi cardiac","Mușchi visceral"]'::jsonb,
  1,
  'Skeletal muscle is striated (due to sarcomere organization) and voluntary (consciously controlled).',
  'Mușchiul scheletic este striat (datorită organizării sarcomerelor) și voluntar (controlat conștient).',
