INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc19',
  'med-admission-barrons',
  'easy',
  'The A band in a sarcomere:',
  'Banda A într-un sarcomer:',
  '["Contains only thin filaments","Contains thick filaments (and overlapping thin filaments)","Contains only Z discs","Is the lightest band","Shortens during contraction"]'::jsonb,
  '["Conține doar filamente subțiri","Conține filamente groase (și filamente subțiri suprapuse)","Conține doar discuri Z","Este banda cea mai deschisă","Se scurtează în timpul contracției"]'::jsonb,
  1,
  'The A (anisotropic/dark) band contains the entire length of thick filaments and overlapping portions of thin filaments.',
  'Banda A (anizotropă/întunecată) conține întreaga lungime a filamentelor groase și porțiunile suprapuse ale filamentelor subțiri.',
  'muscular',
  2
) ON CONFLICT (id) DO UPDATE SET
