INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc20',
  'med-admission-barrons',
  'easy',
  'ATP is required for muscle contraction during which step?',
  'ATP-ul este necesar pentru contracția musculară în care etapă?',
  '["Calcium binding to troponin only","Myosin head detachment from actin and re-cocking","Sarcomere lengthening only","Neurotransmitter release only","None of the above"]'::jsonb,
  '["Doar legarea calciului de troponină","Detașarea capului miozinei de actină și reîncărcarea","Doar alungirea sarcomerului","Doar eliberarea neurotransmițătorului","Nimic din cele de mai sus"]'::jsonb,
  1,
  'ATP binds to myosin to cause detachment from actin and is hydrolyzed to re-cock the myosin head for the next power stroke.',
  'ATP-ul se leagă de miozină pentru a cauza detașarea de actină și este hidrolizat pentru a reîncărca capul miozinei pentru următoarea mișcare de forță.',
  'muscular',
  2
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

-- Set 3 (Easy)
INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc21',
  'med-admission-barrons',
  'easy',
  'The I band in a sarcomere:',
  'Banda I într-un sarcomer:',
  '["Contains thick filaments only","Contains only thin filaments (no overlap with thick)","Is the darkest band","Does not change during contraction","Contains the M line"]'::jsonb,
  '["Conține doar filamente groase","Conține doar filamente subțiri (fără suprapunere cu cele groase)","Este banda cea mai întunecată","Nu se schimbă în timpul contracției","Conține linia M"]'::jsonb,
  1,
  'The I (isotropic/light) band contains only thin filaments and shortens during contraction as filaments slide.',
  'Banda I (izotropă/deschisă) conține doar filamente subțiri și se scurtează în timpul contracției pe măsură ce filamentele alunecă.',
  'muscular',
  3
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
