INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc22',
  'med-admission-barrons',
  'easy',
  'A motor unit consists of:',
  'O unitate motorie constă din:',
  '["One muscle fiber and all its nuclei","One motor neuron and all the muscle fibers it innervates","All the muscles in a limb","One sarcomere","The brain and spinal cord"]'::jsonb,
  '["O fibră musculară și toți nucleii ei","Un neuron motor și toate fibrele musculare pe care le inervează","Toți mușchii dintr-un membru","Un sarcomer","Creierul și măduva spinării"]'::jsonb,
  1,
  'A motor unit is a motor neuron plus all the skeletal muscle fibers it innervates; it is the smallest functional unit of muscle control.',
  'O unitate motorie este un neuron motor plus toate fibrele musculare scheletice pe care le inervează; este cea mai mică unitate funcțională de control muscular.',
  'muscular',
  3
