INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc29',
  'med-admission-barrons',
  'easy',
  'An isotonic contraction involves:',
  'O contracție izotonică implică:',
  '["Muscle tension without length change","Muscle shortening with relatively constant tension","No muscle activity","Relaxation only","Stretching only"]'::jsonb,
  '["Tensiune musculară fără schimbare de lungime","Scurtare musculară cu tensiune relativ constantă","Nicio activitate musculară","Doar relaxare","Doar întindere"]'::jsonb,
  1,
  'Isotonic contractions produce movement (muscle shortens or lengthens) while maintaining relatively constant tension.',
  'Contracțiile izotonice produc mișcare (mușchiul se scurtează sau se alungește) menținând tensiune relativ constantă.',
