INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc30',
  'med-admission-barrons',
  'easy',
  'An isometric contraction involves:',
  'O contracție izometrică implică:',
  '["Muscle shortening","Muscle lengthening","Tension generation without change in muscle length","No ATP usage","Complete relaxation"]'::jsonb,
  '["Scurtare musculară","Alungire musculară","Generarea de tensiune fără schimbarea lungimii musculare","Fără utilizare de ATP","Relaxare completă"]'::jsonb,
  2,
  'Isometric contractions generate tension without changing muscle length, such as holding a heavy object stationary.',
  'Contracțiile izometrice generează tensiune fără a schimba lungimea mușchiului, precum ținerea unui obiect greu staționar.',
