INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc33',
  'med-admission-barrons',
  'easy',
  'Muscle fatigue is primarily caused by:',
  'Oboseala musculară este cauzată în principal de:',
  '["Increased ATP levels","Accumulation of metabolic byproducts (lactic acid, Pi) and ATP depletion","Increased oxygen supply","Decreased temperature","Increased calcium"]'::jsonb,
  '["Niveluri crescute de ATP","Acumularea de produse secundare metabolice (acid lactic, Pi) și epuizarea ATP","Aprovizionare crescută cu oxigen","Temperatură scăzută","Calciu crescut"]'::jsonb,
  1,
  'Muscle fatigue results from ATP depletion, lactic acid accumulation, ionic imbalances, and decreased pH during prolonged activity.',
  'Oboseala musculară rezultă din epuizarea ATP, acumularea de acid lactic, dezechilibre ionice și pH scăzut în timpul activității prelungite.',
  'muscular',
  4
) ON CONFLICT (id) DO UPDATE SET
