  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc34',
  'med-admission-barrons',
  'easy',
  'Type I muscle fibers (slow-twitch) are characterized by:',
  'Fibrele musculare de tip I (contracție lentă) sunt caracterizate de:',
  '["Fast contraction, low endurance","Slow contraction, high endurance, rich in mitochondria","No myoglobin","Low capillary supply","Anaerobic metabolism only"]'::jsonb,
  '["Contracție rapidă, rezistență scăzută","Contracție lentă, rezistență mare, bogate în mitocondrii","Fără mioglobină","Aprovizionare capilară scăzută","Doar metabolism anaerob"]'::jsonb,
  1,
  'Type I (slow oxidative) fibers are red, fatigue-resistant, have many mitochondria and capillaries, and use aerobic metabolism.',
  'Fibrele de tip I (oxidative lente) sunt roșii, rezistente la oboseală, au multe mitocondrii și capilare și folosesc metabolism aerob.',
  'muscular',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
