  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc35',
  'med-admission-barrons',
  'easy',
  'Type II muscle fibers (fast-twitch) are characterized by:',
  'Fibrele musculare de tip II (contracție rapidă) sunt caracterizate de:',
  '["Slow contraction, high endurance","Fast contraction, lower endurance, fewer mitochondria","Red color only","Only aerobic metabolism","Cannot generate much force"]'::jsonb,
  '["Contracție lentă, rezistență mare","Contracție rapidă, rezistență mai scăzută, mai puține mitocondrii","Doar culoare roșie","Doar metabolism aerob","Nu poate genera multă forță"]'::jsonb,
  1,
  'Type II (fast glycolytic) fibers are white/pale, fatigue quickly, have fewer mitochondria, and rely more on anaerobic glycolysis.',
  'Fibrele de tip II (glicolitice rapide) sunt albe/pale, obosesc rapid, au mai puține mitocondrii și se bazează mai mult pe glicoliza anaerobă.',
  'muscular',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc36',
  'med-admission-barrons',
  'easy',
  'Rigor mortis occurs because:',
  'Rigiditatea cadaverică apare deoarece:',
  '["Muscles are too relaxed","Without ATP, myosin cannot detach from actin","Calcium levels decrease","Nerves continue to fire","Muscles continue to contract voluntarily"]'::jsonb,
  '["Mușchii sunt prea relaxați","Fără ATP, miozina nu se poate detașa de actină","Nivelurile de calciu scad","Nervii continuă să transmită","Mușchii continuă să se contracte voluntar"]'::jsonb,
  1,
  'After death, ATP production stops; without ATP, myosin heads remain bound to actin, causing muscle stiffening.',
  'După moarte, producția de ATP se oprește; fără ATP, capetele miozinei rămân legate de actină, cauzând rigidizarea musculară.',
  'muscular',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc37',
  'med-admission-barrons',
  'easy',
  'The prime mover (agonist) is the muscle that:',
  'Motorul primar (agonistul) este mușchiul care:',
  '["Opposes the movement","Is primarily responsible for producing a movement","Stabilizes a joint","Relaxes during movement","Has no function"]'::jsonb,
  '["Se opune mișcării","Este în principal responsabil pentru producerea unei mișcări","Stabilizează o articulație","Se relaxează în timpul mișcării","Nu are nicio funcție"]'::jsonb,
  1,
  'The agonist (prime mover) is the muscle primarily responsible for generating a specific movement.',
  'Agonistul (motorul primar) este mușchiul în principal responsabil pentru generarea unei mișcări specifice.',
  'muscular',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc38',
  'med-admission-barrons',
  'easy',
  'The antagonist muscle:',
  'Mușchiul antagonist:',
  '["Assists the prime mover","Opposes the action of the prime mover","Is always contracted","Produces the main movement","Stabilizes the origin"]'::jsonb,
  '["Ajută motorul primar","Se opune acțiunii motorului primar","Este întotdeauna contractat","Produce mișcarea principală","Stabilizează originea"]'::jsonb,
  1,
  'The antagonist opposes or reverses the action of the agonist; it must relax while the agonist contracts.',
  'Antagonistul se opune sau inversează acțiunea agonistului; trebuie să se relaxeze în timp ce agonistul se contractă.',
  'muscular',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
