  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc39',
  'med-admission-barrons',
  'easy',
  'A synergist muscle:',
  'Un mușchi sinergist:',
  '["Opposes the prime mover","Assists the prime mover in its action","Is always relaxed","Only works during rest","Has no attachment to bones"]'::jsonb,
  '["Se opune motorului primar","Ajută motorul primar în acțiunea sa","Este întotdeauna relaxat","Funcționează doar în repaus","Nu are atașament de oase"]'::jsonb,
  1,
  'Synergists assist the prime mover by adding force or reducing unwanted movements.',
  'Sinergistii ajută motorul primar adăugând forță sau reducând mișcările nedorite.',
  'muscular',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
