  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc40',
  'med-admission-barrons',
  'easy',
  'Myoglobin in muscle tissue functions to:',
  'Mioglobina din țesutul muscular funcționează pentru a:',
  '["Contract the muscle","Store and deliver oxygen within muscle cells","Produce ATP","Bind calcium","Form cross-bridges"]'::jsonb,
  '["Contracta mușchiul","Stoca și livra oxigen în celulele musculare","Produce ATP","Lega calciul","Forma punți transversale"]'::jsonb,
  1,
  'Myoglobin is an oxygen-binding protein that stores oxygen in muscle cells for aerobic respiration.',
  'Mioglobina este o proteină care leagă oxigenul și stochează oxigen în celulele musculare pentru respirația aerobă.',
  'muscular',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
