  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

-- Set 5 (Medium)
INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc41',
  'med-admission-barrons',
  'medium',
  'The sliding filament theory explains that during contraction:',
  'Teoria alunecării filamentelor explică că în timpul contracției:',
  '["Filaments shorten","Thin filaments slide past thick filaments without changing length","Sarcomeres disappear","ATP is not required","Calcium is released from mitochondria"]'::jsonb,
  '["Filamentele se scurtează","Filamentele subțiri alunecă pe lângă filamentele groase fără a-și schimba lungimea","Sarcomerele dispar","ATP-ul nu este necesar","Calciul este eliberat din mitocondrii"]'::jsonb,
  1,
  'The sliding filament theory states that thin (actin) filaments slide along thick (myosin) filaments, shortening the sarcomere without changing filament length.',
  'Teoria alunecării filamentelor afirmă că filamentele subțiri (actină) alunecă de-a lungul filamentelor groase (miozină), scurtând sarcomerul fără a schimba lungimea filamentelor.',
  'muscular',
  5
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc42',
  'med-admission-barrons',
  'medium',
  'Excitation-contraction coupling refers to:',
  'Cuplarea excitație-contracție se referă la:',
  '["Binding of neurotransmitter to receptor","Events linking action potential to muscle contraction (Ca²⁺ release)","ATP synthesis","Protein synthesis","Muscle relaxation"]'::jsonb,
  '["Legarea neurotransmițătorului de receptor","Evenimentele care leagă potențialul de acțiune de contracția musculară (eliberarea Ca²⁺)","Sinteza ATP","Sinteza proteinelor","Relaxarea musculară"]'::jsonb,
  1,
  'Excitation-contraction coupling links the action potential to Ca²⁺ release from SR, initiating the cross-bridge cycle.',
  'Cuplarea excitație-contracție leagă potențialul de acțiune de eliberarea Ca²⁺ din RS, inițiind ciclul punților transversale.',
  'muscular',
  5
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
