INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc43',
  'med-admission-barrons',
  'medium',
  'Troponin functions by:',
  'Troponina funcționează prin:',
  '["Forming cross-bridges","Binding calcium and causing tropomyosin to move, exposing myosin-binding sites","Hydrolyzing ATP","Storing calcium","Releasing acetylcholine"]'::jsonb,
  '["Formarea punților transversale","Legarea calciului și determinarea tropomiozinei să se miște, expunând situsurile de legare a miozinei","Hidrolizarea ATP","Stocarea calciului","Eliberarea acetilcolinei"]'::jsonb,
  1,
  'Troponin binds Ca²⁺, causing a conformational change that moves tropomyosin, exposing myosin-binding sites on actin.',
  'Troponina leagă Ca²⁺, cauzând o schimbare conformațională care mișcă tropomiozina, expunând situsurile de legare a miozinei pe actină.',
  'muscular',
  5
) ON CONFLICT (id) DO UPDATE SET
