INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc44',
  'med-admission-barrons',
  'medium',
  'The power stroke in muscle contraction is:',
  'Mișcarea de forță în contracția musculară este:',
  '["ATP binding to myosin","The pivoting of the myosin head that pulls the thin filament","Calcium binding to troponin","Acetylcholine release","Sarcomere lengthening"]'::jsonb,
  '["Legarea ATP de miozină","Pivotarea capului miozinei care trage filamentul subțire","Legarea calciului de troponină","Eliberarea acetilcolinei","Alungirea sarcomerului"]'::jsonb,
  1,
  'The power stroke occurs when the myosin head pivots, pulling the actin filament toward the center of the sarcomere.',
  'Mișcarea de forță are loc când capul miozinei pivotează, trăgând filamentul de actină spre centrul sarcomerului.',
  'muscular',
  5
) ON CONFLICT (id) DO UPDATE SET
