INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc46',
  'med-admission-barrons',
  'medium',
  'The all-or-none principle of muscle contraction states that:',
  'Principiul totul-sau-nimic al contracției musculare afirmă că:',
  '["All muscles contract at once","A muscle fiber contracts fully or not at all when stimulated","Only some sarcomeres contract","Muscles can partially contract","ATP is not needed"]'::jsonb,
  '["Toți mușchii se contractă odată","O fibră musculară se contractă complet sau deloc când este stimulată","Doar unele sarcomere se contractă","Mușchii se pot contracta parțial","ATP-ul nu este necesar"]'::jsonb,
  1,
  'A muscle fiber either contracts completely when threshold is reached or does not contract at all; graded responses come from recruiting more motor units.',
  'O fibră musculară fie se contractă complet când pragul este atins, fie nu se contractă deloc; răspunsurile gradate vin din recrutarea mai multor unități motorii.',
  'muscular',
  5
