INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc53',
  'med-admission-barrons',
  'medium',
  'Smooth muscle contraction differs from skeletal muscle in that smooth muscle:',
  'Contracția mușchiului neted diferă de mușchiul scheletic prin faptul că mușchiul neted:',
  '["Uses troponin for calcium regulation","Uses calmodulin and myosin light chain kinase for regulation","Has sarcomeres","Is striated","Is voluntary"]'::jsonb,
  '["Folosește troponina pentru reglarea calciului","Folosește calmodulina și kinaza lanțului ușor de miozină pentru reglare","Are sarcomere","Este striat","Este voluntar"]'::jsonb,
  1,
  'Smooth muscle lacks troponin; instead, Ca²⁺-calmodulin activates myosin light chain kinase, which phosphorylates myosin to allow contraction.',
  'Mușchiul neted nu are troponină; în schimb, Ca²⁺-calmodulina activează kinaza lanțului ușor de miozină, care fosforilează miozina pentru a permite contracția.',
