INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc59',
  'med-admission-barrons',
  'medium',
  'Length-tension relationship in muscle states that:',
  'Relația lungime-tensiune în mușchi afirmă că:',
  '["Maximum tension occurs at extreme lengths","Maximum tension occurs at optimal sarcomere length with maximum overlap","Length does not affect tension","Shorter muscles produce more force","Longer muscles always produce more force"]'::jsonb,
  '["Tensiunea maximă apare la lungimi extreme","Tensiunea maximă apare la lungimea optimă a sarcomerului cu suprapunere maximă","Lungimea nu afectează tensiunea","Mușchii mai scurți produc mai multă forță","Mușchii mai lungi produc întotdeauna mai multă forță"]'::jsonb,
  1,
  'Maximum force is generated when sarcomeres are at optimal length, allowing maximum overlap between thick and thin filaments.',
  'Forța maximă este generată când sarcomerele sunt la lungime optimă, permițând suprapunere maximă între filamentele groase și subțiri.',
