INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc62',
  'med-admission-barrons',
  'medium',
  'SERCA pumps in muscle function to:',
  'Pompele SERCA din mușchi funcționează pentru a:',
  '["Release calcium into the sarcoplasm","Pump calcium back into the sarcoplasmic reticulum for relaxation","Release acetylcholine","Produce ATP","Transport oxygen"]'::jsonb,
  '["Elibera calciu în sarcoplasmă","Pompa calciul înapoi în reticulul sarcoplasmic pentru relaxare","Elibera acetilcolina","Produce ATP","Transporta oxigen"]'::jsonb,
  1,
  'SERCA (SR Ca²⁺-ATPase) uses ATP to pump Ca²⁺ from sarcoplasm back into the SR, causing muscle relaxation.',
  'SERCA (Ca²⁺-ATP-aza RS) folosește ATP pentru a pompa Ca²⁺ din sarcoplasmă înapoi în RS, cauzând relaxarea musculară.',
  'muscular',
  7
) ON CONFLICT (id) DO UPDATE SET
