INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc63',
  'med-admission-barrons',
  'medium',
  'The latent period in a muscle twitch is:',
  'Perioada latentă într-o sacadă musculară este:',
  '["The contraction phase","The time between stimulus and start of contraction","The relaxation phase","The refractory period","The tetanic phase"]'::jsonb,
  '["Faza de contracție","Timpul între stimul și începutul contracției","Faza de relaxare","Perioada refractară","Faza tetanică"]'::jsonb,
  1,
  'The latent period is the delay between stimulus and visible contraction, during which excitation-contraction coupling occurs.',
  'Perioada latentă este întârzierea între stimul și contracția vizibilă, în timpul căreia are loc cuplarea excitație-contracție.',
  'muscular',
  7
) ON CONFLICT (id) DO UPDATE SET
