INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc64',
  'med-admission-barrons',
  'medium',
  'Oxygen debt (excess post-exercise oxygen consumption) occurs because:',
  'Datoria de oxigen (consumul de oxigen post-exercițiu în exces) apare deoarece:',
  '["Muscles need to replace ATP, creatine phosphate, and convert lactic acid","Muscles stop using oxygen","No metabolic recovery is needed","Calcium levels remain high","ATP is no longer required"]'::jsonb,
  '["Mușchii trebuie să înlocuiască ATP, fosfatul de creatină și să convertească acidul lactic","Mușchii opresc utilizarea oxigenului","Nu este necesară nicio recuperare metabolică","Nivelurile de calciu rămân ridicate","ATP-ul nu mai este necesar"]'::jsonb,
  0,
  'After intense exercise, extra oxygen is needed to replenish ATP, creatine phosphate, and convert lactic acid back to glucose.',
  'După exerciții intense, oxigen suplimentar este necesar pentru a reîncărca ATP, fosfatul de creatină și a converti acidul lactic înapoi în glucoză.',
  'muscular',
  7
) ON CONFLICT (id) DO UPDATE SET
