INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc71',
  'med-admission-barrons',
  'hard',
  'Duchenne muscular dystrophy is caused by:',
  'Distrofia musculară Duchenne este cauzată de:',
  '["Autoimmune attack on muscle","Mutation affecting dystrophin protein","Vitamin deficiency","Bacterial infection","Excess calcium"]'::jsonb,
  '["Atac autoimun asupra mușchiului","Mutație care afectează proteina distrofină","Deficiență de vitamine","Infecție bacteriană","Calciu excesiv"]'::jsonb,
  1,
  'Duchenne MD is caused by mutations in the dystrophin gene (X-linked), leading to absence of dystrophin and progressive muscle degeneration.',
  'Distrofia Duchenne este cauzată de mutații în gena distrofinei (legată de X), ducând la absența distrofinei și degenerare musculară progresivă.',
  'muscular',
  8
) ON CONFLICT (id) DO UPDATE SET
