INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc72',
  'med-admission-barrons',
  'hard',
  'Myasthenia gravis is characterized by:',
  'Miastenia gravis este caracterizată de:',
  '["Destruction of muscle fibers","Autoantibodies against acetylcholine receptors at the NMJ","Excess acetylcholine release","Overactive motor neurons","Calcium channel mutations"]'::jsonb,
  '["Distrugerea fibrelor musculare","Autoanticorpi împotriva receptorilor de acetilcolină la JNM","Eliberare excesivă de acetilcolină","Neuroni motori hiperactivi","Mutații ale canalelor de calciu"]'::jsonb,
  1,
  'Myasthenia gravis is an autoimmune disease where antibodies attack ACh receptors, reducing neuromuscular transmission and causing muscle weakness.',
  'Miastenia gravis este o boală autoimună în care anticorpii atacă receptorii ACh, reducând transmisia neuromusculară și cauzând slăbiciune musculară.',
  'muscular',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
