  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc73',
  'med-admission-barrons',
  'hard',
  'Botulinum toxin affects muscle by:',
  'Toxina botulinică afectează mușchiul prin:',
  '["Increasing ACh release","Preventing ACh release from motor neurons","Destroying muscle fibers","Increasing calcium release","Stimulating contraction"]'::jsonb,
  '["Creșterea eliberării de ACh","Prevenirea eliberării de ACh din neuronii motori","Distrugerea fibrelor musculare","Creșterea eliberării de calciu","Stimularea contracției"]'::jsonb,
  1,
  'Botulinum toxin blocks ACh release at the NMJ by cleaving SNARE proteins, causing flaccid paralysis.',
  'Toxina botulinică blochează eliberarea ACh la JNM prin clivarea proteinelor SNARE, cauzând paralizie flască.',
  'muscular',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
