  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc74',
  'med-admission-barrons',
  'hard',
  'Tetanus toxin affects muscle by:',
  'Toxina tetanică afectează mușchiul prin:',
  '["Blocking ACh release at NMJ","Blocking inhibitory neurotransmitters in the CNS, causing spastic paralysis","Destroying muscle fibers","Increasing muscle relaxation","Decreasing calcium release"]'::jsonb,
  '["Blocarea eliberării de ACh la JNM","Blocarea neurotransmițătorilor inhibitori în SNC, cauzând paralizie spastică","Distrugerea fibrelor musculare","Creșterea relaxării musculare","Scăderea eliberării de calciu"]'::jsonb,
  1,
  'Tetanus toxin blocks glycine and GABA release in the CNS, preventing inhibition of motor neurons, causing sustained muscle contraction (spastic paralysis).',
  'Toxina tetanică blochează eliberarea de glicină și GABA în SNC, prevenind inhibarea neuronilor motori, cauzând contracție musculară susținută (paralizie spastică).',
  'muscular',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc75',
  'med-admission-barrons',
  'hard',
  'Malignant hyperthermia is triggered by:',
  'Hipertermia malignă este declanșată de:',
  '["Exercise","Certain anesthetic agents in susceptible individuals","Bacterial infection","Dehydration","Vitamin deficiency"]'::jsonb,
  '["Exerciții fizice","Anumiți agenți anestezici la indivizi susceptibili","Infecție bacteriană","Deshidratare","Deficiență de vitamine"]'::jsonb,
  1,
  'Malignant hyperthermia is a pharmacogenetic disorder where certain anesthetics (halothane, succinylcholine) cause uncontrolled Ca²⁺ release from SR.',
  'Hipertermia malignă este o tulburare farmacogenetică în care anumiți anestezici (halotan, succinilcolină) cauzează eliberare necontrolată de Ca²⁺ din RS.',
  'muscular',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
