  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc76',
  'med-admission-barrons',
  'hard',
  'The force-velocity relationship in muscle states that:',
  'Relația forță-viteză în mușchi afirmă că:',
  '["Higher velocity means higher force","Force decreases as contraction velocity increases","Velocity does not affect force","Maximum force occurs at maximum velocity","Relaxed muscles produce most force"]'::jsonb,
  '["Viteză mai mare înseamnă forță mai mare","Forța scade pe măsură ce viteza de contracție crește","Viteza nu afectează forța","Forța maximă apare la viteză maximă","Mușchii relaxați produc cea mai mare forță"]'::jsonb,
  1,
  'As contraction velocity increases, force production decreases because cross-bridges have less time to form and cycle.',
  'Pe măsură ce viteza de contracție crește, producția de forță scade deoarece punțile transversale au mai puțin timp să se formeze și să cicleze.',
  'muscular',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc77',
  'med-admission-barrons',
  'hard',
  'Rhabdomyolysis involves:',
  'Rabdomioliza implică:',
  '["Muscle hypertrophy","Rapid breakdown of skeletal muscle releasing myoglobin","Increased muscle strength","Normal muscle activity","Only cardiac muscle damage"]'::jsonb,
  '["Hipertrofia musculară","Descompunerea rapidă a mușchiului scheletic eliberând mioglobină","Forță musculară crescută","Activitate musculară normală","Doar deteriorare a mușchiului cardiac"]'::jsonb,
  1,
  'Rhabdomyolysis is muscle breakdown releasing myoglobin into blood, which can cause kidney damage; often from trauma, overexertion, or drugs.',
  'Rabdomioliza este descompunerea musculară care eliberează mioglobină în sânge, care poate cauza deteriorarea rinichilor; adesea din traumă, suprasolicitare sau medicamente.',
  'muscular',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc78',
  'med-admission-barrons',
  'hard',
  'The size principle of motor unit recruitment states that:',
  'Principiul mărimii recrutării unităților motorii afirmă că:',
  '["Large motor units are recruited first","Small motor units are recruited first, then larger ones as force needs increase","All motor units are recruited simultaneously","Only fast-twitch fibers are recruited","Recruitment order is random"]'::jsonb,
  '["Unitățile motorii mari sunt recrutate primele","Unitățile motorii mici sunt recrutate primele, apoi cele mai mari pe măsură ce nevoile de forță cresc","Toate unitățile motorii sunt recrutate simultan","Doar fibrele cu contracție rapidă sunt recrutate","Ordinea recrutării este aleatorie"]'::jsonb,
  1,
  'The size principle: smaller motor units (slow-twitch, fatigue-resistant) are recruited first; larger units (fast-twitch) are added as more force is needed.',
  'Principiul mărimii: unitățile motorii mai mici (contracție lentă, rezistente la oboseală) sunt recrutate primele; unitățile mai mari (contracție rapidă) sunt adăugate când este nevoie de mai multă forță.',
  'muscular',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc79',
  'med-admission-barrons',
  'hard',
  'Satellite cells in skeletal muscle function to:',
  'Celulele satelite din mușchiul scheletic funcționează pentru a:',
  '["Produce ATP","Serve as muscle stem cells for repair and regeneration","Contract the muscle","Store calcium","Transmit nerve impulses"]'::jsonb,
  '["Produce ATP","Servi ca celule stem musculare pentru reparare și regenerare","Contracta mușchiul","Stoca calciu","Transmite impulsuri nervoase"]'::jsonb,
  1,
  'Satellite cells are muscle stem cells that can proliferate and fuse to repair damaged muscle fibers or contribute to hypertrophy.',
  'Celulele satelite sunt celule stem musculare care pot prolifera și fuziona pentru a repara fibrele musculare deteriorate sau pentru a contribui la hipertrofie.',
  'muscular',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc80',
  'med-admission-barrons',
  'hard',
  'The cross-bridge cycle in muscle contraction includes (in order):',
  'Ciclul punților transversale în contracția musculară include (în ordine):',
  '["Detachment → power stroke → cross-bridge formation → ATP hydrolysis","Cross-bridge formation → power stroke → detachment → ATP hydrolysis and re-cocking","ATP binding → power stroke → calcium release → detachment","Relaxation → contraction → calcium binding → ATP synthesis","Random sequence"]'::jsonb,
  '["Detașare → mișcare de forță → formarea punții → hidroliza ATP","Formarea punții → mișcare de forță → detașare → hidroliza ATP și reîncărcare","Legarea ATP → mișcare de forță → eliberarea calciului → detașare","Relaxare → contracție → legarea calciului → sinteza ATP","Secvență aleatorie"]'::jsonb,
  1,
  'Cross-bridge cycle: myosin binds actin (cross-bridge formation) → power stroke → ATP binds causing detachment → ATP hydrolyzed to re-cock head.',
  'Ciclul punților transversale: miozina se leagă de actină (formarea punții) → mișcare de forță → ATP-ul se leagă cauzând detașarea → ATP-ul hidrolizat pentru a reîncărca capul.',
  'muscular',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

-- Set 9 (Hard)
INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc81',
  'med-admission-barrons',
  'hard',
  'Lambert-Eaton myasthenic syndrome differs from myasthenia gravis in that it:',
  'Sindromul miastenic Lambert-Eaton diferă de miastenia gravis prin faptul că:',
  '["Attacks acetylcholine receptors","Attacks voltage-gated calcium channels on motor neurons","Is not autoimmune","Affects only smooth muscle","Causes excess ACh release"]'::jsonb,
  '["Atacă receptorii de acetilcolină","Atacă canalele de calciu voltaj-dependente de pe neuronii motori","Nu este autoimun","Afectează doar mușchiul neted","Cauzează eliberare excesivă de ACh"]'::jsonb,
  1,
  'Lambert-Eaton syndrome involves autoantibodies against presynaptic voltage-gated Ca²⁺ channels, reducing ACh release.',
  'Sindromul Lambert-Eaton implică autoanticorpi împotriva canalelor de Ca²⁺ voltaj-dependente presinaptice, reducând eliberarea de ACh.',
  'muscular',
  9
) ON CONFLICT (id) DO UPDATE SET
