INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc82',
  'med-admission-barrons',
  'hard',
  'Curare blocks muscle contraction by:',
  'Curara blochează contracția musculară prin:',
  '["Blocking ACh release","Competitively blocking nicotinic ACh receptors","Blocking calcium release from SR","Destroying muscle fibers","Inhibiting ATP synthesis"]'::jsonb,
  '["Blocarea eliberării de ACh","Blocarea competitivă a receptorilor nicotinici de ACh","Blocarea eliberării de calciu din RS","Distrugerea fibrelor musculare","Inhibarea sintezei de ATP"]'::jsonb,
  1,
  'Curare is a competitive antagonist of nicotinic ACh receptors at the NMJ, preventing depolarization and causing paralysis.',
  'Curara este un antagonist competitiv al receptorilor nicotinici de ACh la JNM, prevenind depolarizarea și cauzând paralizie.',
