INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc83',
  'med-admission-barrons',
  'hard',
  'Neostigmine treats myasthenia gravis by:',
  'Neostigmina tratează miastenia gravis prin:',
  '["Increasing ACh receptor number","Inhibiting acetylcholinesterase, prolonging ACh action","Blocking ACh receptors","Increasing calcium release","Destroying antibodies"]'::jsonb,
  '["Creșterea numărului de receptori ACh","Inhibarea acetilcolinesterazei, prelungind acțiunea ACh","Blocarea receptorilor ACh","Creșterea eliberării de calciu","Distrugerea anticorpilor"]'::jsonb,
  1,
  'Neostigmine is a cholinesterase inhibitor that increases ACh concentration at the NMJ, compensating for reduced receptors.',
  'Neostigmina este un inhibitor al colinesterazei care crește concentrația de ACh la JNM, compensând receptorii reduși.',
