INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc84',
  'med-admission-barrons',
  'hard',
  'Cardiac muscle differs from skeletal muscle in that cardiac muscle:',
  'Mușchiul cardiac diferă de mușchiul scheletic prin faptul că mușchiul cardiac:',
  '["Is voluntary","Has longer action potentials with a plateau phase","Lacks striations","Has no T-tubules","Uses troponin for contraction"]'::jsonb,
  '["Este voluntar","Are potențiale de acțiune mai lungi cu o fază de platou","Nu are striații","Nu are tubuli T","Folosește troponina pentru contracție"]'::jsonb,
  1,
  'Cardiac action potentials have a prolonged plateau phase (due to Ca²⁺ influx), preventing tetanus and ensuring rhythmic contraction.',
  'Potențialele de acțiune cardiace au o fază de platou prelungită (datorită influxului de Ca²⁺), prevenind tetanosul și asigurând contracție ritmică.',
  'muscular',
  9
