INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc85',
  'med-admission-barrons',
  'hard',
  'Single-unit smooth muscle is characterized by:',
  'Mușchiul neted cu o singură unitate este caracterizat de:',
  '["No gap junctions","Gap junctions allowing coordinated contraction as a unit","Voluntary control","Striations","Individual cell control"]'::jsonb,
  '["Fără joncțiuni gap","Joncțiuni gap permițând contracție coordonată ca o unitate","Control voluntar","Striații","Control celular individual"]'::jsonb,
  1,
  'Single-unit (visceral) smooth muscle cells are electrically coupled by gap junctions, allowing them to contract together as a functional unit.',
  'Celulele musculare netede cu o singură unitate (viscerale) sunt cuplate electric prin joncțiuni gap, permițându-le să se contracte împreună ca o unitate funcțională.',
  'muscular',
  9
) ON CONFLICT (id) DO UPDATE SET
