  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc86',
  'med-admission-barrons',
  'hard',
  'Titin protein in muscle functions to:',
  'Proteina titină din mușchi funcționează pentru a:',
  '["Form cross-bridges","Provide elasticity and prevent sarcomere overstretching","Store calcium","Release ATP","Bind troponin"]'::jsonb,
  '["Forma punți transversale","Oferi elasticitate și preveni supraîntinderea sarcomerului","Stoca calciu","Elibera ATP","Lega troponina"]'::jsonb,
  1,
  'Titin (connectin) is a giant elastic protein that spans from Z disc to M line, providing elasticity and centering thick filaments.',
  'Titina (conectina) este o proteină elastică gigantică care se întinde de la discul Z la linia M, oferind elasticitate și centrând filamentele groase.',
  'muscular',
  9
) ON CONFLICT (id) DO UPDATE SET
