  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc87',
  'med-admission-barrons',
  'hard',
  'Dystrophin protein normally functions to:',
  'Proteina distrofină funcționează în mod normal pentru a:',
  '["Contract the muscle","Link the cytoskeleton to the extracellular matrix, stabilizing the sarcolemma","Store calcium","Produce ATP","Release neurotransmitters"]'::jsonb,
  '["Contracta mușchiul","Lega citoscheletul de matricea extracelulară, stabilizând sarcolema","Stoca calciu","Produce ATP","Elibera neurotransmițători"]'::jsonb,
  1,
  'Dystrophin connects the cytoskeleton (actin) to the extracellular matrix via the dystrophin-glycoprotein complex, stabilizing the sarcolemma during contraction.',
  'Distrofina conectează citoscheletul (actina) de matricea extracelulară prin complexul distrofină-glicoproteină, stabilizând sarcolema în timpul contracției.',
  'muscular',
  9
) ON CONFLICT (id) DO UPDATE SET
