  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc88',
  'med-admission-barrons',
  'hard',
  'Muscle spindles detect:',
  'Fusurile musculare detectează:',
  '["Muscle tension","Muscle length and rate of length change","Pain","Temperature","Blood pressure"]'::jsonb,
  '["Tensiunea musculară","Lungimea mușchiului și rata schimbării lungimii","Durerea","Temperatura","Tensiunea arterială"]'::jsonb,
  1,
  'Muscle spindles are stretch receptors that detect muscle length and velocity of stretch, important for the stretch reflex.',
  'Fusurile musculare sunt receptori de întindere care detectează lungimea mușchiului și viteza întinderii, importanți pentru reflexul de întindere.',
