INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc89',
  'med-admission-barrons',
  'hard',
  'Golgi tendon organs detect:',
  'Organele tendinoase Golgi detectează:',
  '["Muscle length","Muscle tension (force)","Temperature","Vibration","Pain only"]'::jsonb,
  '["Lungimea mușchiului","Tensiunea musculară (forța)","Temperatura","Vibrația","Doar durerea"]'::jsonb,
  1,
  'Golgi tendon organs in tendons detect muscle tension; excessive tension triggers a protective reflex that inhibits contraction.',
  'Organele tendinoase Golgi din tendoane detectează tensiunea musculară; tensiunea excesivă declanșează un reflex protector care inhibă contracția.',
