INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc90',
  'med-admission-barrons',
  'hard',
  'The stretch reflex (myotatic reflex) involves:',
  'Reflexul de întindere (reflexul miotatic) implică:',
  '["Muscle relaxation when stretched","Muscle contraction in response to stretch (monosynaptic)","Inhibition of motor neurons","Cardiac muscle only","Voluntary movement"]'::jsonb,
  '["Relaxarea mușchiului când este întins","Contracția mușchiului ca răspuns la întindere (monosinaptic)","Inhibarea neuronilor motori","Doar mușchi cardiac","Mișcare voluntară"]'::jsonb,
  1,
  'The stretch reflex is a monosynaptic reflex where muscle stretch activates spindles, causing reflex contraction of the same muscle (e.g., knee-jerk).',
  'Reflexul de întindere este un reflex monosinaptic în care întinderea mușchiului activează fusurile, cauzând contracție reflexă a aceluiași mușchi (ex. reflexul rotulian).',
  'muscular',
  9
) ON CONFLICT (id) DO UPDATE SET
