INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc91',
  'med-admission-barrons',
  'hard',
  'Fibromyalgia is characterized by:',
  'Fibromialgia este caracterizată de:',
  '["Inflammation of muscles","Chronic widespread pain without inflammation or muscle damage","Muscle wasting","Autoimmune destruction of muscles","Bacterial infection"]'::jsonb,
  '["Inflamația mușchilor","Durere cronică răspândită fără inflamație sau deteriorare musculară","Atrofie musculară","Distrugere autoimună a mușchilor","Infecție bacteriană"]'::jsonb,
  1,
  'Fibromyalgia is a chronic pain syndrome with widespread musculoskeletal pain, fatigue, and tender points, without objective muscle pathology.',
  'Fibromialgia este un sindrom de durere cronică cu durere musculoscheletică răspândită, oboseală și puncte dureroase, fără patologie musculară obiectivă.',
  'muscular',
  10
) ON CONFLICT (id) DO UPDATE SET
