INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc92',
  'med-admission-barrons',
  'hard',
  'Denervation supersensitivity occurs when:',
  'Hipersensibilitatea de denervare apare când:',
  '["Nerves become more active","Muscle develops increased sensitivity to ACh after losing nerve supply","Muscles atrophy completely","Calcium levels decrease","ATP production increases"]'::jsonb,
  '["Nervii devin mai activi","Mușchiul dezvoltă sensibilitate crescută la ACh după pierderea inervației","Mușchii se atrofiază complet","Nivelurile de calciu scad","Producția de ATP crește"]'::jsonb,
  1,
  'After denervation, muscle fibers upregulate ACh receptors across the entire membrane, becoming supersensitive to acetylcholine.',
  'După denervare, fibrele musculare supraexprimă receptorii ACh pe întreaga membrană, devenind hipersensibile la acetilcolină.',
  'muscular',
  10
) ON CONFLICT (id) DO UPDATE SET
