  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc93',
  'med-admission-barrons',
  'hard',
  'Smooth muscle exhibits stress-relaxation response, meaning it:',
  'Mușchiul neted prezintă răspuns de stres-relaxare, însemnând că:',
  '["Cannot relax","Initially resists stretch then relaxes to accommodate increased volume","Contracts continuously","Never changes length","Only responds to nerves"]'::jsonb,
  '["Nu se poate relaxa","Rezistă inițial întinderii apoi se relaxează pentru a acomoda volumul crescut","Se contractă continuu","Nu își schimbă niciodată lungimea","Răspunde doar la nervi"]'::jsonb,
  1,
  'Stress-relaxation allows smooth muscle in hollow organs to accommodate volume increases while maintaining relatively constant pressure.',
  'Răspunsul de stres-relaxare permite mușchiului neted din organele cavitare să acomodeze creșteri de volum menținând presiune relativ constantă.',
  'muscular',
  10
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
