  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc94',
  'med-admission-barrons',
  'hard',
  'Latch state in smooth muscle refers to:',
  'Starea de blocare în mușchiul neted se referă la:',
  '["Rapid contraction","Sustained contraction with low ATP consumption","Complete relaxation","Maximum force generation","Inability to contract"]'::jsonb,
  '["Contracție rapidă","Contracție susținută cu consum scăzut de ATP","Relaxare completă","Generare maximă de forță","Incapacitate de a se contracta"]'::jsonb,
  1,
  'The latch state allows smooth muscle to maintain prolonged contraction with minimal energy expenditure, important for sphincters and blood vessels.',
  'Starea de blocare permite mușchiului neted să mențină contracție prelungită cu cheltuieli minime de energie, importantă pentru sfincteri și vase de sânge.',
  'muscular',
  10
) ON CONFLICT (id) DO UPDATE SET
