  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc95',
  'med-admission-barrons',
  'hard',
  'The sliding filament mechanism requires that during contraction:',
  'Mecanismul alunecării filamentelor necesită ca în timpul contracției:',
  '["Filaments shorten","Z discs move closer together while filament lengths remain constant","A band shortens","I band lengthens","H zone enlarges"]'::jsonb,
  '["Filamentele se scurtează","Discurile Z se apropie în timp ce lungimile filamentelor rămân constante","Banda A se scurtează","Banda I se alungește","Zona H se mărește"]'::jsonb,
  1,
  'During contraction, Z discs are pulled closer as thin filaments slide past thick filaments; I band and H zone shorten, but A band stays constant.',
  'În timpul contracției, discurile Z sunt trase mai aproape pe măsură ce filamentele subțiri alunecă peste cele groase; banda I și zona H se scurtează, dar banda A rămâne constantă.',
  'muscular',
  10
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
