  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc96',
  'med-admission-barrons',
  'hard',
  'Dantrolene treats malignant hyperthermia by:',
  'Dantrolenul tratează hipertermia malignă prin:',
  '["Increasing calcium release","Blocking ryanodine receptors and reducing calcium release from SR","Increasing ATP production","Stimulating muscle contraction","Increasing body temperature"]'::jsonb,
  '["Creșterea eliberării de calciu","Blocarea receptorilor de rianodină și reducerea eliberării de calciu din RS","Creșterea producției de ATP","Stimularea contracției musculare","Creșterea temperaturii corporale"]'::jsonb,
  1,
  'Dantrolene blocks ryanodine receptors on the SR, reducing Ca²⁺ release and muscle contraction, which lowers heat production.',
  'Dantrolenul blochează receptorii de rianodină de pe RS, reducând eliberarea de Ca²⁺ și contracția musculară, ceea ce scade producția de căldură.',
  'muscular',
  10
) ON CONFLICT (id) DO UPDATE SET
