  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc97',
  'med-admission-barrons',
  'hard',
  'Compartment syndrome occurs when:',
  'Sindromul de compartiment apare când:',
  '["Muscles relax completely","Pressure within a muscle compartment rises, compromising blood flow","Nerves regenerate","Muscles grow too large","Tendons shorten"]'::jsonb,
  '["Mușchii se relaxează complet","Presiunea în interiorul unui compartiment muscular crește, compromițând fluxul sanguin","Nervii se regenerează","Mușchii cresc prea mari","Tendoanele se scurtează"]'::jsonb,
  1,
  'Compartment syndrome is increased pressure within a closed muscle compartment that impairs blood flow and can cause tissue damage.',
  'Sindromul de compartiment este presiune crescută în interiorul unui compartiment muscular închis care afectează fluxul sanguin și poate cauza deteriorare tisulară.',
  'muscular',
  10
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc98',
  'med-admission-barrons',
  'hard',
  'McArdle disease affects muscle function because:',
  'Boala McArdle afectează funcția musculară deoarece:',
  '["Excess glycogen storage","Lack of muscle glycogen phosphorylase, impairing glycogen breakdown","Excess calcium release","Autoimmune destruction","Viral infection"]'::jsonb,
  '["Stocare excesivă de glicogen","Lipsa fosforilazei glicogenului muscular, afectând descompunerea glicogenului","Eliberare excesivă de calciu","Distrugere autoimună","Infecție virală"]'::jsonb,
  1,
  'McArdle disease (glycogen storage disease type V) is a deficiency of muscle glycogen phosphorylase, preventing glycogen breakdown for energy.',
  'Boala McArdle (boala de stocare a glicogenului tip V) este o deficiență a fosforilazei glicogenului muscular, prevenind descompunerea glicogenului pentru energie.',
  'muscular',
  10
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
