  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc99',
  'med-admission-barrons',
  'hard',
  'Succinylcholine causes muscle paralysis by:',
  'Succinilcolina cauzează paralizie musculară prin:',
  '["Blocking ACh receptors","Acting as a depolarizing blocker that causes sustained depolarization","Inhibiting ACh release","Destroying muscle fibers","Blocking calcium channels"]'::jsonb,
  '["Blocarea receptorilor ACh","Acționând ca un blocant depolarizant care cauzează depolarizare susținută","Inhibarea eliberării de ACh","Distrugerea fibrelor musculare","Blocarea canalelor de calciu"]'::jsonb,
  1,
  'Succinylcholine is a depolarizing neuromuscular blocker that binds ACh receptors, causing initial fasciculations then paralysis due to persistent depolarization.',
  'Succinilcolina este un blocant neuromuscular depolarizant care se leagă de receptorii ACh, cauzând fasciculații inițiale apoi paralizie datorită depolarizării persistente.',
  'muscular',
  10
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
