  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'musc100',
  'med-admission-barrons',
  'hard',
  'Calsequestrin in muscle functions to:',
  'Calsecvestrina din mușchi funcționează pentru a:',
  '["Release calcium","Bind and store calcium inside the sarcoplasmic reticulum","Contract the muscle","Produce ATP","Form cross-bridges"]'::jsonb,
  '["Elibera calciu","Lega și stoca calciu în interiorul reticulului sarcoplasmic","Contracta mușchiul","Produce ATP","Forma punți transversale"]'::jsonb,
  1,
  'Calsequestrin is a calcium-binding protein in the SR that allows storage of large amounts of Ca²⁺ at lower free concentrations.',
  'Calsecvestrina este o proteină care leagă calciul în RS care permite stocarea unor cantități mari de Ca²⁺ la concentrații libere mai mici.',
