INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro1',
  'med-admission-barrons',
  'easy',
  'Which of the following correctly lists the two main anatomical divisions of the nervous system?',
  'Care dintre următoarele enumeră corect cele două mari diviziuni anatomice ale sistemului nervos?',
  '["Somatic nervous system and autonomic nervous system","Central nervous system and peripheral nervous system","Sympathetic nervous system and parasympathetic nervous system","Cranial nervous system and spinal nervous system","Motor nervous system and sensory nervous system"]'::jsonb,
  '["Sistemul nervos somatic și sistemul nervos autonom","Sistemul nervos central și sistemul nervos periferic","Sistemul nervos simpatic și sistemul nervos parasimpatic","Sistemul nervos cranian și sistemul nervos spinal","Sistemul nervos motor și sistemul nervos senzitiv"]'::jsonb,
  1,
  'Anatomically, the nervous system is divided into the central nervous system (brain and spinal cord) and the peripheral nervous system (all nervous tissue outside the CNS).',
  'Anatomic, sistemul nervos este împărțit în sistem nervos central (creier și măduvă spinării) și sistem nervos periferic (toate structurile nervoase din afara SNC).',
  'nervous',
