INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro5',
  'med-admission-barrons',
  'medium',
  'What is the main function of neuroglial (glial) cells?',
  'Care este funcția principală a celulelor gliale (nevroglie)?',
  '["Generating action potentials and conducting nerve impulses","Providing support, protection, and metabolic assistance to neurons","Forming neuromuscular junctions with skeletal muscle fibers","Transporting oxygen and nutrients in the bloodstream","Producing antibodies against pathogens"]'::jsonb,
  '["Generarea potențialelor de acțiune și conducerea impulsurilor nervoase","Oferirea de suport, protecție și ajutor metabolic neuronilor","Formarea joncțiunilor neuromusculare cu fibrele musculare scheletice","Transportul oxigenului și nutrienților în sânge","Producerea de anticorpi împotriva agenților patogeni"]'::jsonb,
  1,
  'Glial cells support, protect, insulate, and nourish neurons, and help maintain the appropriate environment for neuronal signaling.',
  'Celulele gliale susțin, protejează, izolează și hrănesc neuronii și contribuie la menținerea unui mediu adecvat pentru transmiterea impulsurilor nervoase.',
  'nervous',
  1
) ON CONFLICT (id) DO UPDATE SET
