INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro6',
  'med-admission-barrons',
  'medium',
  'Which statement correctly describes myelin and its function?',
  'Care afirmație descrie corect mielina și funcția sa?',
  '["Myelin is a fluid that fills the synaptic cleft and stores neurotransmitters","Myelin is a pigment that gives neurons their characteristic color","Myelin is a lipid-rich sheath that increases the speed of impulse conduction along axons","Myelin is a hormone secreted by neurons to regulate blood pressure","Myelin is a connective tissue layer that surrounds entire nerves only"]'::jsonb,
  '["Mielina este un lichid care umple fanta sinaptică și stochează neurotransmițători","Mielina este un pigment care conferă neuronilor culoarea caracteristică","Mielina este o teacă bogată în lipide care crește viteza de conducere a impulsului de-a lungul axonilor","Mielina este un hormon secretat de neuroni pentru reglarea tensiunii arteriale","Mielina este un strat de țesut conjunctiv care înconjoară doar nervii ca întreg"]'::jsonb,
  2,
  'Myelin is a lipid-rich insulating sheath around many axons that greatly increases the speed of action potential propagation.',
  'Mielina este o teacă izolatoare bogată în lipide care înconjoară mulți axoni și crește mult viteza de propagare a potențialelor de acțiune.',
  'nervous',
  1
) ON CONFLICT (id) DO UPDATE SET
