  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro7',
  'med-admission-barrons',
  'medium',
  'Which sequence best represents the basic components of a simple reflex arc?',
  'Care succesiune reprezintă cel mai bine componentele de bază ale unui arc reflex simplu?',
  '["Receptor → sensory neuron → integration center → motor neuron → effector","Effector → motor neuron → integration center → sensory neuron → receptor","Receptor → motor neuron → sensory neuron → integration center → effector","Integration center → receptor → effector → sensory neuron → motor neuron","Receptor → effector → sensory neuron → motor neuron → integration center"]'::jsonb,
  '["Receptor → neuron senzitiv → centru de integrare → neuron motor → efector","Efector → neuron motor → centru de integrare → neuron senzitiv → receptor","Receptor → neuron motor → neuron senzitiv → centru de integrare → efector","Centru de integrare → receptor → efector → neuron senzitiv → neuron motor","Receptor → efector → neuron senzitiv → neuron motor → centru de integrare"]'::jsonb,
  0,
  'A simple reflex arc includes a receptor, a sensory neuron, an integration center, a motor neuron, and an effector.',
  'Un arc reflex simplu include un receptor, un neuron senzitiv, un centru de integrare, un neuron motor și un efector.',
  'nervous',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro8',
  'med-admission-barrons',
  'hard',
  'Which option correctly pairs a nervous system division with one of its functions?',
  'Care variantă asociază corect o diviziune a sistemului nervos cu una dintre funcțiile sale?',
  '["Somatic nervous system – unconscious regulation of cardiac muscle and glands","Autonomic nervous system – voluntary control of skeletal muscle","Sympathetic division – \"fight or flight\" responses such as increased heart rate","Parasympathetic division – acute stress responses during danger","Central nervous system – carrying impulses from receptors to effectors in peripheral nerves"]'::jsonb,
  '["Sistemul nervos somatic – reglarea inconștientă a mușchiului cardiac și a glandelor","Sistemul nervos autonom – control voluntar al mușchiului scheletic","Diviziunea simpatică – reacții de tip „luptă sau fugi”, precum creșterea frecvenței cardiace","Diviziunea parasimpatică – reacții acute de stres în timpul pericolului","Sistemul nervos central – conducerea impulsurilor de la receptori la efectori prin nervi periferici"]'::jsonb,
  2,
  'The sympathetic division of the autonomic nervous system mediates "fight or flight" responses such as increased heart rate and blood pressure.',
  'Diviziunea simpatică a sistemului nervos autonom mediază reacțiile „luptă sau fugi”, cum ar fi creșterea frecvenței cardiace și a tensiunii arteriale.',
  'nervous',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro9',
  'med-admission-barrons',
  'hard',
  'Which statement best describes a chemical synapse?',
  'Care afirmație descrie cel mai bine o sinapsă chimică?',
  '["It is a direct electrical connection between neurons without any gap","Neurotransmitters are released from the postsynaptic membrane into the synaptic cleft","Neurotransmitters are released from the presynaptic terminal into the synaptic cleft and bind to receptors on the postsynaptic cell","Myelin sheaths cover the synaptic cleft to speed up transmission","Synaptic transmission occurs only in the peripheral nervous system"]'::jsonb,
  '["Este o conexiune electrică directă între neuroni, fără niciun spațiu","Neurotransmițătorii sunt eliberați de pe membrana postsinaptică în fanta sinaptică","Neurotransmițătorii sunt eliberați din terminalul presinaptic în fanta sinaptică și se leagă de receptori de pe celula postsinaptică","Teaca de mielină acoperă fanta sinaptică pentru a accelera transmiterea","Transmiterea sinaptică are loc doar în sistemul nervos periferic"]'::jsonb,
  2,
  'At a chemical synapse, neurotransmitters released from the presynaptic terminal cross the synaptic cleft and bind to receptors on the postsynaptic membrane.',
  'Într-o sinapsă chimică, neurotransmițătorii eliberați din terminalul presinaptic traversează fanta sinaptică și se leagă de receptori pe membrana postsinaptică.',
  'nervous',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro10',
  'med-admission-barrons',
  'hard',
  'Which change would most likely increase the speed of action potential conduction along an axon?',
  'Care modificare ar crește cel mai probabil viteza de conducere a potențialului de acțiune de-a lungul unui axon?',
  '["Decreasing axon diameter and removing myelin","Increasing axon diameter and myelination","Reducing the number of nodes of Ranvier on a myelinated axon to zero","Replacing myelin with connective tissue","Lowering the resting membrane potential toward zero"]'::jsonb,
  '["Scăderea diametrului axonului și îndepărtarea mielinei","Creșterea diametrului axonului și a gradului de mielinizare","Reducerea numărului de noduri Ranvier pe un axon mielinizat până la zero","Înlocuirea mielinei cu țesut conjunctiv","Scăderea potențialului de repaus al membranei spre zero"]'::jsonb,
  1,
  'Larger axon diameter and the presence of myelin both increase conduction velocity by reducing resistance and enabling saltatory conduction.',
  'Un diametru mai mare al axonului și prezența mielinei cresc viteza de conducere, reducând rezistența și permițând conducerea saltatorie.',
  'nervous',
  1
) ON CONFLICT (id) DO UPDATE SET
