INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro34',
  'med-admission-barrons',
  'medium',
  'During depolarization, the membrane potential becomes:',
  'În timpul depolarizării, potențialul membranei devine:',
  '["More negative","Less negative (more positive)","Unchanged","Zero only","Equal to the potassium equilibrium potential"]'::jsonb,
  '["Mai negativ","Mai puțin negativ (mai pozitiv)","Neschimbat","Doar zero","Egal cu potențialul de echilibru al potasiului"]'::jsonb,
  1,
  'Depolarization occurs when the membrane potential becomes less negative (moves toward positive values), often due to sodium influx.',
  'Depolarizarea are loc când potențialul membranei devine mai puțin negativ (se mișcă spre valori pozitive), adesea datorită influxului de sodiu.',
  'nervous',
  4
) ON CONFLICT (id) DO UPDATE SET
