INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro35',
  'med-admission-barrons',
  'medium',
  'Which ion channel opens during the rising phase of an action potential?',
  'Care canal ionic se deschide în faza ascendentă a unui potențial de acțiune?',
  '["Voltage-gated potassium channels","Voltage-gated sodium channels","Ligand-gated chloride channels","Mechanically-gated calcium channels","Leak potassium channels"]'::jsonb,
  '["Canale de potasiu dependente de voltaj","Canale de sodiu dependente de voltaj","Canale de clor dependente de ligand","Canale de calciu mecanosensibile","Canale de potasiu de scurgere"]'::jsonb,
  1,
  'Voltage-gated sodium channels open during depolarization, allowing Na+ influx and causing the rapid rise in membrane potential.',
  'Canalele de sodiu dependente de voltaj se deschid în timpul depolarizării, permițând influxul de Na+ și provocând creșterea rapidă a potențialului membranei.',
  'nervous',
  4
) ON CONFLICT (id) DO UPDATE SET
