INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro36',
  'med-admission-barrons',
  'medium',
  'What is the refractory period?',
  'Ce este perioada refractară?',
  '["The time when a neuron can generate an action potential more easily","The time when a neuron cannot generate another action potential or requires a stronger stimulus","The resting phase before any stimulus","The time required for neurotransmitter synthesis","The period of myelin formation"]'::jsonb,
  '["Timpul în care un neuron poate genera mai ușor un potențial de acțiune","Timpul în care un neuron nu poate genera alt potențial de acțiune sau necesită un stimul mai puternic","Faza de repaus înainte de orice stimul","Timpul necesar sintezei neurotransmițătorilor","Perioada de formare a mielinei"]'::jsonb,
  1,
  'The refractory period is when a neuron cannot fire another action potential (absolute) or requires a stronger stimulus (relative).',
  'Perioada refractară este când un neuron nu poate declanșa alt potențial de acțiune (absolută) sau necesită un stimul mai puternic (relativă).',
  'nervous',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro37',
  'med-admission-barrons',
  'medium',
  'What is saltatory conduction?',
  'Ce este conducerea saltatorie?',
  '["Continuous propagation of action potentials along unmyelinated axons","The jumping of action potentials from one node of Ranvier to the next in myelinated axons","The transmission of impulses across synapses","The movement of ions through gap junctions","The diffusion of neurotransmitters in the synaptic cleft"]'::jsonb,
  '["Propagarea continuă a potențialelor de acțiune de-a lungul axonilor nemielinizați","Saltul potențialelor de acțiune de la un nod Ranvier la următorul în axonii mielinizați","Transmiterea impulsurilor prin sinapse","Mișcarea ionilor prin joncțiuni gap","Difuzia neurotransmițătorilor în fanta sinaptică"]'::jsonb,
  1,
  'Saltatory conduction is the rapid propagation of action potentials by "jumping" between nodes of Ranvier in myelinated axons.',
  'Conducerea saltatorie este propagarea rapidă a potențialelor de acțiune prin „saltul" între nodurile Ranvier în axonii mielinizați.',
  'nervous',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

