INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro58',
  'med-admission-barrons',
  'hard',
  'The sodium-potassium pump helps maintain resting membrane potential by:',
  'Pompa sodiu-potasiu ajută la menținerea potențialului de repaus al membranei prin:',
  '["Moving 3 Na+ out and 2 K+ into the cell","Moving 2 Na+ out and 3 K+ into the cell","Moving equal amounts of Na+ and K+ in opposite directions","Moving only Na+ out of the cell","Moving only K+ into the cell"]'::jsonb,
  '["Mișcarea a 3 Na+ în afara și 2 K+ în interiorul celulei","Mișcarea a 2 Na+ în afară și 3 K+ în interiorul celulei","Mișcarea unor cantități egale de Na+ și K+ în direcții opuse","Mișcarea doar a Na+ în afara celulei","Mișcarea doar a K+ în interiorul celulei"]'::jsonb,
  0,
  'The Na+/K+-ATPase pumps 3 sodium ions out and 2 potassium ions into the cell, contributing to the negative resting potential.',
  'Na+/K+-ATPaza pompează 3 ioni de sodiu în afară și 2 ioni de potasiu în interiorul celulei, contribuind la potențialul negativ de repaus.',
