INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro97',
  'med-admission-barrons',
  'hard',
  'Damage to the dorsal columns of the spinal cord would result in loss of:',
  'Lezarea coloanelor dorsale ale măduvei spinării ar duce la pierderea:',
  '["Pain and temperature sensation","Fine touch, vibration, and proprioception","Motor function","Autonomic function","Reflexes only"]'::jsonb,
  '["Senzației de durere și temperatură","Atingerii fine, vibrației și propriocepției","Funcției motorii","Funcției autonome","Doar a reflexelor"]'::jsonb,
  1,
  'The dorsal columns carry fine touch, vibration, and proprioception; damage impairs these modalities on the ipsilateral side.',
  'Coloanele dorsale transportă atingerea fină, vibrația și propriocepția; lezarea afectează aceste modalități pe partea ipsilaterală.',
  'nervous',
  10
) ON CONFLICT (id) DO UPDATE SET
