INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro98',
  'med-admission-barrons',
  'hard',
  'Which neurotransmitter imbalance is the primary target of treatment for epilepsy?',
  'Ce dezechilibru de neurotransmițători este ținta principală a tratamentului pentru epilepsie?',
  '["Too much dopamine","Too little acetylcholine","Imbalance between excitation (glutamate) and inhibition (GABA)","Too much serotonin","Too little norepinephrine"]'::jsonb,
  '["Prea multă dopamină","Prea puțină acetilcolină","Dezechilibru între excitație (glutamat) și inhibiție (GABA)","Prea multă serotonină","Prea puțină norepinefrină"]'::jsonb,
  2,
  'Seizures result from excessive neuronal excitation; many antiepileptic drugs enhance GABA inhibition or reduce glutamate excitation.',
  'Crizele rezultă din excitația neuronală excesivă; multe antiepileptice intensifică inhibiția GABA sau reduc excitația glutamatului.',
  'nervous',
  10
) ON CONFLICT (id) DO UPDATE SET
