  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro99',
  'med-admission-barrons',
  'hard',
  'A lesion of the cerebellum would most likely cause:',
  'O leziune a cerebelului ar cauza cel mai probabil:',
  '["Paralysis","Loss of sensation","Ataxia (loss of coordination)","Memory loss","Visual impairment"]'::jsonb,
  '["Paralizie","Pierderea senzației","Ataxie (pierderea coordonării)","Pierderea memoriei","Afectarea vederii"]'::jsonb,
  2,
  'Cerebellar lesions cause ataxia (incoordination), dysmetria, intention tremor, and difficulties with balance and gait.',
  'Leziunile cerebeloase cauzează ataxie (incoordonare), dismetrie, tremor intențional și dificultăți de echilibru și mers.',
  'nervous',
  10
) ON CONFLICT (id) DO UPDATE SET
