INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'neuro100',
  'med-admission-barrons',
  'hard',
  'Which condition involves progressive degeneration of both upper and lower motor neurons?',
  'Ce afecțiune implică degenerarea progresivă atât a neuronilor motori superiori cât și inferiori?',
  '["Parkinson''s disease","Multiple sclerosis","Amyotrophic lateral sclerosis (ALS)","Huntington''s disease","Myasthenia gravis"]'::jsonb,
  '["Boala Parkinson","Scleroza multiplă","Scleroza laterală amiotrofică (SLA)","Boala Huntington","Miastenia gravis"]'::jsonb,
  2,
  'ALS (Lou Gehrig''s disease) is characterized by progressive degeneration of both upper and lower motor neurons, causing weakness and paralysis.',
  'SLA (boala Lou Gehrig) se caracterizează prin degenerarea progresivă atât a neuronilor motori superiori cât și inferiori, cauzând slăbiciune și paralizie.',
  'nervous',
  10
