INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens1',
  'med-admission-barrons',
  'easy',
  'Which structure of the eye focuses light onto the retina?',
  'Care structură a ochiului focalizează lumina pe retină?',
  '["Retina","Lens","Optic nerve","Sclera","Choroid"]'::jsonb,
  '["Retina","Cristalinul","Nervul optic","Sclera","Coroida"]'::jsonb,
  1,
  'The lens (with the cornea) refracts light and focuses it on the retina; the lens changes shape for accommodation (near and far vision).',
  'Cristalinul (împreună cu cornea) refractă lumina și o focalizează pe retină; cristalinul își schimbă forma pentru acomodare (vedere apropiată și îndepărtată).',
  'senses',
  1
) ON CONFLICT (id) DO UPDATE SET
