  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens2',
  'med-admission-barrons',
  'easy',
  'Which part of the ear contains the receptors for hearing (hair cells)?',
  'Care parte a urechii conține receptorii pentru auz (celulele ciliate)?',
  '["External ear","Tympanic membrane","Cochlea","Eustachian tube","Pinna"]'::jsonb,
  '["Urechea externă","Membrana timpanică","Cochlea","Tuba auditivă","Pinna"]'::jsonb,
  2,
  'The cochlea is the spiral organ of the inner ear; it contains the organ of Corti with hair cells that transduce sound vibrations into nerve impulses.',
  'Cochlea este organul spiral al urechii interne; conține organul lui Corti cu celule ciliate care transformă vibrațiile sonore în impulsuri nervoase.',
  'senses',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens3',
  'med-admission-barrons',
  'easy',
  'Which type of receptor responds to chemicals (e.g., taste and smell)?',
  'Care tip de receptor răspunde la substanțe chimice (ex. gust și miros)?',
  '["Mechanoreceptor","Photoreceptor","Chemoreceptor","Thermoreceptor","Nociceptor"]'::jsonb,
  '["Mecanoreceptor","Fotoreceptor","Chemoreceptor","Termoreceptor","Nociceptor"]'::jsonb,
  2,
  'Chemoreceptors respond to chemical stimuli; they are involved in taste (gustation), smell (olfaction), and detection of blood gases.',
  'Chemoreceptorii răspund la stimuli chimici; sunt implicați în gust, miros și detectarea gazelor din sânge.',
  'senses',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
