  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens4',
  'med-admission-barrons',
  'medium',
  'Which layer of the eye contains the photoreceptors (rods and cones)?',
  'Care strat al ochiului conține fotoreceptorii (bastonașe și conuri)?',
  '["Sclera","Choroid","Retina","Cornea","Iris"]'::jsonb,
  '["Sclera","Coroida","Retina","Cornee","Iris"]'::jsonb,
  2,
  'The retina is the innermost layer and contains rods (dim light, peripheral vision) and cones (color, sharp vision).',
  'Retina este stratul cel mai interior și conține bastonașe (lumină slabă, vedere periferică) și conuri (culoare, acuitate).',
  'senses',
  1
) ON CONFLICT (id) DO UPDATE SET
