INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens5',
  'med-admission-barrons',
  'medium',
  'Which structure of the ear equalizes pressure between the middle ear and the atmosphere?',
  'Care structură a urechii echilibrează presiunea între urechea mijlocie și atmosferă?',
  '["Cochlea","Ossicles","Eustachian (auditory) tube","Semicircular canals","Tympanic membrane"]'::jsonb,
  '["Cochlea","Osoanele","Tuba auditivă (Eustachio)","Canalele semicirculare","Membrana timpanică"]'::jsonb,
  2,
  'The Eustachian tube connects the middle ear to the nasopharynx and allows pressure equalization, preventing damage to the eardrum.',
  'Tuba auditivă leagă urechea mijlocie de nazofaringe și permite egalizarea presiunii, prevenind lezarea timpanului.',
  'senses',
  1
) ON CONFLICT (id) DO UPDATE SET
