  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens6',
  'med-admission-barrons',
  'medium',
  'Which sense organ is primarily responsible for detecting balance and rotational movement?',
  'Care organ de simț este în principal responsabil de detectarea echilibrului și a mișcării de rotație?',
  '["Cochlea","Vestibular apparatus (semicircular canals and otolith organs)","Retina","Olfactory epithelium","Taste buds"]'::jsonb,
  '["Cochlea","Aparatul vestibular (canale semicirculare și organe otolitice)","Retina","Epitelul olfactiv","Papilele gustative"]'::jsonb,
  1,
  'The vestibular system (semicircular canals, utricle, saccule) detects head position, linear acceleration, and rotational movement for balance.',
  'Sistemul vestibular (canale semicirculare, utricul, sacul) detectează poziția capului, accelerația liniară și mișcarea de rotație pentru echilibru.',
  'senses',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
