  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens7',
  'med-admission-barrons',
  'medium',
  'Which taste quality is typically detected by receptors that may respond to hydrogen ions (acidity)?',
  'Care calitate gustativă este detectată de obicei de receptori care pot răspunde la ioni de hidrogen (aciditate)?',
  '["Sweet","Sour","Bitter","Umami","Salty only (no acid)"]'::jsonb,
  '["Dulce","Acru","Amar","Umami","Doar sărat (fără acid)"]'::jsonb,
  1,
  'Sour taste is largely associated with acids (H⁺); sweet, bitter, and umami often involve G-protein-coupled receptors.',
  'Gustul acru este asociat în mare parte cu acizii (H⁺); dulce, amar și umami implică adesea receptori cuplați la proteina G.',
  'senses',
  1
) ON CONFLICT (id) DO UPDATE SET
