  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens8',
  'med-admission-barrons',
  'hard',
  'Which part of the retina has the highest concentration of cones and the sharpest vision?',
  'Care parte a retinei are cea mai mare concentrație de conuri și cea mai clară vedere?',
  '["Peripheral retina","Optic disc (blind spot)","Fovea centralis","Choroid","Ciliary body"]'::jsonb,
  '["Retina periferică","Discul optic (punct orb)","Fovea centrală","Coroida","Corpul ciliar"]'::jsonb,
  2,
  'The fovea centralis is a small depression in the center of the retina with a high density of cones and no rods; it provides the sharpest color vision.',
  'Fovea centrală este o mică depresiune în centrul retinei cu densitate mare de conuri și fără bastonașe; oferă cea mai clară vedere în culori.',
  'senses',
  1
) ON CONFLICT (id) DO UPDATE SET
