INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens9',
  'med-admission-barrons',
  'hard',
  'Which structure controls the amount of light entering the eye by changing the size of the pupil?',
  'Care structură controlează cantitatea de lumină care intră în ochi modificând mărimea pupilei?',
  '["Lens","Retina","Iris","Cornea","Sclera"]'::jsonb,
  '["Cristalinul","Retina","Irisul","Cornee","Sclera"]'::jsonb,
  2,
  'The iris is the colored ring of muscle that adjusts the diameter of the pupil; it constricts in bright light and dilates in dim light.',
  'Irisul este inelul colorat de mușchi care ajustează diametrul pupilei; se contractă în lumină puternică și se dilată în lumină slabă.',
  'senses',
  1
) ON CONFLICT (id) DO UPDATE SET
