INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens10',
  'med-admission-barrons',
  'hard',
  'Where are the olfactory receptors located?',
  'Unde sunt localizați receptorii olfactivi?',
  '["On the tongue","In the retina","In the olfactory epithelium in the roof of the nasal cavity","In the cochlea","In the skin"]'::jsonb,
  '["Pe limbă","În retină","În epiteliul olfactiv din bolta cavității nazale","În cochlee","În piele"]'::jsonb,
  2,
  'Olfactory receptor neurons are in the olfactory epithelium in the superior part of the nasal cavity; their axons form the olfactory nerve.',
  'Neuronii receptori olfactivi sunt în epiteliul olfactiv din partea superioară a cavității nazale; axoni lor formează nervul olfactiv.',
  'senses',
  1
) ON CONFLICT (id) DO UPDATE SET
