INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens13',
  'med-admission-barrons',
  'easy',
  'What are the three tiny bones in the middle ear called?',
  'Cum se numesc cele trei oase mici din urechea medie?',
  '["Semicircular canals","Ossicles (malleus, incus, stapes)","Cochlear bones","Labyrinthine bones","Vestibular bones"]'::jsonb,
  '["Canalele semicirculare","Osicularele (ciocan, nicovală, scăriță)","Oasele cohleare","Oasele labirintice","Oasele vestibulare"]'::jsonb,
  1,
  'The ossicles (malleus, incus, stapes) transmit and amplify sound vibrations from the tympanic membrane to the oval window.',
  'Osicularele (ciocan, nicovală, scăriță) transmit și amplifică vibrațiile sonore de la membrana timpanică la fereastra ovală.',
