INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens14',
  'med-admission-barrons',
  'easy',
  'Which type of photoreceptor is responsible for color vision?',
  'Care tip de fotoreceptor este responsabil pentru vederea în culori?',
  '["Rods","Cones","Bipolar cells","Ganglion cells","Horizontal cells"]'::jsonb,
  '["Bastonașele","Conurile","Celulele bipolare","Celulele ganglionare","Celulele orizontale"]'::jsonb,
  1,
  'Cones are photoreceptors that function in bright light and are responsible for color vision (red, green, blue types).',
  'Conurile sunt fotoreceptori care funcționează în lumină puternică și sunt responsabile de vederea în culori (tipuri roșu, verde, albastru).',
