INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens31',
  'med-admission-barrons',
  'medium',
  'What causes the condition known as "color blindness"?',
  'Ce cauzează afecțiunea cunoscută drept „daltonism"?',
  '["Damage to rods","Absence or defect of one or more types of cone pigments","Damage to the optic nerve","Clouding of the lens","Detachment of the retina"]'::jsonb,
  '["Deteriorarea bastonașelor","Absența sau defectul unuia sau mai multor tipuri de pigmenți ai conurilor","Lezarea nervului optic","Opacifierea cristalinului","Dezlipirea retinei"]'::jsonb,
  1,
  'Color blindness results from the absence or dysfunction of one or more cone types (red, green, or blue).',
  'Daltonismul rezultă din absența sau disfuncția unuia sau mai multor tipuri de conuri (roșu, verde sau albastru).',
