INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens32',
  'med-admission-barrons',
  'medium',
  'What is myopia (nearsightedness)?',
  'Ce este miopia?',
  '["Difficulty seeing near objects","Difficulty seeing distant objects (image focuses in front of retina)","Clouding of the lens","Increased intraocular pressure","Loss of accommodation with age"]'::jsonb,
  '["Dificultate în vederea obiectelor apropiate","Dificultate în vederea obiectelor la distanță (imaginea se focalizează în fața retinei)","Opacifierea cristalinului","Creșterea presiunii intraoculare","Pierderea acomodării odată cu vârsta"]'::jsonb,
  1,
  'In myopia, the eyeball is too long or the cornea/lens is too curved, so light focuses in front of the retina; corrected with concave lenses.',
  'În miopie, globul ocular este prea lung sau cornea/cristalinul este prea curbat, astfel încât lumina se focalizează în fața retinei; se corectează cu lentile concave.',
  'senses',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
