  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens33',
  'med-admission-barrons',
  'medium',
  'What is hyperopia (farsightedness)?',
  'Ce este hipermetropia?',
  '["Difficulty seeing distant objects","Difficulty seeing near objects (image focuses behind retina)","Uneven curvature of the cornea","Clouding of the lens","Progressive loss of peripheral vision"]'::jsonb,
  '["Dificultate în vederea obiectelor la distanță","Dificultate în vederea obiectelor apropiate (imaginea se focalizează în spatele retinei)","Curbură neuniformă a corneei","Opacifierea cristalinului","Pierderea progresivă a vederii periferice"]'::jsonb,
  1,
  'In hyperopia, the eyeball is too short, so light focuses behind the retina; corrected with convex lenses.',
  'În hipermetropie, globul ocular este prea scurt, astfel încât lumina se focalizează în spatele retinei; se corectează cu lentile convexe.',
  'senses',
  4
) ON CONFLICT (id) DO UPDATE SET
