  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens34',
  'med-admission-barrons',
  'medium',
  'What is presbyopia?',
  'Ce este presbiopia?',
  '["Nearsightedness from birth","Loss of lens elasticity with age, affecting near vision","Increased intraocular pressure","Clouding of the cornea","Detachment of the retina"]'::jsonb,
  '["Miopie din naștere","Pierderea elasticității cristalinului odată cu vârsta, afectând vederea de aproape","Creșterea presiunii intraoculare","Opacifierea corneei","Dezlipirea retinei"]'::jsonb,
  1,
  'Presbyopia is age-related loss of accommodation due to decreased lens elasticity, making it difficult to focus on near objects.',
  'Presbiopia este pierderea acomodării legată de vârstă din cauza scăderii elasticității cristalinului, făcând dificilă focalizarea pe obiecte apropiate.',
  'senses',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens35',
  'med-admission-barrons',
  'medium',
  'What is a cataract?',
  'Ce este cataracta?',
  '["Increased pressure in the eye","Clouding of the lens","Detachment of the retina","Infection of the conjunctiva","Damage to the optic nerve"]'::jsonb,
  '["Creșterea presiunii în ochi","Opacifierea cristalinului","Dezlipirea retinei","Infecție a conjunctivei","Lezarea nervului optic"]'::jsonb,
  1,
  'A cataract is a clouding of the lens that obstructs light passage, causing blurry vision; treated surgically by lens replacement.',
  'Cataracta este opacifierea cristalinului care obstrucționează trecerea luminii, cauzând vedere încețoșată; tratată chirurgical prin înlocuirea cristalinului.',
  'senses',
  4
) ON CONFLICT (id) DO UPDATE SET
