INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens38',
  'med-admission-barrons',
  'medium',
  'Which structure acts as the primary sound receptor?',
  'Care structură acționează ca receptor sonor primar?',
  '["Tympanic membrane","Ossicles","Organ of Corti","Semicircular canals","Eustachian tube"]'::jsonb,
  '["Membrana timpanică","Osicularele","Organul Corti","Canalele semicirculare","Tuba lui Eustachio"]'::jsonb,
  2,
  'The organ of Corti in the cochlea contains hair cells that are the actual receptors for sound transduction.',
  'Organul Corti din cohlee conține celule ciliate care sunt receptorii reali pentru transducția sunetului.',
  'senses',
  4
) ON CONFLICT (id) DO UPDATE SET
