INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens39',
  'med-admission-barrons',
  'medium',
  'What is the function of the utricle and saccule?',
  'Care este funcția utriculului și saculului?',
  '["Detecting sound vibrations","Detecting linear acceleration and head position (gravity)","Equalizing pressure in the ear","Amplifying sound","Protecting the eardrum"]'::jsonb,
  '["Detectarea vibrațiilor sonore","Detectarea accelerației liniare și a poziției capului (gravitație)","Echilibrarea presiunii în ureche","Amplificarea sunetului","Protejarea timpanului"]'::jsonb,
  1,
  'The utricle and saccule contain otoliths and hair cells that detect linear acceleration and static head position relative to gravity.',
  'Utriculul și saculul conțin otoliți și celule ciliate care detectează accelerația liniară și poziția statică a capului relativ la gravitație.',
  'senses',
