INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens41',
  'med-admission-barrons',
  'medium',
  'Where does visual information cross to the opposite side of the brain?',
  'Unde se încrucișează informația vizuală către partea opusă a creierului?',
  '["Lateral geniculate nucleus","Optic chiasm","Superior colliculus","Primary visual cortex","Retina"]'::jsonb,
  '["Nucleul geniculat lateral","Chiasma optică","Coliculul superior","Cortexul vizual primar","Retina"]'::jsonb,
  1,
  'At the optic chiasm, fibers from the nasal retina cross to the opposite side; temporal fibers remain ipsilateral.',
  'La chiasma optică, fibrele din retina nazală se încrucișează spre partea opusă; fibrele temporale rămân ipsilaterale.',
