INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens42',
  'med-admission-barrons',
  'medium',
  'Which part of the retina lacks photoreceptors and creates a blind spot?',
  'Care parte a retinei nu are fotoreceptori și creează un punct orb?',
  '["Fovea","Macula","Optic disc","Peripheral retina","Ciliary body"]'::jsonb,
  '["Foveea","Macula","Discul optic","Retina periferică","Corpul ciliar"]'::jsonb,
  2,
  'The optic disc is where the optic nerve exits the eye; it has no photoreceptors, creating a physiological blind spot.',
  'Discul optic este locul unde nervul optic iese din ochi; nu are fotoreceptori, creând un punct orb fiziologic.',
