INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens43',
  'med-admission-barrons',
  'medium',
  'Which cranial nerve carries taste sensation from the anterior two-thirds of the tongue?',
  'Care nerv cranian transportă senzația gustativă din două treimi anterioare ale limbii?',
  '["Trigeminal nerve (V)","Facial nerve (VII)","Glossopharyngeal nerve (IX)","Vagus nerve (X)","Hypoglossal nerve (XII)"]'::jsonb,
  '["Nervul trigemen (V)","Nervul facial (VII)","Nervul glosofaringian (IX)","Nervul vag (X)","Nervul hipoglos (XII)"]'::jsonb,
  1,
  'The facial nerve (VII) carries taste from the anterior two-thirds of the tongue via the chorda tympani.',
  'Nervul facial (VII) transportă gustul din cele două treimi anterioare ale limbii prin chorda timpanică.',
