INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens45',
  'med-admission-barrons',
  'medium',
  'Which type of receptor detects pain?',
  'Ce tip de receptor detectează durerea?',
  '["Mechanoreceptor","Thermoreceptor","Photoreceptor","Nociceptor","Proprioceptor"]'::jsonb,
  '["Mecanoreceptor","Termoreceptor","Fotoreceptor","Nociceptor","Proprioceptor"]'::jsonb,
  3,
  'Nociceptors are free nerve endings that detect potentially harmful stimuli and generate pain sensations.',
  'Nociceptorii sunt terminații nervoase libere care detectează stimuli potențial dăunători și generează senzații de durere.',
  'senses',
  5
) ON CONFLICT (id) DO UPDATE SET
