  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens46',
  'med-admission-barrons',
  'medium',
  'What is referred pain?',
  'Ce este durerea referită?',
  '["Pain that moves from one location to another","Pain felt at a location different from the actual source","Pain that is imagined by the patient","Pain that occurs only at night","Pain caused by muscle tension"]'::jsonb,
  '["Durerea care se deplasează dintr-un loc în altul","Durerea resimțită într-un loc diferit de sursa reală","Durerea imaginată de pacient","Durerea care apare doar noaptea","Durerea cauzată de tensiunea musculară"]'::jsonb,
  1,
  'Referred pain occurs when pain from visceral organs is perceived as coming from a somatic location due to convergence of sensory pathways.',
  'Durerea referită apare când durerea din organele viscerale este percepută ca venind dintr-o locație somatică din cauza convergenței căilor senzoriale.',
  'senses',
  5
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens47',
  'med-admission-barrons',
  'medium',
  'Which receptors detect body position and movement in muscles, tendons, and joints?',
  'Care receptori detectează poziția și mișcarea corpului în mușchi, tendoane și articulații?',
  '["Thermoreceptors","Nociceptors","Proprioceptors","Photoreceptors","Chemoreceptors"]'::jsonb,
  '["Termoreceptorii","Nociceptorii","Proprioceptorii","Fotoreceptorii","Chemoreceptorii"]'::jsonb,
  2,
  'Proprioceptors (muscle spindles, Golgi tendon organs, joint receptors) detect body position, movement, and muscle tension.',
  'Proprioceptorii (fusuri musculare, organe tendinoase Golgi, receptori articulari) detectează poziția corpului, mișcarea și tensiunea musculară.',
  'senses',
  5
) ON CONFLICT (id) DO UPDATE SET
