  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens48',
  'med-admission-barrons',
  'medium',
  'Which sensory receptor adapts slowly and continues to signal as long as the stimulus persists?',
  'Care receptor senzorial se adaptează lent și continuă să semnalizeze atât timp cât stimulul persistă?',
  '["Rapidly adapting receptor","Tonic (slowly adapting) receptor","Phasic receptor","Photoreceptor","Thermoreceptor only"]'::jsonb,
  '["Receptor cu adaptare rapidă","Receptor tonic (cu adaptare lentă)","Receptor fazic","Fotoreceptor","Doar termoreceptor"]'::jsonb,
  1,
  'Tonic (slowly adapting) receptors continue to generate action potentials throughout a sustained stimulus, important for position sense.',
  'Receptorii tonici (cu adaptare lentă) continuă să genereze potențiale de acțiune pe tot parcursul unui stimul susținut, importanți pentru simțul poziției.',
  'senses',
  5
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
