INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens49',
  'med-admission-barrons',
  'medium',
  'Which sense involves detection of airborne chemical molecules?',
  'Care simț implică detectarea moleculelor chimice din aer?',
  '["Gustation","Olfaction","Vision","Audition","Proprioception"]'::jsonb,
  '["Gustația","Olfacția","Vederea","Audiția","Propriocepția"]'::jsonb,
  1,
  'Olfaction (smell) is the detection of airborne odorant molecules by receptors in the olfactory epithelium.',
  'Olfacția (mirosul) este detectarea moleculelor odorante din aer de către receptorii din epiteliul olfactiv.',
