INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens50',
  'med-admission-barrons',
  'medium',
  'Where does olfactory information first synapse in the brain?',
  'Unde se produce prima sinapsă a informației olfactive în creier?',
  '["Thalamus","Olfactory bulb","Primary motor cortex","Hippocampus","Cerebellum"]'::jsonb,
  '["Talamus","Bulbul olfactiv","Cortexul motor primar","Hipocampus","Cerebel"]'::jsonb,
  1,
  'Olfactory receptor neurons synapse in the olfactory bulb, which then sends information to olfactory cortex (bypassing thalamus initially).',
  'Neuronii receptori olfactivi fac sinapsă în bulbul olfactiv, care apoi trimite informații către cortexul olfactiv (ocolind inițial talamusul).',
