INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens51',
  'med-admission-barrons',
  'medium',
  'Which structure of the eye produces aqueous humor?',
  'Care structură a ochiului produce umoarea apoasă?',
  '["Cornea","Ciliary body","Iris","Lens","Retina"]'::jsonb,
  '["Corneea","Corpul ciliar","Irisul","Cristalinul","Retina"]'::jsonb,
  1,
  'The ciliary body produces aqueous humor and contains the ciliary muscle that controls lens shape for accommodation.',
  'Corpul ciliar produce umoarea apoasă și conține mușchiul ciliar care controlează forma cristalinului pentru acomodare.',
  'senses',
  6
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
