INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens52',
  'med-admission-barrons',
  'hard',
  'What is the mechanism of sound transduction in the cochlea?',
  'Care este mecanismul transducției sunetului în cohlee?',
  '["Direct electrical stimulation of hair cells","Mechanical bending of hair cell stereocilia causes ion channels to open","Chemical neurotransmitter release from the tympanic membrane","Light absorption by photopigments","Temperature-induced depolarization"]'::jsonb,
  '["Stimulare electrică directă a celulelor ciliate","Îndoirea mecanică a stereocililor celulelor ciliate cauzează deschiderea canalelor ionice","Eliberarea de neurotransmițători chimici din membrana timpanică","Absorbția luminii de către fotopigmenți","Depolarizare indusă de temperatură"]'::jsonb,
  1,
  'Sound vibrations cause basilar membrane movement, which bends hair cell stereocilia and opens mechanically-gated ion channels.',
  'Vibrațiile sonore cauzează mișcarea membranei bazilare, care îndoaie stereocilii celulelor ciliate și deschide canale ionice mecano-sensibile.',
  'senses',
  6
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens53',
  'med-admission-barrons',
  'hard',
  'Which area of the basilar membrane responds best to high-frequency sounds?',
  'Care zonă a membranei bazilare răspunde cel mai bine la sunetele de frecvență înaltă?',
  '["Apex (near helicotrema)","Base (near oval window)","Middle portion","All areas equally","Only the tectorial membrane"]'::jsonb,
  '["Apexul (aproape de helicotrema)","Baza (aproape de fereastra ovală)","Porțiunea de mijloc","Toate zonele în mod egal","Doar membrana tectorială"]'::jsonb,
  1,
  'High-frequency sounds cause maximum vibration at the base of the cochlea (narrow, stiff membrane); low frequencies at the apex (wide, flexible).',
  'Sunetele de frecvență înaltă cauzează vibrație maximă la baza cohleei (membrană îngustă, rigidă); frecvențele joase la apex (lată, flexibilă).',
  'senses',
  6
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens54',
  'med-admission-barrons',
  'hard',
  'What is the photopigment found in rod cells?',
  'Care este fotopigmentul găsit în celulele bastonaș?',
  '["Photopsin","Rhodopsin","Melanopsin","Hemoglobin","Myoglobin"]'::jsonb,
  '["Fotopsina","Rodopsina","Melanopsina","Hemoglobina","Mioglobina"]'::jsonb,
  1,
  'Rhodopsin (visual purple) is the photopigment in rods that absorbs light and initiates the visual transduction cascade.',
  'Rodopsina (purpura vizuală) este fotopigmentul din bastonașe care absoarbe lumina și inițiază cascada de transducție vizuală.',
  'senses',
  6
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens55',
  'med-admission-barrons',
  'hard',
  'When light strikes rhodopsin, what conformational change occurs?',
  'Când lumina lovește rodopsina, ce schimbare conformațională are loc?',
  '["Retinal changes from 11-cis to all-trans form","Opsin is degraded","Rhodopsin splits into its subunits permanently","The rod cell contracts","Calcium is released from mitochondria"]'::jsonb,
  '["Retinalul se schimbă din forma 11-cis în forma all-trans","Opsina este degradată","Rodopsina se desparte permanent în subunitățile sale","Celula bastonaș se contractă","Calciul este eliberat din mitocondrii"]'::jsonb,
  0,
  'Light causes retinal (vitamin A derivative) to isomerize from 11-cis to all-trans form, triggering conformational changes in opsin.',
  'Lumina face ca retinalul (derivat al vitaminei A) să se izomerizeze din forma 11-cis în forma all-trans, declanșând schimbări conformaționale în opsină.',
  'senses',
  6
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens56',
  'med-admission-barrons',
  'hard',
  'In the dark, photoreceptors are:',
  'În întuneric, fotoreceptorii sunt:',
  '["Hyperpolarized","Depolarized (constantly releasing neurotransmitter)","At zero membrane potential","Completely inactive","Generating action potentials continuously"]'::jsonb,
  '["Hiperpolarizați","Depolarizați (eliberând constant neurotransmițător)","La potențial de membrană zero","Complet inactivi","Generând potențiale de acțiune continuu"]'::jsonb,
  1,
  'In the dark, photoreceptors are depolarized due to open cGMP-gated channels; they constantly release glutamate. Light causes hyperpolarization.',
  'În întuneric, fotoreceptorii sunt depolarizați datorită canalelor deschise dependente de cGMP; eliberează constant glutamat. Lumina cauzează hiperpolarizare.',
  'senses',
  6
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens57',
  'med-admission-barrons',
  'hard',
  'What happens to photoreceptors when light is detected?',
  'Ce se întâmplă cu fotoreceptorii când lumina este detectată?',
  '["They depolarize","They hyperpolarize","They generate action potentials","They release more neurotransmitter","They contract"]'::jsonb,
  '["Se depolarizează","Se hiperpolarizează","Generează potențiale de acțiune","Eliberează mai mult neurotransmițător","Se contractă"]'::jsonb,
  1,
  'Light causes photoreceptors to hyperpolarize by closing cGMP-gated channels, reducing neurotransmitter (glutamate) release.',
  'Lumina face ca fotoreceptorii să se hiperpolarizeze prin închiderea canalelor dependente de cGMP, reducând eliberarea de neurotransmițător (glutamat).',
  'senses',
  6
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens58',
  'med-admission-barrons',
  'hard',
  'What is the primary visual cortex also known as?',
  'Cum se mai numește cortexul vizual primar?',
  '["Broca''s area","V1 or striate cortex","Wernicke''s area","Auditory cortex","Motor cortex"]'::jsonb,
  '["Aria Broca","V1 sau cortexul striat","Aria Wernicke","Cortexul auditiv","Cortexul motor"]'::jsonb,
  1,
  'The primary visual cortex (V1), located in the occipital lobe, is also called the striate cortex due to its striped appearance.',
  'Cortexul vizual primar (V1), situat în lobul occipital, se mai numește și cortex striat datorită aspectului său striat.',
  'senses',
  6
) ON CONFLICT (id) DO UPDATE SET
