INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens63',
  'med-admission-barrons',
  'hard',
  'What causes conductive hearing loss?',
  'Ce cauzează pierderea auditivă de conducere?',
  '["Damage to the cochlea or auditory nerve","Problems in the outer or middle ear that prevent sound transmission","Damage to the auditory cortex","Rupture of the round window","Excessive endolymph production"]'::jsonb,
  '["Lezarea cohleei sau a nervului auditiv","Probleme în urechea externă sau medie care împiedică transmiterea sunetului","Lezarea cortexului auditiv","Ruptura ferestrei rotunde","Producție excesivă de endolimfă"]'::jsonb,
  1,
  'Conductive hearing loss results from obstruction or damage in the outer or middle ear (e.g., earwax, otitis media, ossicle damage).',
  'Pierderea auditivă de conducere rezultă din obstrucția sau lezarea urechii externe sau medii (ex. cerumen, otită medie, leziuni ale osicularelor).',
  'senses',
  7
