INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens71',
  'med-admission-barrons',
  'hard',
  'What is retinitis pigmentosa?',
  'Ce este retinita pigmentară?',
  '["A bacterial infection of the retina","A genetic disorder causing progressive degeneration of photoreceptors","Inflammation due to autoimmune disease","Macular degeneration only","A tumor of the retina"]'::jsonb,
  '["O infecție bacteriană a retinei","O afecțiune genetică care cauzează degenerarea progresivă a fotoreceptorilor","Inflamație datorată unei boli autoimune","Doar degenerescență maculară","O tumoare a retinei"]'::jsonb,
  1,
  'Retinitis pigmentosa is a group of genetic disorders causing progressive rod photoreceptor degeneration, leading to night blindness and tunnel vision.',
  'Retinita pigmentară este un grup de afecțiuni genetice care cauzează degenerarea progresivă a fotoreceptorilor bastonaș, ducând la cecitate nocturnă și vedere în tunel.',
  'senses',
  8
) ON CONFLICT (id) DO UPDATE SET
