INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens72',
  'med-admission-barrons',
  'hard',
  'What causes night blindness (nyctalopia)?',
  'Ce cauzează cecitatea nocturnă (nictalopia)?',
  '["Excessive cone activity","Impaired rod function or vitamin A deficiency","Damage to the optic nerve","Clouding of the cornea","Macular degeneration"]'::jsonb,
  '["Activitate excesivă a conurilor","Funcție afectată a bastonașelor sau deficit de vitamina A","Lezarea nervului optic","Opacifierea corneei","Degenerescență maculară"]'::jsonb,
  1,
  'Night blindness results from rod dysfunction or vitamin A deficiency (needed for rhodopsin synthesis), impairing dim-light vision.',
  'Cecitatea nocturnă rezultă din disfuncția bastonașelor sau deficitul de vitamina A (necesară pentru sinteza rodopsinei), afectând vederea în lumină slabă.',
  'senses',
  8
) ON CONFLICT (id) DO UPDATE SET
