INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens73',
  'med-admission-barrons',
  'hard',
  'Which structure amplifies sound waves between the tympanic membrane and the oval window?',
  'Care structură amplifică undele sonore între membrana timpanică și fereastra ovală?',
  '["Cochlea","Ossicles","Semicircular canals","Eustachian tube","External auditory canal"]'::jsonb,
  '["Cohleea","Osicularele","Canalele semicirculare","Tuba lui Eustachio","Conductul auditiv extern"]'::jsonb,
  1,
  'The ossicles (malleus, incus, stapes) amplify sound pressure about 20x through lever action and area difference (large eardrum to small oval window).',
  'Osicularele (ciocan, nicovală, scăriță) amplifică presiunea sonoră de aproximativ 20x prin acțiune de pârghie și diferență de suprafață (timpan mare la fereastra ovală mică).',
  'senses',
  8
) ON CONFLICT (id) DO UPDATE SET
