INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens74',
  'med-admission-barrons',
  'hard',
  'What is the acoustic reflex?',
  'Ce este reflexul acustic?',
  '["Automatic focusing of the lens in response to sound","Contraction of the stapedius and tensor tympani muscles to protect against loud sounds","Dilation of the pupil in response to sound","Increased endolymph production","Rotation of the eyes toward a sound source"]'::jsonb,
  '["Focalizarea automată a cristalinului ca răspuns la sunet","Contracția mușchilor stapediu și tensor timpanic pentru a proteja împotriva sunetelor puternice","Dilatarea pupilei ca răspuns la sunet","Producție crescută de endolimfă","Rotirea ochilor spre o sursă de sunet"]'::jsonb,
  1,
  'The acoustic reflex involves contraction of middle ear muscles in response to loud sounds to attenuate sound transmission and protect the cochlea.',
  'Reflexul acustic implică contracția mușchilor urechii medii ca răspuns la sunetele puternice pentru a atenua transmisia sunetului și a proteja cohleea.',
  'senses',
  8
) ON CONFLICT (id) DO UPDATE SET
