INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens76',
  'med-admission-barrons',
  'hard',
  'What causes motion sickness?',
  'Ce cauzează răul de mișcare?',
  '["Excessive stimulation of photoreceptors","Conflicting information from visual, vestibular, and proprioceptive systems","Damage to the cochlea","High blood pressure","Dehydration"]'::jsonb,
  '["Stimularea excesivă a fotoreceptorilor","Informații conflictuale de la sistemele vizual, vestibular și proprioceptiv","Lezarea cohleei","Tensiune arterială crescută","Deshidratare"]'::jsonb,
  1,
  'Motion sickness results from sensory conflict when visual, vestibular, and proprioceptive inputs about motion are inconsistent.',
  'Răul de mișcare rezultă din conflictul senzorial când informațiile vizuale, vestibulare și proprioceptive despre mișcare sunt inconsistente.',
  'senses',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
