INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens77',
  'med-admission-barrons',
  'hard',
  'Which visual pathway is responsible for object recognition ("what" pathway)?',
  'Care cale vizuală este responsabilă pentru recunoașterea obiectelor (calea „ce")?',
  '["Dorsal stream","Ventral stream","Optic radiation","Superior colliculus pathway","Retinohypothalamic tract"]'::jsonb,
  '["Calea dorsală","Calea ventrală","Radiația optică","Calea coliculului superior","Tractul retinohipotalamic"]'::jsonb,
  1,
  'The ventral stream (occipital to temporal lobe) processes object identity ("what" pathway), while the dorsal stream processes spatial location ("where").',
  'Calea ventrală (occipital spre lobul temporal) procesează identitatea obiectului (calea „ce"), în timp ce calea dorsală procesează localizarea spațială („unde").',
  'senses',
  8
) ON CONFLICT (id) DO UPDATE SET
