  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens78',
  'med-admission-barrons',
  'hard',
  'Which visual pathway is responsible for spatial awareness and guiding action ("where" pathway)?',
  'Care cale vizuală este responsabilă pentru conștientizarea spațială și ghidarea acțiunii (calea „unde")?',
  '["Ventral stream","Dorsal stream","Lateral geniculate pathway","Retinal pathway","Olfactory pathway"]'::jsonb,
  '["Calea ventrală","Calea dorsală","Calea geniculată laterală","Calea retinală","Calea olfactivă"]'::jsonb,
  1,
  'The dorsal stream (occipital to parietal lobe) processes spatial information and guides movements ("where/how" pathway).',
  'Calea dorsală (occipital spre lobul parietal) procesează informații spațiale și ghidează mișcările (calea „unde/cum").',
  'senses',
  8
) ON CONFLICT (id) DO UPDATE SET
