INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens79',
  'med-admission-barrons',
  'hard',
  'What is anosmia?',
  'Ce este anosmia?',
  '["Loss of taste","Loss of smell","Loss of hearing","Loss of vision","Loss of touch sensation"]'::jsonb,
  '["Pierderea gustului","Pierderea mirosului","Pierderea auzului","Pierderea vederii","Pierderea senzației tactile"]'::jsonb,
  1,
  'Anosmia is the loss of the sense of smell, which can result from nasal obstruction, damage to olfactory neurons, or brain injury.',
  'Anosmia este pierderea simțului mirosului, care poate rezulta din obstrucție nazală, lezarea neuronilor olfactivi sau leziuni cerebrale.',
  'senses',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
