  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens80',
  'med-admission-barrons',
  'hard',
  'Why does loss of smell often affect taste perception?',
  'De ce pierderea mirosului afectează adesea percepția gustului?',
  '["Smell and taste share the same receptors","Olfaction contributes significantly to flavor perception","Taste buds degenerate without smell","The tongue loses blood supply","They use the same cranial nerve"]'::jsonb,
  '["Mirosul și gustul împart aceiași receptori","Olfacția contribuie semnificativ la percepția aromei","Papilele gustative degenerează fără miros","Limba pierde aportul sanguin","Folosesc același nerv cranian"]'::jsonb,
  1,
  'Flavor is a combination of taste and smell; olfaction (retronasal smell) enhances taste perception, so anosmia reduces perceived flavor.',
  'Aroma este o combinație de gust și miros; olfacția (mirosul retronasal) îmbunătățește percepția gustului, astfel încât anosmia reduce aroma percepută.',
  'senses',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

-- Set 9 (Hard)
INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens81',
  'med-admission-barrons',
  'hard',
  'What is the function of the pupillary light reflex?',
  'Care este funcția reflexului pupilar la lumină?',
  '["To change lens shape for focusing","To adjust pupil size in response to light intensity","To move the eyes toward a light source","To protect against UV radiation","To increase tear production"]'::jsonb,
  '["Să schimbe forma cristalinului pentru focalizare","Să ajusteze dimensiunea pupilei ca răspuns la intensitatea luminii","Să miște ochii spre o sursă de lumină","Să protejeze împotriva radiației UV","Să crească producția de lacrimi"]'::jsonb,
  1,
  'The pupillary light reflex constricts the pupil in bright light and dilates it in dim light to regulate retinal illumination.',
  'Reflexul pupilar la lumină contractă pupila în lumină puternică și o dilată în lumină slabă pentru a regla iluminarea retinei.',
  'senses',
  9
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
