  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens82',
  'med-admission-barrons',
  'hard',
  'Which nerve mediates the pupillary constriction response?',
  'Care nerv mediază răspunsul de constricție pupilară?',
  '["Optic nerve (afferent only)","Oculomotor nerve (parasympathetic efferent)","Trigeminal nerve","Facial nerve","Abducens nerve"]'::jsonb,
  '["Nervul optic (doar aferent)","Nervul oculomotor (eferent parasimpatic)","Nervul trigemen","Nervul facial","Nervul abducens"]'::jsonb,
  1,
  'The oculomotor nerve (CN III) carries parasympathetic fibers that cause pupillary constriction via the ciliary ganglion.',
  'Nervul oculomotor (NC III) transportă fibre parasimpatice care cauzează constricția pupilei prin ganglionul ciliar.',
  'senses',
  9
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
