  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens83',
  'med-admission-barrons',
  'hard',
  'What is the accommodation reflex?',
  'Ce este reflexul de acomodare?',
  '["Constriction of the pupil in response to light","Adjustment of lens shape, pupil constriction, and eye convergence for near vision","Dilation of the pupil in darkness","Movement of the eyes to track a moving object","Production of tears in response to irritation"]'::jsonb,
  '["Constricția pupilei ca răspuns la lumină","Ajustarea formei cristalinului, constricția pupilei și convergența ochilor pentru vederea de aproape","Dilatarea pupilei în întuneric","Mișcarea ochilor pentru a urmări un obiect în mișcare","Producerea lacrimilor ca răspuns la iritație"]'::jsonb,
  1,
  'The accommodation reflex involves lens thickening (ciliary muscle contraction), pupil constriction, and convergence of the eyes for near focus.',
  'Reflexul de acomodare implică îngroșarea cristalinului (contracția mușchiului ciliar), constricția pupilei și convergența ochilor pentru focalizare apropiată.',
  'senses',
  9
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
