  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens84',
  'med-admission-barrons',
  'hard',
  'What is the vestibulo-ocular reflex (VOR)?',
  'Ce este reflexul vestibulo-ocular (RVO)?',
  '["Eye movement toward a sound source","Eye movements that compensate for head movements to stabilize gaze","Pupil dilation in response to vestibular stimulation","Closure of the eyelids during rapid head movement","Increased tear production during rotation"]'::jsonb,
  '["Mișcarea ochilor spre o sursă de sunet","Mișcări oculare care compensează mișcările capului pentru a stabiliza privirea","Dilatarea pupilei ca răspuns la stimularea vestibulară","Închiderea pleoapelor în timpul mișcării rapide a capului","Producție crescută de lacrimi în timpul rotației"]'::jsonb,
  1,
  'The VOR produces eye movements opposite to head movement to maintain stable vision during head rotation.',
  'RVO produce mișcări oculare opuse mișcării capului pentru a menține o vedere stabilă în timpul rotației capului.',
  'senses',
  9
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens85',
