INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens87',
  'med-admission-barrons',
  'hard',
  'What is nystagmus?',
  'Ce este nistagmusul?',
  '["Involuntary, rhythmic eye movements","Paralysis of eye muscles","Double vision","Loss of color vision","Drooping of the eyelid"]'::jsonb,
  '["Mișcări oculare involuntare, ritmice","Paralizia mușchilor oculari","Vedere dublă","Pierderea vederii în culori","Căderea pleoapei"]'::jsonb,
  0,
  'Nystagmus is involuntary, repetitive, rhythmic eye movements that can be physiological (e.g., optokinetic) or pathological.',
  'Nistagmusul constă în mișcări oculare involuntare, repetitive, ritmice, care pot fi fiziologice (ex. optokinetice) sau patologice.',
