INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens88',
  'med-admission-barrons',
  'hard',
  'Which structure of the eye drains aqueous humor?',
  'Care structură a ochiului drenează umoarea apoasă?',
  '["Ciliary body","Canal of Schlemm (trabecular meshwork)","Lens","Vitreous body","Cornea"]'::jsonb,
  '["Corpul ciliar","Canalul lui Schlemm (rețeaua trabeculară)","Cristalinul","Corpul vitros","Corneea"]'::jsonb,
  1,
  'Aqueous humor drains through the trabecular meshwork into the canal of Schlemm at the iridocorneal angle; blockage can cause glaucoma.',
  'Umoarea apoasă se drenează prin rețeaua trabeculară în canalul lui Schlemm la unghiul iridocornean; blocarea poate cauza glaucom.',
