INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens89',
  'med-admission-barrons',
  'hard',
  'What is strabismus?',
  'Ce este strabismul?',
  '["Clouding of the lens","Misalignment of the eyes","Loss of peripheral vision","Inflammation of the conjunctiva","Retinal detachment"]'::jsonb,
  '["Opacifierea cristalinului","Nealinierea ochilor","Pierderea vederii periferice","Inflamația conjunctivei","Dezlipirea retinei"]'::jsonb,
  1,
  'Strabismus (squint) is misalignment of the eyes due to imbalance of extraocular muscles or neural control, causing eyes to point in different directions.',
  'Strabismul (șaște) este nealinierea ochilor din cauza dezechilibrului mușchilor extraoculari sau a controlului neural, făcând ochii să privească în direcții diferite.',
  'senses',
  9
) ON CONFLICT (id) DO UPDATE SET
