INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens90',
  'med-admission-barrons',
  'hard',
  'What is the tonotopic organization of the auditory cortex?',
  'Ce este organizarea tonotopică a cortexului auditiv?',
  '["Organization by intensity of sound","Organization by frequency, with different areas responding to different pitches","Organization by direction of sound","Random organization of sound processing","Organization by temporal pattern only"]'::jsonb,
  '["Organizare după intensitatea sunetului","Organizare după frecvență, cu zone diferite răspunzând la tonuri diferite","Organizare după direcția sunetului","Organizare aleatorie a procesării sunetului","Organizare doar după tipar temporal"]'::jsonb,
  1,
  'Tonotopic organization means different frequencies are processed in different locations along the auditory cortex, preserving the cochlear frequency map.',
  'Organizarea tonotopică înseamnă că diferite frecvențe sunt procesate în locații diferite de-a lungul cortexului auditiv, păstrând harta de frecvență a cohleei.',
  'senses',
  9
) ON CONFLICT (id) DO UPDATE SET
