INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens91',
  'med-admission-barrons',
  'hard',
  'A patient has lost vision in the left visual field of both eyes. Where is the likely lesion?',
  'Un pacient a pierdut vederea în câmpul vizual stâng al ambilor ochi. Unde este probabil leziunea?',
  '["Left optic nerve","Right optic tract or radiation","Optic chiasm","Left retina","Right optic nerve"]'::jsonb,
  '["Nervul optic stâng","Tractul sau radiația optică dreaptă","Chiasma optică","Retina stângă","Nervul optic drept"]'::jsonb,
  1,
  'Left homonymous hemianopia (loss of left visual field in both eyes) indicates damage to the right optic tract or visual cortex.',
  'Hemianopia omonimă stângă (pierderea câmpului vizual stâng în ambii ochi) indică lezarea tractului optic drept sau a cortexului vizual.',
