INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens92',
  'med-admission-barrons',
  'hard',
  'A tumor compressing the optic chiasm would most likely cause:',
  'O tumoare care comprimă chiasma optică ar cauza cel mai probabil:',
  '["Total blindness in one eye","Bitemporal hemianopia (loss of peripheral vision on both sides)","Loss of central vision only","Complete color blindness","Night blindness only"]'::jsonb,
  '["Orbire totală într-un ochi","Hemianopie bitemporală (pierderea vederii periferice de ambele părți)","Pierderea doar a vederii centrale","Daltonism complet","Doar cecitate nocturnă"]'::jsonb,
  1,
  'A chiasmal lesion (e.g., pituitary tumor) damages crossing fibers from nasal retinas, causing bitemporal hemianopia (tunnel vision).',
  'O leziune chiasmală (ex. tumoră hipofizară) lezează fibrele care se încrucișează din retinele nazale, cauzând hemianopie bitemporală (vedere în tunel).',
  'senses',
  10
) ON CONFLICT (id) DO UPDATE SET
