INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens93',
  'med-admission-barrons',
  'hard',
  'A patient with a lesion of the right optic nerve would experience:',
  'Un pacient cu o leziune a nervului optic drept ar experimenta:',
  '["Blindness in the left eye","Blindness in the right eye","Loss of peripheral vision bilaterally","Loss of central vision bilaterally","Color blindness only"]'::jsonb,
  '["Orbire în ochiul stâng","Orbire în ochiul drept","Pierderea vederii periferice bilateral","Pierderea vederii centrale bilateral","Doar daltonism"]'::jsonb,
  1,
  'Damage to one optic nerve causes complete vision loss in that eye only (monocular blindness in the right eye).',
  'Lezarea unui nerv optic cauzează pierderea completă a vederii doar în acel ochi (orbire monoculară în ochiul drept).',
  'senses',
  10
) ON CONFLICT (id) DO UPDATE SET
