INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens96',
  'med-admission-barrons',
  'hard',
  'What is presbycusis?',
  'Ce este presbiacuzia?',
  '["Congenital hearing loss","Age-related hearing loss, typically affecting high frequencies first","Hearing loss due to infection","Sudden hearing loss","Hearing loss due to trauma"]'::jsonb,
  '["Pierdere auditivă congenitală","Pierdere auditivă legată de vârstă, afectând de obicei frecvențele înalte mai întâi","Pierdere auditivă datorată infecției","Pierdere auditivă bruscă","Pierdere auditivă datorată traumei"]'::jsonb,
  1,
  'Presbycusis is age-related sensorineural hearing loss, typically affecting high-frequency hearing first due to cochlear hair cell degeneration.',
  'Presbiacuzia este pierderea auditivă senzorioneurală legată de vârstă, afectând de obicei auzul de frecvență înaltă mai întâi din cauza degenerării celulelor ciliate cohleare.',
  'senses',
  10
) ON CONFLICT (id) DO UPDATE SET
