INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens97',
  'med-admission-barrons',
  'hard',
  'A patient cannot distinguish between red and green. Which type of color vision deficiency do they have?',
  'Un pacient nu poate distinge între roșu și verde. Ce tip de deficiență a vederii în culori are?',
  '["Tritanopia (blue-yellow)","Protanopia or deuteranopia (red-green)","Complete achromatopsia","Night blindness","Macular degeneration"]'::jsonb,
  '["Tritanopia (albastru-galben)","Protanopie sau deuteranopie (roșu-verde)","Acromatopsie completă","Cecitate nocturnă","Degenerescență maculară"]'::jsonb,
  1,
  'Red-green color blindness (protanopia = no red cones; deuteranopia = no green cones) is the most common type of color vision deficiency.',
  'Daltonismul roșu-verde (protanopia = fără conuri roșii; deuteranopia = fără conuri verzi) este cel mai frecvent tip de deficiență a vederii în culori.',
  'senses',
  10
