  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens98',
  'med-admission-barrons',
  'hard',
  'What is an acoustic neuroma?',
  'Ce este un neurinom acustic?',
  '["Inflammation of the cochlea","A benign tumor on the vestibulocochlear nerve","Infection of the middle ear","Rupture of the eardrum","Degeneration of auditory cortex"]'::jsonb,
  '["Inflamație a cohleei","O tumoare benignă pe nervul vestibulo-cohlear","Infecție a urechii medii","Ruptura timpanului","Degenerarea cortexului auditiv"]'::jsonb,
  1,
  'An acoustic neuroma (vestibular schwannoma) is a benign tumor arising from Schwann cells of the vestibulocochlear nerve (CN VIII).',
  'Un neurinom acustic (schwannom vestibular) este o tumoare benignă care provine din celulele Schwann ale nervului vestibulo-cohlear (NC VIII).',
  'senses',
