INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'sens100',
  'med-admission-barrons',
  'hard',
  'Which sensory adaptation explains why you stop noticing a constant odor after some time?',
  'Care adaptare senzorială explică de ce nu mai observi un miros constant după un timp?',
  '["Sensitization","Olfactory adaptation (habituation)","Cross-adaptation","Potentiation","Sensory amplification"]'::jsonb,
  '["Sensibilizare","Adaptare olfactivă (habituare)","Adaptare încrucișată","Potențare","Amplificare senzorială"]'::jsonb,
  1,
  'Olfactory adaptation is the decreased sensitivity to a constant odor over time, occurring at both receptor and central processing levels.',
  'Adaptarea olfactivă este scăderea sensibilității la un miros constant în timp, apărând atât la nivel de receptor cât și de procesare centrală.',
