INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'endo1',
  'med-admission-barrons',
  'easy',
  'Which gland is often called the "master gland" because it secretes hormones that control other endocrine glands?',
  'Care glandă este adesea numită „glanda maestră” deoarece secretă hormoni care controlează alte glande endocrine?',
  '["Thyroid","Adrenal gland","Pituitary gland","Pancreas","Pineal gland"]'::jsonb,
  '["Tiroidă","Glandă suprarenală","Glanda hipofizară","Pancreas","Glanda pineală"]'::jsonb,
  2,
  'The pituitary gland secretes tropic hormones (e.g., ACTH, TSH, FSH, LH) that regulate the thyroid, adrenal cortex, and gonads.',
  'Hipofiza secretă hormoni tropici (ex. ACTH, TSH, FSH, LH) care reglează tiroida, cortexul suprarenal și gonadele.',
  'endocrine',
  1
) ON CONFLICT (id) DO UPDATE SET
