  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'endo2',
  'med-admission-barrons',
  'easy',
  'Which hormone lowers blood glucose by promoting glucose uptake into cells?',
  'Care hormon scade glicemia promovând captarea glucozei în celule?',
  '["Glucagon","Insulin","Cortisol","Growth hormone","Epinephrine"]'::jsonb,
  '["Glucagonul","Insulina","Cortizolul","Hormonul de creștere","Epinefrina"]'::jsonb,
  1,
  'Insulin, from pancreatic beta cells, stimulates cells to take up glucose and store it as glycogen or fat, lowering blood glucose.',
  'Insulina, din celulele beta pancreatice, stimulează celulele să preia glucoză și să o stocheze ca glicogen sau grăsimi, scăzând glicemia.',
  'endocrine',
  1
) ON CONFLICT (id) DO UPDATE SET
