  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'endo3',
  'med-admission-barrons',
  'easy',
  'Which gland produces hormones that regulate metabolism and body calcium levels?',
  'Care glandă produce hormoni care reglează metabolismul și nivelul de calciu din organism?',
  '["Adrenal gland","Thyroid gland","Pancreas","Pineal gland","Thymus"]'::jsonb,
  '["Glanda suprarenală","Glanda tiroidă","Pancreas","Glanda pineală","Timus"]'::jsonb,
  1,
  'The thyroid produces thyroxine (T4) and triiodothyronine (T3) for metabolism, and calcitonin for calcium regulation.',
  'Tiroida produce tiroxina (T4) și triiodotironina (T3) pentru metabolism și calcitonina pentru reglarea calciului.',
  'endocrine',
