INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'endo7',
  'med-admission-barrons',
  'medium',
  'Which hormone increases blood calcium by stimulating osteoclasts and promoting calcium reabsorption in the kidneys?',
  'Care hormon crește calciul din sânge stimulând osteoclastele și promovând reabsorbția de calciu în rinichi?',
  '["Calcitonin","Parathyroid hormone (PTH)","Insulin","Cortisol","Aldosterone"]'::jsonb,
  '["Calcitonina","Hormonul paratiroid (PTH)","Insulina","Cortizolul","Aldosteronul"]'::jsonb,
  1,
  'PTH, from the parathyroid glands, raises blood calcium by stimulating bone resorption, kidney reabsorption of Ca²⁺, and intestinal absorption (via vitamin D).',
  'PTH, din glandele paratiroide, crește calciul din sânge stimulând resorbția osoasă, reabsorbția de Ca²⁺ în rinichi și absorbția intestinală (prin vitamina D).',
  'endocrine',
  1
