INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'endo10',
  'med-admission-barrons',
  'hard',
  'Which gland produces melatonin and is involved in circadian rhythm regulation?',
  'Care glandă produce melatonina și este implicată în reglarea ritmului circadian?',
  '["Pituitary","Thyroid","Adrenal","Pineal gland","Pancreas"]'::jsonb,
  '["Hipofiză","Tiroidă","Suprarenală","Glanda pineală","Pancreas"]'::jsonb,
  3,
  'The pineal gland secretes melatonin in response to darkness, helping regulate sleep-wake cycles and circadian rhythms.',
  'Glanda pineală secretă melatonina ca răspuns la întuneric, ajutând la reglarea ciclurilor de somn-veghe și a ritmurilor circadiene.',
