INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'endo11',
  'med-admission-barrons',
  'easy',
  'What are hormones?',
  'Ce sunt hormonii?',
  '["Enzymes that speed up chemical reactions","Chemical messengers secreted into blood that affect target cells","Structural proteins in cell membranes","Nucleic acids that carry genetic information","Antibodies produced by the immune system"]'::jsonb,
  '["Enzime care accelerează reacțiile chimice","Mesageri chimici secretați în sânge care afectează celulele țintă","Proteine structurale în membranele celulare","Acizi nucleici care transportă informații genetice","Anticorpi produși de sistemul imunitar"]'::jsonb,
  1,
  'Hormones are chemical messengers produced by endocrine glands that travel through the blood to affect specific target cells.',
  'Hormonii sunt mesageri chimici produși de glandele endocrine care călătoresc prin sânge pentru a afecta celule țintă specifice.',
  'endocrine',
  2
) ON CONFLICT (id) DO UPDATE SET
