  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'endo12',
  'med-admission-barrons',
  'easy',
  'Where is the pituitary gland located?',
  'Unde este situată glanda pituitară?',
  '["In the neck","In a bony cavity (sella turcica) at the base of the brain","Above the kidneys","In the chest","In the abdomen"]'::jsonb,
  '["În gât","Într-o cavitate osoasă (șaua turcească) la baza creierului","Deasupra rinichilor","În torace","În abdomen"]'::jsonb,
  1,
  'The pituitary gland sits in the sella turcica of the sphenoid bone, connected to the hypothalamus by the infundibulum (pituitary stalk).',
  'Glanda pituitară se află în șaua turcească a osului sfenoid, conectată la hipotalamus prin infundibul (tija hipofizară).',
  'endocrine',
  2
) ON CONFLICT (id) DO UPDATE SET
