  '["Thyroid glands","Parathyroid glands","Adrenal glands","Pituitary glands","Pineal glands"]'::jsonb,
  '["Glandele tiroide","Glandele paratiroide","Glandele suprarenale","Glandele pituitare","Glandele pineale"]'::jsonb,
