INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'blood1',
  'med-admission-barrons',
  'easy',
  'Which of the following best describes blood as a tissue?',
  'Care dintre afirmațiile de mai jos descrie cel mai bine sângele ca țesut?',
  '["It is an epithelial tissue composed mainly of tightly packed cells","It is a nervous tissue composed of neurons and neuroglia","It is a connective tissue with formed elements suspended in a fluid matrix","It is a muscular tissue specialized for contraction","It is an avascular tissue containing no cells"]'::jsonb,
  '["Este un țesut epitelial alcătuit în principal din celule strâns unite","Este un țesut nervos alcătuit din neuroni și celule gliale","Este un țesut conjunctiv cu elemente figurate suspendate într-o matrice fluidă","Este un țesut muscular specializat pentru contracție","Este un țesut avascular care nu conține celule"]'::jsonb,
  2,
  'Blood is classified as a connective tissue because it consists of formed elements suspended in a fluid extracellular matrix called plasma.',
  'Sângele este încadrat ca țesut conjunctiv deoarece conține elemente figurate suspendate într-o matrice extracelulară fluidă numită plasmă.',
  'blood',
  1
) ON CONFLICT (id) DO UPDATE SET
