INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'blood13',
  'med-admission-barrons',
  'easy',
  'Which type of blood cell is responsible for carrying oxygen?',
  'Care tip de celulă sanguină este responsabil de transportul oxigenului?',
  '["White blood cells","Platelets","Red blood cells (erythrocytes)","Plasma cells","Mast cells"]'::jsonb,
  '["Globulele albe","Trombocitele","Globulele roșii (eritrocitele)","Plasmocitele","Mastocitele"]'::jsonb,
