INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cardio2',
  'med-admission-barrons',
  'easy',
  'Which statement best describes the function of the atria?',
  'Care afirmație descrie cel mai bine funcția atriilor?',
  '["They pump blood directly into the systemic circulation at high pressure","They receive blood returning to the heart and act as priming chambers for the ventricles","They generate the main contractile force of the heart","They contain the pulmonary and aortic semilunar valves","They are responsible for initiating the electrical impulse of the heart"]'::jsonb,
  '["Pompează sânge direct în circulația sistemică la presiune mare","Primesc sângele care se întoarce la inimă și acționează ca „camere de primire” pentru ventricule","Generează principala forță contractilă a inimii","Conțin valvele semilunare pulmonară și aortică","Sunt responsabile pentru inițierea impulsului electric al inimii"]'::jsonb,
  1,
  'The atria receive venous blood returning to the heart and gently fill the ventricles, acting as low-pressure priming chambers.',
  'Atriile primesc sângele venos care se întoarce la inimă și umplu ușor ventriculele, acționând ca „camere de primire” cu presiune joasă.',
  'cardiovascular',
  1
) ON CONFLICT (id) DO UPDATE SET
