INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cardio3',
  'med-admission-barrons',
  'easy',
  'Which structure prevents backflow of blood from the right ventricle to the right atrium during ventricular systole?',
  'Care structură împiedică refluxul sângelui din ventriculul drept în atriul drept în timpul sistolei ventriculare?',
  '["Pulmonary valve","Aortic valve","Mitral (bicuspid) valve","Tricuspid valve","Interventricular septum"]'::jsonb,
  '["Valva pulmonară","Valva aortică","Valva mitrală (bicuspida)","Valva tricuspida","Septul interventricular"]'::jsonb,
  3,
  'The tricuspid valve is the right atrioventricular valve and prevents backflow from the right ventricle into the right atrium during ventricular contraction.',
  'Valva tricuspida este valva atrioventriculară dreaptă și împiedică refluxul sângelui din ventriculul drept în atriul drept în timpul contracției ventriculare.',
  'cardiovascular',
  1
) ON CONFLICT (id) DO UPDATE SET
