INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cardio4',
  'med-admission-barrons',
  'medium',
  'Which of the following lists correctly represents the sequence of blood flow through the right side of the heart and lungs?',
  'Care dintre următoarele variante reprezintă corect succesiunea fluxului de sânge prin partea dreaptă a inimii și plămâni?',
  '["Right atrium → right ventricle → pulmonary veins → lungs","Right atrium → pulmonary trunk → right ventricle → lungs","Venae cavae → right atrium → right ventricle → pulmonary trunk → lungs","Lungs → pulmonary arteries → right ventricle → right atrium","Right ventricle → venae cavae → lungs → right atrium"]'::jsonb,
  '["Atriul drept → ventriculul drept → vene pulmonare → plămâni","Atriul drept → trunchiul pulmonar → ventriculul drept → plămâni","Vene cave → atriul drept → ventriculul drept → trunchiul pulmonar → plămâni","Plămâni → artere pulmonare → ventriculul drept → atriul drept","Ventriculul drept → vene cave → plămâni → atriul drept"]'::jsonb,
  2,
  'Deoxygenated blood returns via the venae cavae to the right atrium, passes into the right ventricle, and is then pumped into the pulmonary trunk toward the lungs.',
  'Sângele neoxigenat se întoarce prin venele cave în atriul drept, trece în ventriculul drept și este apoi pompat în trunchiul pulmonar către plămâni.',
  'cardiovascular',
  1
) ON CONFLICT (id) DO UPDATE SET
