INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cardio5',
  'med-admission-barrons',
  'medium',
  'Which statement about the coronary arteries is TRUE?',
  'Care afirmație despre arterele coronare este ADEVĂRATĂ?',
  '["They arise from the inferior vena cava just before it enters the right atrium","They are branches of the pulmonary trunk supplying the lungs","They arise from the ascending aorta just above the aortic valve","They carry deoxygenated blood to the myocardium","They mainly fill during ventricular systole"]'::jsonb,
  '["Ia naștere din vena cavă inferioară chiar înainte de intrarea în atriul drept","Sunt ramuri ale trunchiului pulmonar care vascularizează plămânii","Ia naștere din aorta ascendentă imediat deasupra valvei aortice","Transportă sânge neoxigenat către miocard","Se umplu în principal în timpul sistolei ventriculare"]'::jsonb,
  2,
  'The right and left coronary arteries arise from the ascending aorta just above the aortic valve and supply oxygenated blood to the myocardium.',
  'Arterele coronare dreaptă și stângă iau naștere din aorta ascendentă imediat deasupra valvei aortice și aduc sânge oxigenat la miocard.',
