INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cardio6',
  'med-admission-barrons',
  'medium',
  'Which component of the cardiac conduction system normally acts as the primary pacemaker of the heart?',
  'Care component al sistemului de conducere cardiac acționează în mod normal ca „pacemaker” principal al inimii?',
  '["Atrioventricular (AV) node","Bundle of His","Purkinje fibers","Sinoatrial (SA) node","Interventricular septum"]'::jsonb,
  '["Nodul atrioventricular (AV)","Trunchiul fasciculului His","Fibrele Purkinje","Nodul sinoatrial (SA)","Septul interventricular"]'::jsonb,
  3,
  'The sinoatrial (SA) node initiates the electrical impulse in a healthy heart and therefore functions as the primary pacemaker.',
  'Nodul sinoatrial (SA) inițiază impulsul electric într-o inimă sănătoasă și, prin urmare, funcționează ca pacemaker principal.',
