INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cardio7',
  'med-admission-barrons',
  'medium',
  'During ventricular systole, which of the following events occurs?',
  'În timpul sistolei ventriculare, care dintre următoarele evenimente are loc?',
  '["Atrioventricular valves open and semilunar valves close","Both atria and ventricles relax simultaneously","Atrioventricular valves close and semilunar valves open","Blood flows from atria into ventricles","Pulmonary and aortic pressures fall to zero"]'::jsonb,
  '["Valvele atrioventriculare se deschid, iar valvele semilunare se închid","Atât atriile, cât și ventriculele se relaxează simultan","Valvele atrioventriculare se închid, iar valvele semilunare se deschid","Sângele curge din atrii în ventricule","Presiunile pulmonară și aortică scad la zero"]'::jsonb,
  2,
  'During ventricular systole, the AV valves close to prevent backflow into the atria, while the semilunar valves open to allow ejection of blood into the great arteries.',
  'În sistola ventriculară, valvele atrioventriculare se închid pentru a preveni refluxul în atrii, iar valvele semilunare se deschid pentru a permite ejectarea sângelui în marile artere.',
  'cardiovascular',
  1
) ON CONFLICT (id) DO UPDATE SET
