INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cardio8',
  'med-admission-barrons',
  'hard',
  'Which pressure change best explains the closure of the atrioventricular valves at the beginning of ventricular systole?',
  'Care modificare de presiune explică cel mai bine închiderea valvelor atrioventriculare la începutul sistolei ventriculare?',
  '["Atrial pressure becomes higher than ventricular pressure","Ventricular pressure exceeds atrial pressure","Arterial pressure exceeds ventricular pressure","Atrial pressure falls to zero","Pericardial pressure suddenly rises above ventricular pressure"]'::jsonb,
  '["Presiunea atrială devine mai mare decât presiunea ventriculară","Presiunea ventriculară depășește presiunea atrială","Presiunea arterială depășește presiunea ventriculară","Presiunea atrială scade la zero","Presiunea pericardică crește brusc peste presiunea ventriculară"]'::jsonb,
  1,
  'At the onset of ventricular systole, rising ventricular pressure exceeds atrial pressure, forcing the atrioventricular valves to close.',
  'La începutul sistolei ventriculare, creșterea presiunii ventriculare depășește presiunea atrială, ceea ce determină închiderea valvelor atrioventriculare.',
