INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cardio71',
  'med-admission-barrons',
  'hard',
  'Blood pressure is calculated as:',
  'Tensiunea arterială se calculează ca:',
  '["Stroke volume × Heart rate","Cardiac output × Peripheral resistance","Blood volume / Vessel diameter","Heart rate × Peripheral resistance","Stroke volume × Peripheral resistance"]'::jsonb,
  '["Volumul sistolic × Frecvența cardiacă","Debitul cardiac × Rezistența periferică","Volumul de sânge / Diametrul vasului","Frecvența cardiacă × Rezistența periferică","Volumul sistolic × Rezistența periferică"]'::jsonb,
  1,
  'Mean arterial pressure (MAP) = Cardiac output × Total peripheral resistance.',
