INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cardio72',
  'med-admission-barrons',
  'hard',
  'Mean arterial pressure (MAP) can be estimated by:',
  'Presiunea arterială medie (PAM) poate fi estimată prin:',
  '["Systolic + Diastolic / 2","Diastolic + 1/3 (Systolic - Diastolic)","Systolic - Diastolic","Systolic × Diastolic","(Systolic + Diastolic) × 2"]'::jsonb,
  '["Sistolică + Diastolică / 2","Diastolică + 1/3 (Sistolică - Diastolică)","Sistolică - Diastolică","Sistolică × Diastolică","(Sistolică + Diastolică) × 2"]'::jsonb,
  1,
  'MAP ≈ Diastolic + 1/3 (Pulse pressure), because diastole is longer than systole.',
  'PAM ≈ Diastolică + 1/3 (Presiunea pulsului), deoarece diastola este mai lungă decât sistola.',
  'cardiovascular',
  8
