INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cardio73',
  'med-admission-barrons',
  'hard',
  'What is pulse pressure?',
  'Ce este presiunea pulsului?',
  '["Mean arterial pressure","Systolic pressure minus diastolic pressure","Diastolic pressure divided by 2","Cardiac output divided by heart rate","Central venous pressure"]'::jsonb,
  '["Presiunea arterială medie","Presiunea sistolică minus presiunea diastolică","Presiunea diastolică împărțită la 2","Debitul cardiac împărțit la frecvența cardiacă","Presiunea venoasă centrală"]'::jsonb,
  1,
  'Pulse pressure = Systolic pressure - Diastolic pressure (normally about 40 mmHg).',
  'Presiunea pulsului = Presiunea sistolică - Presiunea diastolică (normal aproximativ 40 mmHg).',
