INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'cardio74',
  'med-admission-barrons',
  'hard',
  'According to Poiseuille''s law, blood flow is most affected by:',
  'Conform legii lui Poiseuille, fluxul sanguin este afectat cel mai mult de:',
  '["Blood viscosity","Vessel length","Vessel radius","Pressure gradient","Blood temperature"]'::jsonb,
  '["Vâscozitatea sângelui","Lungimea vasului","Raza vasului","Gradientul de presiune","Temperatura sângelui"]'::jsonb,
  2,
  'Flow is proportional to radius to the fourth power (r⁴); halving radius decreases flow 16-fold.',
