INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp1',
  'med-admission-barrons',
  'easy',
  'What is the primary function of the respiratory system?',
  'Care este funcția principală a sistemului respirator?',
  '["To produce hormones and regulate metabolism","To transport nutrients and wastes throughout the body","To perform gas exchange, supplying oxygen and removing carbon dioxide","To generate nerve impulses for muscle contraction","To synthesize plasma proteins and clotting factors"]'::jsonb,
  '["Producerea hormonilor și reglarea metabolismului","Transportul nutrienților și produșilor de excreție în organism","Realizarea schimbului de gaze, aport de oxigen și eliminare de dioxid de carbon","Generarea impulsurilor nervoase pentru contracția musculară","Sinteza proteinelor plasmatice și a factorilor de coagulare"]'::jsonb,
  2,
  'The respiratory system''s main role is gas exchange, providing oxygen to the blood and removing carbon dioxide from it.',
  'Rolul principal al sistemului respirator este schimbul de gaze, asigurând aportul de oxigen și eliminarea dioxidului de carbon din sânge.',
  'respiratory',
  1
) ON CONFLICT (id) DO UPDATE SET
