INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp2',
  'med-admission-barrons',
  'easy',
  'Which structures are part of the upper respiratory tract?',
  'Care structuri fac parte din căile respiratorii superioare?',
  '["Nose, nasal cavity, pharynx, and larynx","Trachea, bronchi, and bronchioles","Alveoli and pulmonary capillaries","Pleura and diaphragm","Lungs and ribs"]'::jsonb,
  '["Nasul, cavitatea nazală, faringele și laringele","Traheea, bronhiile și bronhiolele","Alveolele și capilarele pulmonare","Pleura și diafragmul","Plămânii și coastele"]'::jsonb,
  0,
  'The upper respiratory tract includes the nose, nasal cavity, pharynx, and larynx, which conduct, warm, and filter inspired air.',
  'Căile respiratorii superioare includ nasul, cavitatea nazală, faringele și laringele, care conduc, încălzesc și filtrează aerul inspirat.',
  'respiratory',
  1
) ON CONFLICT (id) DO UPDATE SET
