  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp3',
  'med-admission-barrons',
  'easy',
  'Which structure directly connects the larynx to the primary bronchi?',
  'Care structură conectează direct laringele cu bronhiile principale?',
  '["Pharynx","Trachea","Alveolar ducts","Bronchioles","Diaphragm"]'::jsonb,
  '["Faringele","Traheea","Ductele alveolare","Bronhiolele","Diafragmul"]'::jsonb,
  1,
  'The trachea is a tubular airway that extends from the larynx and bifurcates into the right and left primary bronchi.',
  'Traheea este un conduct aerian tubular care se întinde de la laringe și se bifurcă în bronhia principală dreaptă și stângă.',
  'respiratory',
