INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp4',
  'med-admission-barrons',
  'easy',
  'In which structures of the lungs does most gas exchange occur?',
  'În care structuri ale plămânilor are loc majoritatea schimbului de gaze?',
  '["Trachea and primary bronchi","Bronchioles and terminal bronchioles","Alveoli and respiratory bronchioles","Pleural cavity and ribs","Diaphragm and intercostal muscles"]'::jsonb,
  '["Trahee și bronhii principale","Bronhiole și bronhiole terminale","Alveole și bronhiole respiratorii","Cavitate pleurală și coaste","Diafragm și mușchii intercostali"]'::jsonb,
  2,
  'Gas exchange takes place in the respiratory portion of the airway, mainly in the alveoli and adjacent respiratory bronchioles.',
  'Schimbul de gaze are loc în porțiunea respiratorie a căilor aeriene, în principal la nivelul alveolelor și al bronhiolelor respiratorii.',
  'respiratory',
  1
) ON CONFLICT (id) DO UPDATE SET
