INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp5',
  'med-admission-barrons',
  'medium',
  'Which muscle is the primary muscle of inspiration during quiet breathing?',
  'Care mușchi este principalul mușchi al inspirației în respirația liniștită?',
  '["Internal intercostal muscles","Diaphragm","Abdominal muscles","Sternocleidomastoid","Scalene muscles"]'::jsonb,
  '["Mușchii intercostali interni","Diafragmul","Mușchii abdominali","Sternocleidomastoidianul","Mușchii scalenii"]'::jsonb,
  1,
  'During quiet inspiration, contraction of the diaphragm is the main driver of lung expansion and air entry.',
  'În inspirația liniștită, contracția diafragmului este principalul mecanism care determină expansiunea plămânilor și pătrunderea aerului.',
  'respiratory',
  1
) ON CONFLICT (id) DO UPDATE SET
