INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp6',
  'med-admission-barrons',
  'medium',
  'What happens to intrathoracic pressure during inspiration?',
  'Ce se întâmplă cu presiunea intratoracică în timpul inspirației?',
  '["It becomes more positive than atmospheric pressure","It becomes more negative than atmospheric pressure","It remains constant and equal to atmospheric pressure","It rises sharply to stop air from entering the lungs","It alternates randomly between positive and negative values"]'::jsonb,
  '["Devine mai pozitivă decât presiunea atmosferică","Devine mai negativă decât presiunea atmosferică","Rămâne constantă și egală cu presiunea atmosferică","Crește brusc pentru a împiedica intrarea aerului în plămâni","Alternează aleator între valori pozitive și negative"]'::jsonb,
  1,
  'During inspiration, thoracic volume increases and intrathoracic pressure becomes more negative than atmospheric pressure, drawing air into the lungs.',
  'În inspirație, volumul toracic crește, iar presiunea intratoracică devine mai negativă decât presiunea atmosferică, ceea ce determină pătrunderea aerului în plămâni.',
  'respiratory',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp7',
  'med-admission-barrons',
  'medium',
  'Which statement best describes gas exchange at the alveolar level?',
  'Care afirmație descrie cel mai bine schimbul de gaze la nivel alveolar?',
  '["Oxygen and carbon dioxide are actively pumped across the respiratory membrane","Oxygen diffuses from blood to alveolar air, while carbon dioxide diffuses from air to blood","Both oxygen and carbon dioxide diffuse down their partial pressure gradients across the respiratory membrane","Gas exchange only occurs during forced inspiration","Gas exchange occurs only in the trachea and main bronchi"]'::jsonb,
  '["Oxigenul și dioxidul de carbon sunt pompate activ peste membrana respiratorie","Oxigenul difuzează din sânge în aerul alveolar, iar dioxidul de carbon din aer în sânge","Atât oxigenul, cât și dioxidul de carbon difuzează conform gradientului de presiune parțială peste membrana respiratorie","Schimbul de gaze apare doar în inspirația forțată","Schimbul de gaze are loc doar în trahee și bronhiile principale"]'::jsonb,
  2,
  'At the respiratory membrane, oxygen and carbon dioxide move by diffusion, down their respective partial pressure gradients.',
  'La nivelul membranei respiratorii, oxigenul și dioxidul de carbon se deplasează prin difuziune, urmând gradientul lor de presiune parțială.',
  'respiratory',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp8',
  'med-admission-barrons',
  'hard',
  'Which factor most directly determines the direction of diffusion of oxygen between alveolar air and pulmonary capillary blood?',
  'Care factor determină cel mai direct direcția difuziunii oxigenului între aerul alveolar și sângele capilar pulmonar?',
  '["Total atmospheric pressure","Difference in partial pressure of oxygen between alveoli and blood","Body temperature","Blood pH","Level of hemoglobin saturation in systemic veins"]'::jsonb,
  '["Presiunea atmosferică totală","Diferența de presiune parțială a oxigenului între alveole și sânge","Temperatura corpului","pH-ul sângelui","Gradul de saturație a hemoglobinei în venele sistemice"]'::jsonb,
  1,
  'Oxygen diffuses from a region of higher partial pressure to a region of lower partial pressure, so the alveolar–capillary partial pressure gradient is key.',
  'Oxigenul difuzează dintr-o zonă cu presiune parțială mai mare către una cu presiune parțială mai mică; astfel, gradientul de presiune parțială alveolo-capilar este esențial.',
  'respiratory',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp9',
  'med-admission-barrons',
  'hard',
  'Which of the following best describes the term "ventilation–perfusion (V/Q) matching"?',
  'Care dintre afirmațiile de mai jos descrie cel mai bine termenul „potrivirea ventilație–perfuzie (V/Q)”?',
  '["Equal heart rate and respiratory rate at rest","Equal volumes of air in both lungs","The relationship between air reaching alveoli and blood flow in their capillaries","The ratio between tidal volume and inspiratory reserve volume","The balance between oxygen and carbon dioxide content in expired air"]'::jsonb,
  '["Egalitatea dintre frecvența cardiacă și frecvența respiratorie în repaus","Volum egal de aer în ambii plămâni","Relația dintre aerul care ajunge în alveole și fluxul de sânge din capilarele lor","Raportul dintre volumul curent și volumul de rezervă inspirator","Echilibrul dintre conținutul de oxigen și dioxid de carbon din aerul expirat"]'::jsonb,
  2,
  'Ventilation–perfusion matching refers to the relationship between alveolar ventilation and pulmonary capillary perfusion, which must be balanced for efficient gas exchange.',
  'Potrivirea ventilație–perfuzie descrie relația dintre ventilația alveolară și perfuzia capilară pulmonară, relație care trebuie să fie echilibrată pentru un schimb eficient de gaze.',
  'respiratory',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp10',
  'med-admission-barrons',
  'hard',
  'Which of the following changes would most likely decrease the efficiency of external respiration in the lungs?',
  'Care dintre următoarele modificări ar scădea cel mai probabil eficiența respirației externe în plămâni?',
  '["Increased surface area of alveoli","Thickening of the respiratory membrane","A thin and moist respiratory membrane","Adequate matching of ventilation and perfusion","High partial pressure of oxygen in alveolar air"]'::jsonb,
  '["Creșterea suprafeței alveolelor","Îngroșarea membranei respiratorii","O membrană respiratorie subțire și umedă","Potrivirea adecvată a ventilației cu perfuzia","Presiune parțială mare a oxigenului în aerul alveolar"]'::jsonb,
  1,
  'Thickening of the respiratory membrane increases diffusion distance and slows gas exchange, reducing the efficiency of external respiration.',
  'Îngroșarea membranei respiratorii crește distanța de difuziune și încetinește schimbul de gaze, reducând eficiența respirației externe.',
  'respiratory',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

