INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp15',
  'med-admission-barrons',
  'easy',
  'What structure prevents food from entering the trachea?',
  'Ce structură previne intrarea alimentelor în trahee?',
  '["Uvula","Epiglottis","Tongue","Soft palate","Vocal cords"]'::jsonb,
  '["Uvula","Epiglota","Limba","Palatul moale","Corzile vocale"]'::jsonb,
  1,
  'The epiglottis is a flap that covers the trachea during swallowing to prevent aspiration.',
  'Epiglota este o clapetă care acoperă traheea în timpul înghițirii pentru a preveni aspirația.',
  'respiratory',
