INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp24',
  'med-admission-barrons',
  'medium',
  'The pharynx is divided into three regions. The correct order from top to bottom is:',
  'Faringele este împărțit în trei regiuni. Ordinea corectă de sus în jos este:',
  '["Oropharynx, nasopharynx, laryngopharynx","Nasopharynx, oropharynx, laryngopharynx","Laryngopharynx, oropharynx, nasopharynx","Nasopharynx, laryngopharynx, oropharynx","Oropharynx, laryngopharynx, nasopharynx"]'::jsonb,
  '["Orofaringe, nazofaringe, laringofaringe","Nazofaringe, orofaringe, laringofaringe","Laringofaringe, orofaringe, nazofaringe","Nazofaringe, laringofaringe, orofaringe","Orofaringe, laringofaringe, nazofaringe"]'::jsonb,
  1,
  'From superior to inferior: nasopharynx (behind nasal cavity), oropharynx (behind mouth), laryngopharynx (above larynx).',
  'De la superior la inferior: nazofaringe (în spatele cavității nazale), orofaringe (în spatele gurii), laringofaringe (deasupra laringelui).',
  'respiratory',
  3
) ON CONFLICT (id) DO UPDATE SET
