INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp31',
  'med-admission-barrons',
  'medium',
  'The right main bronchus is:',
  'Bronhia principală dreaptă este:',
  '["Longer and more horizontal","Shorter, wider, and more vertical","The same as the left","Narrower than the left","Without cartilage"]'::jsonb,
  '["Mai lungă și mai orizontală","Mai scurtă, mai lată și mai verticală","La fel ca cea stângă","Mai îngustă decât cea stângă","Fără cartilaj"]'::jsonb,
  1,
  'The right main bronchus is shorter, wider, and more vertical, making it more likely for aspirated objects to enter.',
  'Bronhia principală dreaptă este mai scurtă, mai lată și mai verticală, făcând mai probabilă intrarea obiectelor aspirate.',
  'respiratory',
  4
) ON CONFLICT (id) DO UPDATE SET
