INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp32',
  'med-admission-barrons',
  'medium',
  'As bronchi branch into smaller bronchioles, they:',
  'Pe măsură ce bronhiile se ramifică în bronhiole mai mici, ele:',
  '["Gain more cartilage","Lose cartilage and gain smooth muscle","Become more rigid","Increase in diameter","Lose cilia entirely"]'::jsonb,
  '["Câștigă mai mult cartilaj","Pierd cartilaj și câștigă mușchi neted","Devin mai rigide","Cresc în diametru","Pierd cilii complet"]'::jsonb,
  1,
  'Bronchioles have no cartilage; their walls contain smooth muscle that can constrict or dilate.',
  'Bronhiolele nu au cartilaj; pereții lor conțin mușchi neted care se poate contracta sau dilata.',
  'respiratory',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
