  'Celulele alveolare de tip II produc:',
  '["Mucus","Surfactant","Antibodies","Red blood cells","Histamine"]'::jsonb,
  '["Mucus","Surfactant","Anticorpi","Globule roșii","Histamină"]'::jsonb,
