INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp36',
  'med-admission-barrons',
  'medium',
  'Surfactant prevents:',
  'Surfactantul previne:',
  '["Infection","Alveolar collapse (atelectasis)","Gas exchange","Blood flow to alveoli","Mucus production"]'::jsonb,
  '["Infecția","Colapsul alveolar (atelectazie)","Schimbul de gaze","Fluxul sanguin către alveole","Producția de mucus"]'::jsonb,
  1,
  'Surfactant reduces alveolar surface tension, preventing collapse and making inflation easier.',
