INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp51',
  'med-admission-barrons',
  'medium',
  'Tidal volume is:',
  'Volumul curent este:',
  '["Maximum air exhaled after maximum inspiration","Air inhaled or exhaled in normal breathing","Air remaining after maximum exhalation","Maximum air that can be inspired","Total lung capacity"]'::jsonb,
  '["Aerul maxim expirat după inspirație maximă","Aerul inspirat sau expirat în respirația normală","Aerul rămas după expirație maximă","Aerul maxim care poate fi inspirat","Capacitatea pulmonară totală"]'::jsonb,
  1,
  'Tidal volume (TV) is the amount of air inhaled or exhaled in a normal breath (~500 mL).',
  'Volumul curent (VC) este cantitatea de aer inspirat sau expirat într-o respirație normală (~500 mL).',
