INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp52',
  'med-admission-barrons',
  'medium',
  'Vital capacity is:',
  'Capacitatea vitală este:',
  '["Air remaining after normal expiration","Maximum air exhaled after maximum inspiration","Air that cannot be exhaled","Normal tidal volume","Dead space volume"]'::jsonb,
  '["Aerul rămas după expirație normală","Aerul maxim expirat după inspirație maximă","Aerul care nu poate fi expirat","Volumul curent normal","Volumul spațiului mort"]'::jsonb,
  1,
  'Vital capacity = IRV + TV + ERV; it''s the maximum air that can be exhaled after maximum inhalation.',
  'Capacitatea vitală = VRI + VC + VRE; este aerul maxim care poate fi expirat după inhalare maximă.',
