INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp53',
  'med-admission-barrons',
  'medium',
  'Residual volume is:',
  'Volumul rezidual este:',
  '["Air inspired during normal breathing","Air remaining in lungs after maximum expiration","Air in the conducting airways","Maximum inspiratory capacity","Tidal volume plus reserve"]'::jsonb,
  '["Aerul inspirat în timpul respirației normale","Aerul rămas în plămâni după expirație maximă","Aerul din căile conductoare","Capacitatea inspiratorie maximă","Volumul curent plus rezervă"]'::jsonb,
  1,
  'Residual volume (~1200 mL) is air that remains in the lungs after forced expiration, preventing collapse.',
  'Volumul rezidual (~1200 mL) este aerul care rămâne în plămâni după expirație forțată, prevenind colapsul.',
