INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp54',
  'med-admission-barrons',
  'hard',
  'Total lung capacity equals:',
  'Capacitatea pulmonară totală este egală cu:',
  '["Vital capacity minus residual volume","Vital capacity plus residual volume","Tidal volume plus residual volume","Inspiratory reserve plus tidal volume","Expiratory reserve plus tidal volume"]'::jsonb,
  '["Capacitatea vitală minus volumul rezidual","Capacitatea vitală plus volumul rezidual","Volumul curent plus volumul rezidual","Rezerva inspiratorie plus volumul curent","Rezerva expiratorie plus volumul curent"]'::jsonb,
  1,
  'Total lung capacity = Vital capacity + Residual volume (approximately 6000 mL in adults).',
  'Capacitatea pulmonară totală = Capacitatea vitală + Volumul rezidual (aproximativ 6000 mL la adulți).',
  'respiratory',
  6
) ON CONFLICT (id) DO UPDATE SET
