INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'resp97',
  'med-admission-barrons',
  'hard',
  'Pulmonary embolism most commonly originates from:',
  'Embolia pulmonară își are originea cel mai frecvent în:',
  '["Left atrium","Coronary arteries","Deep leg veins (DVT)","Pulmonary arteries","Aorta"]'::jsonb,
  '["Atriul stâng","Arterele coronare","Venele profunde ale picioarelor (TVP)","Arterele pulmonare","Aorta"]'::jsonb,
  2,
  'Most pulmonary emboli arise from deep vein thrombosis (DVT) in the legs traveling to the lungs.',
