INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'dig1',
  'med-admission-barrons',
  'easy',
  'Which organs are part of the alimentary canal (GI tract)?',
  'Care organe fac parte din canalul alimentar (tubul digestiv propriu-zis)?',
  '["Mouth, pharynx, esophagus, stomach, small intestine, large intestine","Liver, pancreas, gallbladder","Mouth, liver, kidneys","Pancreas, spleen, adrenal glands","Tongue, salivary glands, liver"]'::jsonb,
  '["Cavitatea bucală, faringele, esofagul, stomacul, intestinul subțire, intestinul gros","Ficatul, pancreasul, vezica biliară","Cavitatea bucală, ficatul, rinichii","Pancreasul, splina, glandele suprarenale","Limba, glandele salivare, ficatul"]'::jsonb,
  0,
  'The alimentary canal is the continuous tube from mouth to anus and includes mouth, pharynx, esophagus, stomach, small intestine, and large intestine.',
  'Canalul alimentar este un tub continuu de la cavitatea bucală la anus și include cavitatea bucală, faringele, esofagul, stomacul, intestinul subțire și intestinul gros.',
  'digestive',
  1
) ON CONFLICT (id) DO UPDATE SET
