INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'dig2',
  'med-admission-barrons',
  'easy',
  'Which of the following are accessory digestive organs?',
  'Care dintre următoarele sunt organe anexe ale sistemului digestiv?',
  '["Liver, pancreas, gallbladder, salivary glands","Stomach, small intestine, large intestine","Esophagus and rectum","Heart and lungs","Kidneys and ureters"]'::jsonb,
  '["Ficatul, pancreasul, vezica biliară, glandele salivare","Stomacul, intestinul subțire, intestinul gros","Esofagul și rectul","Inima și plămânii","Rinichii și ureterele"]'::jsonb,
  0,
  'Accessory digestive organs include the liver, gallbladder, pancreas, and salivary glands, which secrete substances into the GI tract but are not part of the main tube.',
  'Organele anexe includ ficatul, vezica biliară, pancreasul și glandele salivare, care secretă substanțe în tubul digestiv, dar nu fac parte din tubul propriu-zis.',
  'digestive',
  1
) ON CONFLICT (id) DO UPDATE SET
