INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'dig3',
  'med-admission-barrons',
  'easy',
  'Which statement best describes the main function of the small intestine?',
  'Care afirmație descrie cel mai bine funcția principală a intestinului subțire?',
  '["Temporary storage of feces before elimination","Mechanical breakdown of food by strong churning movements only","Major site of chemical digestion and absorption of nutrients","Production and storage of bile","Filtration of blood and excretion of nitrogenous wastes"]'::jsonb,
  '["Depozitarea temporară a materiilor fecale înainte de eliminare","Dezintegrarea mecanică a alimentelor doar prin mișcări puternice","Locul principal al digestiei chimice și al absorbției nutrienților","Producerea și depozitarea bilei","Filtrarea sângelui și excreția produșilor azotați"]'::jsonb,
  2,
  'Most chemical digestion and almost all nutrient absorption occur in the small intestine.',
  'Cea mai mare parte a digestiei chimice și aproape toată absorbția nutrienților au loc în intestinul subțire.',
  'digestive',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
