INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'dig4',
  'med-admission-barrons',
  'easy',
  'Which process is an example of mechanical digestion?',
  'Care proces reprezintă un exemplu de digestie mecanică?',
  '["Action of salivary amylase on starch","Pepsin breaking down proteins in the stomach","Bile salts emulsifying fats in the small intestine","Chewing food with the teeth","Pancreatic lipase splitting triglycerides"]'::jsonb,
  '["Acțiunea amilazei salivare asupra amidonului","Descompunerea proteinelor de către pepsină în stomac","Emulsificarea grăsimilor de către sărurile biliare în intestinul subțire","Masticația alimentelor cu ajutorul dinților","Scindarea trigliceridelor de către lipaza pancreatică"]'::jsonb,
  3,
  'Mechanical digestion involves physical breakdown of food, such as chewing, without changing its chemical structure.',
  'Digestia mecanică implică fragmentarea fizică a alimentelor, de exemplu prin masticație, fără modificarea structurii chimice.',
  'digestive',
  1
) ON CONFLICT (id) DO UPDATE SET
