INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'dig5',
  'med-admission-barrons',
  'medium',
  'Which of the following is a correct function of the stomach?',
  'Care dintre următoarele reprezintă o funcție corectă a stomacului?',
  '["Main site of nutrient absorption into the blood","Production of bile and detoxification of absorbed substances","Mixing food with gastric juice and starting protein digestion","Secretion of most digestive enzymes for all macronutrients","Storage of feces until defecation"]'::jsonb,
  '["Principalul loc de absorbție a nutrienților în sânge","Producerea bilei și detoxifierea substanțelor absorbite","Amestecarea alimentelor cu sucul gastric și inițierea digestiei proteinelor","Secreția celor mai mulți enzimi digestivi pentru toți macronutrienții","Depozitarea materiilor fecale până la defecație"]'::jsonb,
  2,
  'The stomach mixes food with gastric juice, forming chyme, and initiates protein digestion, but absorbs few nutrients.',
  'Stomacul amestecă alimentele cu sucul gastric, formând chimul, și inițiază digestia proteinelor, dar absoarbe puțini nutrienți.',
  'digestive',
