INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'dig6',
  'med-admission-barrons',
  'medium',
  'Which statement about the large intestine (colon) is TRUE?',
  'Care afirmație despre intestinul gros (colon) este ADEVĂRATĂ?',
  '["It is the main site of lipid digestion and absorption","It primarily functions in water and electrolyte absorption and feces formation","It produces bile and stores it until needed","It secretes most digestive enzymes for protein digestion","It is the main site of glucose absorption from the lumen"]'::jsonb,
  '["Este principalul loc de digestie și absorbție a lipidelor","Are ca funcție principală absorbția apei și electroliților și formarea materiilor fecale","Produce bila și o depozitează până este necesară","Secretă majoritatea enzimelor digestive pentru digestia proteinelor","Este principalul loc de absorbție a glucozei din lumen"]'::jsonb,
  1,
  'The large intestine mainly absorbs water and electrolytes and compacts indigestible residues into feces.',
  'Intestinul gros absoarbe în principal apă și electroliți și compactează reziduurile nedigerabile în materii fecale.',
