  '["Carbohydrates","Proteins","Vitamins","Minerals","Water"]'::jsonb,
  '["Glucidele (carbohidrații)","Proteinele","Vitaminele","Mineralele","Apa"]'::jsonb,
  0,
  'Carbohydrates are the main immediate energy source for cells and are commonly used to generate ATP.',
  'Glucidele reprezintă principala sursă imediată de energie pentru celule și sunt frecvent utilizate pentru producerea de ATP.',
  'metabolism',
  1
) ON CONFLICT (id) DO UPDATE SET
