INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'metab4',
  'med-admission-barrons',
  'easy',
  'Which of the following is considered a macronutrient?',
  'Care dintre următoarele este considerat macronutrient?',
  '["Vitamin C","Iron","Calcium","Carbohydrates","Vitamin B12"]'::jsonb,
  '["Vitamina C","Fierul","Calciul","Glucidele (carbohidrații)","Vitamina B12"]'::jsonb,
  3,
  'Macronutrients—carbohydrates, lipids, and proteins—are required in relatively large amounts and provide energy or structural components.',
  'Macronutrienții – glucide, lipide și proteine – sunt necesari în cantități relativ mari și furnizează energie sau componente structurale.',
  'metabolism',
  1
) ON CONFLICT (id) DO UPDATE SET
