  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'metab5',
  'med-admission-barrons',
  'medium',
  'Which statement best distinguishes micronutrients from macronutrients?',
  'Care afirmație diferențiază cel mai bine micronutrienții de macronutrienți?',
  '["Micronutrients provide most of the body''s energy needs","Micronutrients are needed in smaller amounts and mainly act as cofactors and regulators","Macronutrients are needed only in trace amounts","Micronutrients include only carbohydrates and lipids","Micronutrients cannot be obtained from the diet"]'::jsonb,
  '["Micronutrienții furnizează cea mai mare parte a necesarului energetic al organismului","Micronutrienții sunt necesari în cantități mai mici și acționează în principal ca factori cofatori și regulatori","Macronutrienții sunt necesari doar în cantități de urme","Micronutrienții includ doar glucide și lipide","Micronutrienții nu pot fi obținuți din alimentație"]'::jsonb,
  1,
  'Micronutrients, such as vitamins and minerals, are required in small amounts and are critical as cofactors, regulators, and structural elements.',
  'Micronutrienții, precum vitaminele și mineralele, sunt necesari în cantități mici și sunt esențiali ca factori cofatori, regulatori și elemente structurale.',
  'metabolism',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'metab6',
  'med-admission-barrons',
  'medium',
  'Which of the following correctly matches a vitamin group with its solubility?',
  'Care variantă asociază corect un grup de vitamine cu solubilitatea lor?',
  '["Vitamins A, D, E, K – water-soluble","B-complex and vitamin C – fat-soluble","Vitamins A, D, E, K – fat-soluble","Vitamins B6 and B12 – stored extensively in adipose tissue","All vitamins are fat-soluble and stored in the liver"]'::jsonb,
  '["Vitaminele A, D, E, K – solubile în apă","Complexul B și vitamina C – solubile în grăsimi","Vitaminele A, D, E, K – solubile în grăsimi","Vitaminele B6 și B12 – stocate extensiv în țesutul adipos","Toate vitaminele sunt solubile în grăsimi și stocate în ficat"]'::jsonb,
  2,
  'Vitamins A, D, E, and K are fat-soluble, whereas the B-complex vitamins and vitamin C are water-soluble.',
  'Vitaminele A, D, E și K sunt liposolubile, în timp ce vitaminele din complexul B și vitamina C sunt hidrosolubile.',
  'metabolism',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'metab7',
  'med-admission-barrons',
  'medium',
  'Which organ plays a central role in regulating carbohydrate metabolism (e.g., glycogenesis, glycogenolysis, gluconeogenesis)?',
  'Care organ are un rol central în reglarea metabolismului glucidic (de ex. glicogeneză, glicogenoliză, gluconeogeneză)?',
  '["Kidneys","Liver","Spleen","Large intestine","Pancreas only"]'::jsonb,
  '["Rinichii","Ficatul","Splina","Intestinul gros","Doar pancreasul"]'::jsonb,
  1,
  'The liver is a key metabolic organ that stores glycogen, breaks it down when needed, and produces glucose via gluconeogenesis.',
  'Ficatul este un organ metabolic esențial care depozitează glicogen, îl degradează la nevoie și produce glucoză prin gluconeogeneză.',
  'metabolism',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
