  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'metab8',
  'med-admission-barrons',
  'hard',
  'Which hormone is primarily responsible for lowering blood glucose levels after a carbohydrate-rich meal?',
  'Care hormon este responsabil în principal de scăderea glicemiei după o masă bogată în glucide?',
  '["Glucagon","Insulin","Cortisol","Adrenaline (epinephrine)","Thyroxine (T4)"]'::jsonb,
  '["Glucagonul","Insulina","Cortizolul","Adrenalina (epinefrina)","Tiroxina (T4)"]'::jsonb,
  1,
  'Insulin, secreted by pancreatic beta cells, promotes cellular uptake and storage of glucose, thereby lowering blood glucose levels.',
  'Insulina, secretată de celulele beta pancreatice, favorizează captarea și depozitarea glucozei de către celule, scăzând astfel glicemia.',
  'metabolism',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'metab9',
  'med-admission-barrons',
  'hard',
  'Which of the following best describes basal metabolic rate (BMR)?',
  'Care dintre afirmațiile de mai jos descrie cel mai bine rata metabolică bazală (BMR)?',
  '["The amount of energy used during vigorous exercise","The total energy expenditure over 24 hours regardless of conditions","The rate of energy use at rest in a postabsorptive state, in a neutral thermal environment","The amount of energy derived only from protein metabolism","The energy needed to digest and absorb a single meal"]'::jsonb,
  '["Cantitatea de energie utilizată în timpul efortului fizic intens","Cheltuiala energetică totală pe 24 de ore indiferent de condiții","Rata de utilizare a energiei în repaus, în stare postabsorbtivă, într-un mediu termic neutru","Cantitatea de energie obținută doar din metabolismul proteinelor","Energia necesară pentru digestia și absorbția unei singure mese"]'::jsonb,
  2,
  'Basal metabolic rate is measured at rest, in a postabsorptive state, in a neutral thermal environment, and reflects the minimal energy needed to sustain vital functions.',
  'Rata metabolică bazală se măsoară în repaus, în stare postabsorbtivă, într-un mediu termic neutru și reflectă energia minimă necesară pentru funcțiile vitale.',
  'metabolism',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'metab10',
  'med-admission-barrons',
  'hard',
  'Which of the following is a correct example of how nutrients support cellular metabolism?',
  'Care dintre următoarele reprezintă un exemplu corect al modului în care nutrienții susțin metabolismul celular?',
  '["Carbohydrates provide amino acids for DNA replication","Lipids serve only as structural components of cell membranes and never as an energy source","Proteins supply amino acids for enzyme synthesis and tissue repair","Vitamins directly generate ATP by being broken down in mitochondria","Minerals are not involved in enzymatic reactions"]'::jsonb,
  '["Glucidele furnizează aminoacizi pentru replicarea ADN-ului","Lipidele servesc doar ca elemente structurale ale membranelor celulare și niciodată ca sursă de energie","Proteinele furnizează aminoacizi pentru sinteza enzimelor și repararea țesuturilor","Vitaminele generează direct ATP prin degradare în mitocondrii","Mineralele nu sunt implicate în reacții enzimatice"]'::jsonb,
  2,
  'Proteins provide amino acids that are essential for the synthesis of enzymes and structural proteins involved in growth and tissue repair.',
  'Proteinele furnizează aminoacizi esențiali pentru sinteza enzimelor și a proteinelor structurale implicate în creștere și repararea țesuturilor.',
  'metabolism',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

