INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'urin4',
  'med-admission-barrons',
  'medium',
  'Where does filtration of blood primarily occur in the kidney?',
  'Unde are loc în principal filtrarea sângelui în rinichi?',
  '["Loop of Henle","Collecting duct","Glomerulus (within Bowman''s capsule)","Distal convoluted tubule","Renal pelvis"]'::jsonb,
  '["Ansa Henle","Tubul colector","Glomerul (în capsula Bowman)","Tubul contorsionat distal","Pelvisul renal"]'::jsonb,
  2,
  'In the glomerulus, blood pressure forces fluid and small solutes through the filtration barrier into Bowman''s capsule, forming the filtrate.',
  'În glomerul, presiunea sanguină forțează fluidul și solutii mici prin bariera de filtrare în capsula Bowman, formând filtratul.',
