INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'urin30',
  'med-admission-barrons',
  'medium',
  'What is the primary driving force for glomerular filtration?',
  'Care este forța principală care conduce filtrarea glomerulară?',
  '["Oncotic pressure in Bowman''s capsule","Hydrostatic pressure in Bowman''s capsule","Glomerular capillary blood pressure","Osmotic gradient in medulla","Active transport of solutes"]'::jsonb,
  '["Presiunea oncotică în capsula Bowman","Presiunea hidrostatică în capsula Bowman","Presiunea sanguină capilară glomerulară","Gradientul osmotic din medulară","Transportul activ al soluților"]'::jsonb,
  2,
  'Glomerular capillary blood pressure (about 55 mmHg) is the primary force pushing fluid through the filtration membrane.',
  'Presiunea sanguină capilară glomerulară (aproximativ 55 mmHg) este forța principală care împinge lichidul prin membrana de filtrare.',
