INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'urin44',
  'med-admission-barrons',
  'hard',
  'Which mechanism is primarily responsible for the countercurrent multiplier effect in the loop of Henle?',
  'Care mecanism este responsabil în principal pentru efectul de multiplicare în contracurent în ansa Henle?',
  '["Passive diffusion of water in ascending limb","Active transport of NaCl in thick ascending limb","ADH action on descending limb","Urea recycling in collecting duct only","Osmosis in Bowman''s capsule"]'::jsonb,
  '["Difuzia pasivă a apei în segmentul ascendent","Transportul activ al NaCl în segmentul ascendent gros","Acțiunea ADH pe segmentul descendent","Doar reciclarea ureei în tubul colector","Osmoza în capsula Bowman"]'::jsonb,
  1,
  'Active transport of NaCl out of the thick ascending limb (impermeable to water) establishes the medullary osmotic gradient.',
  'Transportul activ al NaCl din segmentul ascendent gros (impermeabil la apă) stabilește gradientul osmotic medular.',
  'urinary',
  5
) ON CONFLICT (id) DO UPDATE SET
