  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'urin45',
  'med-admission-barrons',
  'hard',
  'What is the role of vasa recta in kidney function?',
  'Care este rolul vasa recta în funcția renală?',
  '["Filtration of blood","Secretion of renin","Maintaining medullary osmotic gradient","Production of erythropoietin","Reabsorption of glucose"]'::jsonb,
  '["Filtrarea sângelui","Secreția reninei","Menținerea gradientului osmotic medular","Producția eritropoietinei","Reabsorbția glucozei"]'::jsonb,
  2,
  'The vasa recta are straight capillaries that supply blood to the medulla while preserving the osmotic gradient through countercurrent exchange.',
  'Vasa recta sunt capilare drepte care furnizează sânge medularii menținând gradientul osmotic prin schimb în contracurent.',
