INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'urin46',
  'med-admission-barrons',
  'hard',
  'Which condition results from inability of kidneys to produce concentrated urine despite high ADH levels?',
  'Ce afecțiune rezultă din incapacitatea rinichilor de a produce urină concentrată în ciuda nivelurilor ridicate de ADH?',
  '["Central diabetes insipidus","Nephrogenic diabetes insipidus","SIADH","Diabetes mellitus","Addison''s disease"]'::jsonb,
  '["Diabet insipid central","Diabet insipid nefrogen","SIADH","Diabet zaharat","Boala Addison"]'::jsonb,
  1,
  'Nephrogenic diabetes insipidus occurs when collecting ducts fail to respond to ADH, causing dilute urine despite adequate hormone.',
  'Diabetul insipid nefrogen apare când tubii colectori nu răspund la ADH, cauzând urină diluată în ciuda hormonului adecvat.',
