INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'urin47',
  'med-admission-barrons',
  'hard',
  'Which layer of the glomerular filtration barrier contains podocytes?',
  'Care strat al barierei de filtrare glomerulară conține podocite?',
  '["Fenestrated endothelium","Basement membrane","Visceral layer of Bowman''s capsule","Parietal layer of Bowman''s capsule","Mesangium"]'::jsonb,
  '["Endoteliu fenestrat","Membrana bazală","Stratul visceral al capsulei Bowman","Stratul parietal al capsulei Bowman","Mezangiu"]'::jsonb,
  2,
  'Podocytes form the visceral layer of Bowman''s capsule; their foot processes create filtration slits that filter blood.',
  'Podocitele formează stratul visceral al capsulei Bowman; prelungirile lor pediculare creează fante de filtrare care filtrează sângele.',
  'urinary',
  5
) ON CONFLICT (id) DO UPDATE SET
