INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'urin48',
  'med-admission-barrons',
  'hard',
  'What is the renal clearance of a substance if it equals the GFR?',
  'Care este clearance-ul renal al unei substanțe dacă egalează RFG?',
  '["Substance is reabsorbed","Substance is secreted","Substance is neither reabsorbed nor secreted","Substance is protein-bound","Substance is completely filtered"]'::jsonb,
  '["Substanța este reabsorbită","Substanța este secretată","Substanța nu este nici reabsorbită nici secretată","Substanța este legată de proteine","Substanța este complet filtrată"]'::jsonb,
  2,
  'If clearance equals GFR, the substance is freely filtered and neither reabsorbed nor secreted (like inulin).',
  'Dacă clearance-ul egalează RFG, substanța este filtrată liber și nici reabsorbită nici secretată (precum inulina).',
  'urinary',
  5
) ON CONFLICT (id) DO UPDATE SET
