INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'urin49',
  'med-admission-barrons',
  'hard',
  'Which receptor type mediates the effect of ADH on collecting duct water permeability?',
  'Care tip de receptor mediază efectul ADH asupra permeabilității la apă a tubului colector?',
  '["V1 receptor","V2 receptor","Alpha-1 receptor","Beta-2 receptor","Mineralocorticoid receptor"]'::jsonb,
  '["Receptor V1","Receptor V2","Receptor alfa-1","Receptor beta-2","Receptor mineralocorticoid"]'::jsonb,
  1,
  'ADH binds to V2 receptors on collecting duct principal cells, activating cAMP pathway to insert aquaporin-2 channels.',
  'ADH se leagă de receptorii V2 pe celulele principale ale tubului colector, activând calea cAMP pentru inserarea canalelor aquaporină-2.',
