INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repM87',
  'med-admission-barrons',
  'hard',
  'What is the function of activin in male reproduction?',
  'Care este funcția activinei în reproducerea masculină?',
  '["Inhibits FSH release","Stimulates FSH release (opposite of inhibin)","Produces testosterone","Inhibits spermatogenesis","Causes erection"]'::jsonb,
  '["Inhibă eliberarea FSH","Stimulează eliberarea FSH (opus inhibinei)","Produce testosteron","Inhibă spermatogeneza","Cauzează erecția"]'::jsonb,
  1,
  'Activin, also produced by Sertoli cells, has the opposite effect of inhibin, stimulating FSH release from the pituitary.',
  'Activina, produsă tot de celulele Sertoli, are efectul opus inhibinei, stimulând eliberarea FSH din hipofiză.',
