INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repM90',
  'med-admission-barrons',
  'hard',
  'What is spermatocele?',
  'Ce este spermatocelul?',
  '["Testicular tumor","Fluid-filled cyst of the epididymis containing sperm","Dilated veins","Absence of sperm","Inflammation of testis"]'::jsonb,
  '["Tumoare testiculară","Chist plin cu lichid al epididimului conținând spermatozoizi","Vene dilatate","Absența spermatozoizilor","Inflamația testiculului"]'::jsonb,
  1,
  'A spermatocele is a benign, painless cyst of the epididymis containing milky fluid with dead sperm, usually requiring no treatment.',
  'Un spermatocel este un chist benign, nedureros al epididimului conținând lichid lăptos cu spermatozoizi morți, de obicei fără a necesita tratament.',
  'repro-male',
  9
) ON CONFLICT (id) DO UPDATE SET
