INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repM91',
  'med-admission-barrons',
  'hard',
  'What is the difference between sperm emission and ejaculation neurologically?',
  'Care este diferența neurologică între emisia și ejacularea spermatozoizilor?',
  '["Both are parasympathetic","Emission is sympathetic (T10-L2), ejaculation is somatic (S2-4 pudendal nerve)","Both are somatic","Both are sympathetic","Emission is somatic, ejaculation is parasympathetic"]'::jsonb,
  '["Ambele sunt parasimpatice","Emisia este simpatică (T10-L2), ejacularea este somatică (S2-4 nervul pudendal)","Ambele sunt somatice","Ambele sunt simpatice","Emisia este somatică, ejacularea este parasimpatică"]'::jsonb,
  1,
  'Emission (movement to urethra) is controlled by sympathetic nerves (T10-L2); ejaculation (expulsion) is somatic via pudendal nerve rhythmic contractions.',
  'Emisia (mișcarea în uretră) este controlată de nervi simpatici (T10-L2); ejacularea (expulzarea) este somatică prin contracții ritmice ale nervului pudendal.',
  'repro-male',
  10
) ON CONFLICT (id) DO UPDATE SET
