INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repM92',
  'med-admission-barrons',
  'hard',
  'What is the significance of the prehn sign in testicular pain?',
  'Care este semnificația semnului Prehn în durerea testiculară?',
  '["Diagnoses cancer","Elevation relieves pain in epididymitis but not torsion","Always indicates torsion","Measures testosterone","Evaluates sperm count"]'::jsonb,
  '["Diagnostică cancerul","Elevarea ameliorează durerea în epididimită dar nu în torsiune","Indică întotdeauna torsiune","Măsoară testosteronul","Evaluează numărul de spermatozoizi"]'::jsonb,
  1,
  'Prehn''s sign: scrotal elevation relieves pain in epididymitis (positive) but not in testicular torsion (negative); however, it''s not fully reliable.',
  'Semnul Prehn: elevarea scrotală ameliorează durerea în epididimită (pozitiv) dar nu în torsiunea testiculară (negativ); totuși, nu este complet fiabil.',
  'repro-male',
