INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF1',
  'med-admission-barrons',
  'easy',
  'Which organ is the site of fertilization and where the fertilized egg typically implants and develops?',
  'Care organ este locul fertilizării și unde ovulul fecundat se implantează și se dezvoltă de obicei?',
  '["Ovary","Uterus","Vagina","Fallopian tube (uterine tube) for fertilization; uterus for implantation","Cervix"]'::jsonb,
  '["Ovar","Uter","Vagin","Trompă uterină pentru fertilizare; uter pentru implantare","Col uterin"]'::jsonb,
  3,
  'Fertilization usually occurs in the fallopian tube; the embryo then travels to the uterus and implants in the endometrium.',
  'Fertilizarea are loc de obicei în trompa uterină; embrionul ajunge apoi în uter și se implantează în endometru.',
  'repro-female',
