INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF5',
  'med-admission-barrons',
  'medium',
  'Which event in the ovarian cycle triggers ovulation (release of the oocyte)?',
  'Care eveniment din ciclul ovarian declanșează ovulația (eliberarea ovulului)?',
  '["A surge in FSH","A surge in LH","A drop in estrogen only","A surge in progesterone only","A drop in prolactin"]'::jsonb,
  '["Un vârf de FSH","Un vârf de LH","Doar o scădere a estrogenului","Doar un vârf de progesteron","O scădere a prolactinei"]'::jsonb,
  1,
  'The mid-cycle LH surge triggers the final maturation of the follicle and ovulation (release of the oocyte from the ovary).',
  'Vârful de LH de la mijlocul ciclului declanșează maturarea finală a foliculului și ovulația (eliberarea ovulului din ovar).',
  'repro-female',
  1
) ON CONFLICT (id) DO UPDATE SET
