INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF6',
  'med-admission-barrons',
  'medium',
  'Which structure is the narrow lower portion of the uterus that opens into the vagina?',
  'Care structură este porțiunea îngustă inferioară a uterului care se deschide în vagin?',
  '["Fundus","Body of uterus","Cervix","Fallopian tube","Vagina"]'::jsonb,
  '["Fondul","Corpul uterin","Colul uterin","Trompa uterină","Vaginul"]'::jsonb,
  2,
  'The cervix is the lower, narrow part of the uterus that projects into the vagina; it contains a canal that allows passage of sperm and menstrual flow.',
  'Colul uterin este partea inferioară îngustă a uterului care se proiectează în vagin; conține un canal care permite trecerea spermei și a fluxului menstrual.',
  'repro-female',
  1
) ON CONFLICT (id) DO UPDATE SET
