  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF7',
  'med-admission-barrons',
  'medium',
  'Which structure forms after ovulation from the ruptured follicle and secretes progesterone?',
  'Care structură se formează după ovulație din foliculul rupt și secretă progesteron?',
  '["Primary follicle","Corpus luteum","Graafian follicle only (before ovulation)","Oocyte","Endometrium"]'::jsonb,
  '["Folicul primar","Corpul galben","Doar foliculul Graaf (înainte de ovulație)","Ovocit","Endometru"]'::jsonb,
  1,
  'After ovulation, the remaining follicle becomes the corpus luteum, which secretes progesterone (and some estrogen) to support the endometrium and early pregnancy.',
  'După ovulație, foliculul rămas devine corpul galben, care secretă progesteron (și puțin estrogen) pentru a susține endometrul și sarcina timpurie.',
  'repro-female',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
