  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF8',
  'med-admission-barrons',
  'hard',
  'Which phase of the menstrual cycle is characterized by shedding of the endometrial lining if fertilization has not occurred?',
  'Care fază a ciclului menstrual este caracterizată de eliminarea mucoasei endometriale dacă nu a avut loc fertilizarea?',
  '["Follicular phase","Ovulation","Luteal phase","Menstrual phase (menstruation)","Proliferative phase only"]'::jsonb,
  '["Faza foliculară","Ovulație","Faza luteală","Faza menstruală (menstruație)","Doar faza proliferativă"]'::jsonb,
  3,
  'During menstruation, the endometrial lining is shed (bleeding) when the corpus luteum degenerates and progesterone and estrogen drop, if no pregnancy has occurred.',
  'În timpul menstruației, mucoasa endometrială este eliminată (sângerare) când corpul galben degenerează și progesteronul și estrogenul scad, dacă nu a apărut sarcină.',
  'repro-female',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF9',
  'med-admission-barrons',
  'hard',
  'Which hormone is essential for maintaining pregnancy by preventing uterine contractions and supporting the endometrium?',
  'Care hormon este esențial pentru menținerea sarcinii prin prevenirea contracțiilor uterine și susținerea endometrului?',
  '["Estrogen only","Progesterone","FSH","LH","Prolactin only (before birth)"]'::jsonb,
  '["Doar estrogen","Progesteron","FSH","LH","Doar prolactina (înainte de naștere)"]'::jsonb,
  1,
  'Progesterone maintains the endometrium, reduces uterine contractility, and supports early pregnancy; it is produced by the corpus luteum and later by the placenta.',
  'Progesteronul menține endometrul, reduce contractilitatea uterină și susține sarcina timpurie; este produs de corpul galben și mai târziu de placentă.',
  'repro-female',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
