  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF10',
  'med-admission-barrons',
  'hard',
  'Where does the oocyte typically get fertilized by a sperm cell?',
  'Unde este fecundat de obicei ovulul de un spermatozoid?',
  '["In the ovary","In the uterus","In the vagina","In the fallopian (uterine) tube, usually the ampulla","In the cervix"]'::jsonb,
  '["În ovar","În uter","În vagin","În trompa uterină, de obicei în ampulă","În colul uterin"]'::jsonb,
  3,
  'Fertilization usually occurs in the ampulla of the fallopian tube, where the oocyte is picked up by the fimbriae after ovulation.',
  'Fertilizarea are loc de obicei în ampula trompei uterine, unde ovulul este prins de fimbrii după ovulație.',
  'repro-female',
  1
) ON CONFLICT (id) DO UPDATE SET
