INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF25',
  'med-admission-barrons',
  'medium',
  'What is the function of progesterone?',
  'Care este funcția progesteronului?',
  '["Stimulates follicle development","Prepares and maintains endometrium for pregnancy","Triggers ovulation","Causes menstruation","Stimulates breast milk production"]'::jsonb,
  '["Stimulează dezvoltarea foliculului","Pregătește și menține endometrul pentru sarcină","Declanșează ovulația","Cauzează menstruația","Stimulează producția de lapte matern"]'::jsonb,
  1,
  'Progesterone prepares the endometrium for implantation, maintains pregnancy, inhibits uterine contractions, and raises body temperature.',
  'Progesteronul pregătește endometrul pentru implantare, menține sarcina, inhibă contracțiile uterine și crește temperatura corpului.',
  'repro-female',
  3
) ON CONFLICT (id) DO UPDATE SET
