INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF31',
  'med-admission-barrons',
  'medium',
  'What is the normal position of the uterus?',
  'Care este poziția normală a uterului?',
  '["Retroverted and retroflexed","Anteverted and anteflexed","Vertical","Horizontal","Inverted"]'::jsonb,
  '["Retroversat și retroflectat","Anteversat și anteflectat","Vertical","Orizontal","Inversat"]'::jsonb,
  1,
  'The normal uterine position is anteverted (tilted forward over bladder) and anteflexed (bent forward at the junction of body and cervix).',
  'Poziția uterină normală este anteversată (înclinată înainte peste vezică) și anteflectată (îndoită înainte la joncțiunea corpului și colului).',
