INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF42',
  'med-admission-barrons',
  'hard',
  'What is the transformation zone of the cervix?',
  'Ce este zona de transformare a colului uterin?',
  '["Internal os","Area where columnar epithelium meets squamous epithelium","External os only","Uterine cavity","Vaginal fornix"]'::jsonb,
  '["Orificiul intern","Zona unde epiteliul cilindric întâlnește epiteliul scuamos","Doar orificiul extern","Cavitatea uterină","Fornixul vaginal"]'::jsonb,
  1,
  'The transformation zone is where the columnar epithelium of the endocervix meets the squamous epithelium of the ectocervix; it is the most common site for cervical cancer.',
  'Zona de transformare este unde epiteliul cilindric al endocervixului întâlnește epiteliul scuamos al ectocervixului; este cel mai frecvent loc pentru cancerul de col uterin.',
