INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF43',
  'med-admission-barrons',
  'hard',
  'What hormone maintains the corpus luteum in early pregnancy?',
  'Ce hormon menține corpul galben în sarcina timpurie?',
  '["LH","hCG (human chorionic gonadotropin)","FSH","Estrogen","Prolactin"]'::jsonb,
  '["LH","hCG (gonadotropină corionică umană)","FSH","Estrogen","Prolactină"]'::jsonb,
  1,
  'hCG from the developing placenta maintains the corpus luteum until the placenta takes over progesterone production (around 8-10 weeks).',
  'hCG de la placenta în dezvoltare menține corpul galben până când placenta preia producția de progesteron (în jurul săptămânilor 8-10).',
  'repro-female',
  5
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
