  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF44',
  'med-admission-barrons',
  'hard',
  'What is polycystic ovary syndrome (PCOS)?',
  'Ce este sindromul ovarelor polichistice (SOPC)?',
  '["Ovarian cancer","Hormonal disorder with anovulation, hyperandrogenism, and polycystic ovaries","Infection of ovaries","Premature menopause","Uterine fibroids"]'::jsonb,
  '["Cancer ovarian","Tulburare hormonală cu anovulație, hiperandrogenism și ovare polichistice","Infecție a ovarelor","Menopauză prematură","Fibroame uterine"]'::jsonb,
  1,
  'PCOS is characterized by chronic anovulation, elevated androgens (causing hirsutism, acne), insulin resistance, and multiple ovarian cysts.',
  'SOPC este caracterizat de anovulație cronică, androgeni ridicați (cauzând hirsutism, acnee), rezistență la insulină și multiple chisturi ovariene.',
  'repro-female',
  5
) ON CONFLICT (id) DO UPDATE SET
