INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF45',
  'med-admission-barrons',
  'hard',
  'What is endometriosis?',
  'Ce este endometrioza?',
  '["Uterine cancer","Presence of endometrial tissue outside the uterus","Thick endometrium","Absence of endometrium","Infection of endometrium"]'::jsonb,
  '["Cancer uterin","Prezența țesutului endometrial în afara uterului","Endometru gros","Absența endometrului","Infecție a endometrului"]'::jsonb,
  1,
  'Endometriosis is the presence of functional endometrial tissue outside the uterus, causing pain, inflammation, and often infertility.',
  'Endometrioza este prezența țesutului endometrial funcțional în afara uterului, cauzând durere, inflamație și adesea infertilitate.',
  'repro-female',
