INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF46',
  'med-admission-barrons',
  'hard',
  'What is the suspensory ligament of the ovary?',
  'Ce este ligamentul suspensor al ovarului?',
  '["Connects ovary to uterus","Contains ovarian vessels and nerves from pelvic brim to ovary","Part of the round ligament","Supports the bladder","Connects uterus to sacrum"]'::jsonb,
  '["Conectează ovarul la uter","Conține vasele și nervii ovarieni de la marginea pelvisului la ovar","Parte a ligamentului rotund","Susține vezica","Conectează uterul de sacru"]'::jsonb,
  1,
  'The suspensory ligament (infundibulopelvic ligament) contains the ovarian artery, vein, and nerves connecting the ovary to the lateral pelvic wall.',
  'Ligamentul suspensor (ligamentul infundibulo-pelvin) conține artera ovariană, vena și nervii care conectează ovarul la peretele pelvin lateral.',
