INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF49',
  'med-admission-barrons',
  'hard',
  'What causes primary ovarian insufficiency (premature menopause)?',
  'Ce cauzează insuficiența ovariană primară (menopauza prematură)?',
  '["Pituitary tumor","Depletion or dysfunction of ovarian follicles before age 40","Hypothalamic dysfunction","Excessive exercise only","Normal aging"]'::jsonb,
  '["Tumoare hipofizară","Depleția sau disfuncția foliculilor ovarieni înainte de 40 ani","Disfuncție hipotalamică","Doar exercițiu excesiv","Îmbătrânire normală"]'::jsonb,
  1,
  'Primary ovarian insufficiency is loss of ovarian function before age 40 due to follicle depletion, autoimmune causes, or genetic factors like Turner syndrome.',
  'Insuficiența ovariană primară este pierderea funcției ovariene înainte de 40 ani din cauza depleției foliculare, cauze autoimune sau factori genetici precum sindromul Turner.',
  'repro-female',
  5
) ON CONFLICT (id) DO UPDATE SET
