INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF50',
  'med-admission-barrons',
  'hard',
  'What is the blood supply to the ovary?',
  'Care este alimentarea cu sânge a ovarului?',
  '["Uterine artery only","Ovarian artery (from aorta) and ovarian branch of uterine artery","Internal iliac artery only","External iliac artery","Femoral artery"]'::jsonb,
  '["Doar artera uterină","Artera ovariană (de la aortă) și ramura ovariană a arterei uterine","Doar artera iliacă internă","Artera iliacă externă","Artera femurală"]'::jsonb,
  1,
  'The ovary receives blood from the ovarian artery (directly from aorta) and the ovarian branch of the uterine artery, which anastomose.',
  'Ovarul primește sânge de la artera ovariană (direct de la aortă) și ramura ovariană a arterei uterine, care se anastomozează.',
  'repro-female',
  5
