INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF51',
  'med-admission-barrons',
  'hard',
  'What is the dominant follicle?',
  'Ce este foliculul dominant?',
  '["Smallest follicle","The follicle selected to ovulate in each cycle","Multiple follicles","Corpus luteum","Primordial follicle"]'::jsonb,
  '["Cel mai mic folicul","Foliculul selectat să ovuleze în fiecare ciclu","Foliculi multipli","Corp galben","Folicul primordial"]'::jsonb,
  1,
  'The dominant follicle is the single follicle selected (usually around day 7) to complete maturation and ovulate; others undergo atresia.',
  'Foliculul dominant este foliculul unic selectat (de obicei în jurul zilei 7) să completeze maturarea și să ovuleze; ceilalți suferă atrezie.',
  'repro-female',
  6
) ON CONFLICT (id) DO UPDATE SET
