INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF52',
  'med-admission-barrons',
  'hard',
  'What is the corona radiata?',
  'Ce este corona radiată?',
  '["Layer around the corpus luteum","Layer of granulosa cells surrounding the oocyte after ovulation","Part of the fallopian tube","Outer ovarian covering","Uterine muscle layer"]'::jsonb,
  '["Strat în jurul corpului galben","Strat de celule granuloase care înconjoară ovocitul după ovulație","Parte a trompei uterine","Învelișul extern al ovarului","Stratul muscular uterin"]'::jsonb,
  1,
  'The corona radiata is the layer of granulosa cells that remains attached to the zona pellucida after ovulation; sperm must penetrate it.',
  'Corona radiată este stratul de celule granuloase care rămâne atașat de zona pelucidă după ovulație; spermatozoizii trebuie să-l penetreze.',
  'repro-female',
  6
) ON CONFLICT (id) DO UPDATE SET
