INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF53',
  'med-admission-barrons',
  'hard',
  'What is menorrhagia?',
  'Ce este menoragia?',
  '["Absence of periods","Abnormally heavy or prolonged menstrual bleeding","Painful periods","Irregular periods","Spotting between periods"]'::jsonb,
  '["Absența menstruației","Sângerare menstruală anormal de abundentă sau prelungită","Perioade dureroase","Perioade neregulate","Spotting între perioade"]'::jsonb,
  1,
  'Menorrhagia is heavy menstrual bleeding (>80 mL) or periods lasting >7 days, which can lead to anemia.',
  'Menoragia este sângerare menstruală abundentă (>80 mL) sau perioade care durează >7 zile, care pot duce la anemie.',
