INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF54',
  'med-admission-barrons',
  'hard',
  'What is metrorrhagia?',
  'Ce este metroragia?',
  '["Heavy periods","Irregular bleeding between normal menstrual periods","Painful periods","No periods","Heavy periods with clots"]'::jsonb,
  '["Perioade abundente","Sângerare neregulată între perioadele menstruale normale","Perioade dureroase","Fără perioade","Perioade abundente cu cheaguri"]'::jsonb,
  1,
  'Metrorrhagia is uterine bleeding at irregular intervals, especially between expected menstrual periods.',
  'Metroragia este sângerare uterină la intervale neregulate, mai ales între perioadele menstruale așteptate.',
