INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF55',
  'med-admission-barrons',
  'hard',
  'What is the mechanism of action of combined oral contraceptives?',
  'Care este mecanismul de acțiune al contraceptivelor orale combinate?',
  '["Kill sperm","Inhibit ovulation, thicken cervical mucus, thin endometrium","Block fallopian tubes","Prevent implantation only","Stimulate menstruation"]'::jsonb,
  '["Ucid spermatozoizii","Inhibă ovulația, îngroașă mucusul cervical, subțiază endometrul","Blochează trompele uterine","Previn doar implantarea","Stimulează menstruația"]'::jsonb,
  1,
  'Combined oral contraceptives prevent pregnancy by suppressing ovulation (via negative feedback), thickening cervical mucus, and making endometrium less receptive.',
  'Contraceptivele orale combinate previn sarcina prin suprimarea ovulației (prin feedback negativ), îngroșarea mucusului cervical și făcând endometrul mai puțin receptiv.',
  'repro-female',
  6
) ON CONFLICT (id) DO UPDATE SET
