  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF56',
  'med-admission-barrons',
  'hard',
  'What is endometrial hyperplasia?',
  'Ce este hiperplazia endometrială?',
  '["Thin endometrium","Abnormal thickening of endometrium due to excess estrogen","Endometrial cancer","Normal menstruation","Endometriosis"]'::jsonb,
  '["Endometru subțire","Îngroșare anormală a endometrului din cauza excesului de estrogen","Cancer endometrial","Menstruație normală","Endometrioză"]'::jsonb,
  1,
  'Endometrial hyperplasia is abnormal proliferation of endometrial glands due to prolonged unopposed estrogen; it can progress to cancer.',
  'Hiperplazia endometrială este proliferarea anormală a glandelor endometriale din cauza estrogenului necontrariat prelungit; poate progresa spre cancer.',
  'repro-female',
  6
) ON CONFLICT (id) DO UPDATE SET
