  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF57',
  'med-admission-barrons',
  'hard',
  'What is adenomyosis?',
  'Ce este adenomioza?',
  '["Endometrial tissue in ovary","Endometrial tissue within myometrium (uterine muscle)","Uterine cancer","Cervical polyp","Vaginal infection"]'::jsonb,
  '["Țesut endometrial în ovar","Țesut endometrial în miometru (mușchiul uterin)","Cancer uterin","Polip cervical","Infecție vaginală"]'::jsonb,
  1,
  'Adenomyosis is the presence of endometrial glands and stroma within the myometrium, causing an enlarged, tender uterus and heavy periods.',
  'Adenomioza este prezența glandelor și stromei endometriale în miometru, cauzând un uter mărit, sensibil și perioade abundente.',
