INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF58',
  'med-admission-barrons',
  'hard',
  'What are uterine leiomyomas (fibroids)?',
  'Ce sunt leiomioamele uterine (fibroamele)?',
  '["Cancerous tumors","Benign smooth muscle tumors of the myometrium","Ovarian cysts","Endometrial polyps","Cervical cancer"]'::jsonb,
  '["Tumori canceroase","Tumori benigne ale mușchiului neted din miometru","Chisturi ovariene","Polipi endometriali","Cancer cervical"]'::jsonb,
  1,
  'Leiomyomas (fibroids) are benign tumors of uterine smooth muscle, the most common pelvic tumors in women.',
  'Leiomioamele (fibroamele) sunt tumori benigne ale mușchiului neted uterin, cele mai frecvente tumori pelvine la femei.',
