INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF59',
  'med-admission-barrons',
  'hard',
  'What is the most common cause of female infertility?',
  'Care este cea mai frecventă cauză de infertilitate feminină?',
  '["Uterine abnormalities","Ovulatory dysfunction","Cervical factors","Vaginal obstruction","Hormonal excess"]'::jsonb,
  '["Anomalii uterine","Disfuncție ovulatorie","Factori cervicali","Obstrucție vaginală","Exces hormonal"]'::jsonb,
  1,
  'Ovulatory dysfunction (anovulation or irregular ovulation) is the most common cause of female infertility, often due to PCOS or hypothalamic issues.',
  'Disfuncția ovulatorie (anovulație sau ovulație neregulată) este cea mai frecventă cauză de infertilitate feminină, adesea din cauza SOPC sau problemelor hipotalamice.',
  'repro-female',
  6
) ON CONFLICT (id) DO UPDATE SET
