  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF60',
  'med-admission-barrons',
  'hard',
  'What is pelvic inflammatory disease (PID)?',
  'Ce este boala inflamatorie pelvină (BIP)?',
  '["Urinary tract infection","Infection of upper female genital tract (uterus, tubes, ovaries)","Vaginal yeast infection","Cervical cancer","Endometriosis"]'::jsonb,
  '["Infecție a tractului urinar","Infecție a tractului genital superior feminin (uter, trompe, ovare)","Infecție vaginală cu drojdii","Cancer cervical","Endometrioză"]'::jsonb,
  1,
  'PID is infection of the upper female reproductive tract, usually from ascending STIs (chlamydia, gonorrhea), which can cause infertility and ectopic pregnancy.',
  'BIP este infecția tractului reproductiv superior feminin, de obicei din ITS ascendente (chlamydia, gonoree), care poate cauza infertilitate și sarcină ectopică.',
  'repro-female',
  6
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

-- Set 7 (Hard)
INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF61',
  'med-admission-barrons',
  'hard',
  'What is ectopic pregnancy?',
  'Ce este sarcina ectopică?',
  '["Normal pregnancy","Implantation outside the uterine cavity, usually in fallopian tube","Twin pregnancy","Molar pregnancy","Late pregnancy"]'::jsonb,
  '["Sarcină normală","Implantare în afara cavității uterine, de obicei în trompa uterină","Sarcină gemelară","Sarcină molară","Sarcină tardivă"]'::jsonb,
  1,
  'Ectopic pregnancy is implantation outside the uterus (95% in fallopian tubes); it is a medical emergency as tube rupture causes life-threatening bleeding.',
  'Sarcina ectopică este implantarea în afara uterului (95% în trompele uterine); este o urgență medicală deoarece ruptura trompei cauzează sângerare care pune viața în pericol.',
  'repro-female',
  7
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
