  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF62',
  'med-admission-barrons',
  'hard',
  'What is the function of inhibin B from granulosa cells?',
  'Care este funcția inhibinei B din celulele granuloase?',
  '["Stimulates FSH","Inhibits FSH release via negative feedback","Stimulates LH","Causes ovulation","Stimulates estrogen"]'::jsonb,
  '["Stimulează FSH","Inhibă eliberarea FSH prin feedback negativ","Stimulează LH","Cauzează ovulația","Stimulează estrogenul"]'::jsonb,
  1,
  'Inhibin B from granulosa cells provides negative feedback to the pituitary, selectively inhibiting FSH secretion.',
  'Inhibina B din celulele granuloase oferă feedback negativ hipofizei, inhibând selectiv secreția de FSH.',
  'repro-female',
  7
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
