  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF63',
  'med-admission-barrons',
  'hard',
  'What triggers the LH surge for ovulation?',
  'Ce declanșează creșterea bruscă a LH pentru ovulație?',
  '["Low estrogen","High sustained estrogen levels (positive feedback)","Progesterone peak","FSH decline","Prolactin release"]'::jsonb,
  '["Estrogen scăzut","Niveluri ridicate susținute de estrogen (feedback pozitiv)","Vârful de progesteron","Declinul FSH","Eliberarea prolactinei"]'::jsonb,
  1,
  'When estrogen reaches a critical threshold and is sustained for about 36 hours, it switches from negative to positive feedback, triggering the LH surge.',
  'Când estrogenul atinge un prag critic și este susținut aproximativ 36 ore, trece de la feedback negativ la pozitiv, declanșând creșterea bruscă a LH.',
  'repro-female',
  7
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF64',
  'med-admission-barrons',
  'hard',
  'What is mittelschmerz?',
  'Ce este mittelschmerz?',
  '["Painful menstruation","Mid-cycle pain associated with ovulation","Implantation pain","Labor pain","Postmenstrual pain"]'::jsonb,
  '["Menstruație dureroasă","Durere la mijlocul ciclului asociată cu ovulația","Durere de implantare","Durere de travaliu","Durere postmenstruală"]'::jsonb,
  1,
  'Mittelschmerz is one-sided lower abdominal pain occurring at ovulation, caused by follicular rupture or fluid irritating the peritoneum.',
  'Mittelschmerz este durere abdominală inferioară unilaterală care apare la ovulație, cauzată de ruptura foliculară sau lichid care iritează peritoneul.',
  'repro-female',
  7
) ON CONFLICT (id) DO UPDATE SET
