INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF65',
  'med-admission-barrons',
  'hard',
  'What is the Graafian follicle?',
  'Ce este foliculul Graaf?',
  '["Primordial follicle","Mature preovulatory follicle","Corpus luteum","Corpus albicans","Atretic follicle"]'::jsonb,
  '["Folicul primordial","Folicul matur preovulator","Corp galben","Corp albicans","Folicul atretic"]'::jsonb,
  1,
  'The Graafian (tertiary/mature) follicle is the fully developed follicle ready to release its oocyte at ovulation, containing a fluid-filled antrum.',
  'Foliculul Graaf (terțiar/matur) este foliculul complet dezvoltat gata să elibereze ovocitul la ovulație, conținând un antru plin cu lichid.',
  'repro-female',
  7
) ON CONFLICT (id) DO UPDATE SET
