  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF66',
  'med-admission-barrons',
  'hard',
  'What happens to the oocyte at fertilization regarding meiosis?',
  'Ce se întâmplă cu ovocitul la fertilizare în ceea ce privește meioza?',
  '["Meiosis begins","Meiosis II completes","Mitosis occurs","Meiosis stops permanently","Meiosis I begins"]'::jsonb,
  '["Meioza începe","Meioza II se completează","Mitoza are loc","Meioza se oprește permanent","Meioza I începe"]'::jsonb,
  1,
  'At ovulation, meiosis I completes; the secondary oocyte arrests in metaphase II until sperm penetration triggers completion of meiosis II.',
  'La ovulație, meioza I se completează; ovocitul secundar se blochează în metafaza II până când penetrarea spermatozoidului declanșează completarea meiozei II.',
  'repro-female',
  7
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF67',
  'med-admission-barrons',
  'hard',
  'What is the vulva?',
  'Ce este vulva?',
  '["Internal reproductive organs","External female genitalia (labia, clitoris, vestibule)","The vagina","The uterus","The ovaries"]'::jsonb,
  '["Organe reproductive interne","Organele genitale externe feminine (labii, clitoris, vestibul)","Vaginul","Uterul","Ovarele"]'::jsonb,
  1,
  'The vulva includes all external female genitalia: mons pubis, labia majora and minora, clitoris, vestibule, and vestibular glands.',
  'Vulva include toate organele genitale externe feminine: muntele pubian, labiile mari și mici, clitorisul, vestibulul și glandele vestibulare.',
  'repro-female',
  7
) ON CONFLICT (id) DO UPDATE SET
