INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF68',
  'med-admission-barrons',
  'hard',
  'What is the homologous structure to the penis in females?',
  'Care este structura omologă penisului la femei?',
  '["Labia majora","Clitoris","Vagina","Uterus","Labia minora"]'::jsonb,
  '["Labiile mari","Clitorisul","Vaginul","Uterul","Labiile mici"]'::jsonb,
  1,
  'The clitoris is homologous to the penis, developing from the same embryonic tissue (genital tubercle) and containing erectile tissue.',
  'Clitorisul este omolog penisului, dezvoltându-se din același țesut embrionar (tubercul genital) și conținând țesut erectil.',
