INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF70',
  'med-admission-barrons',
  'hard',
  'What hormone changes occur during menopause?',
  'Ce schimbări hormonale apar în timpul menopauzei?',
  '["Increased estrogen and progesterone","Decreased estrogen/progesterone, increased FSH/LH","Increased all hormones","No hormonal changes","Decreased FSH only"]'::jsonb,
  '["Estrogen și progesteron crescute","Estrogen/progesteron scăzute, FSH/LH crescute","Toți hormonii crescuți","Fără schimbări hormonale","Doar FSH scăzut"]'::jsonb,
  1,
  'Menopause involves declining ovarian function with decreased estrogen and progesterone, and elevated FSH and LH due to loss of negative feedback.',
  'Menopauza implică declinul funcției ovariene cu estrogen și progesteron scăzute, și FSH și LH ridicate din cauza pierderii feedback-ului negativ.',
  'repro-female',
  7
) ON CONFLICT (id) DO UPDATE SET
