INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF71',
  'med-admission-barrons',
  'hard',
  'What is the function of relaxin during pregnancy?',
  'Care este funcția relaxinei în timpul sarcinii?',
  '["Stimulates labor","Relaxes pelvic ligaments and softens cervix for delivery","Stimulates breast milk","Maintains blood pressure","Stimulates fetal growth"]'::jsonb,
  '["Stimulează travaliul","Relaxează ligamentele pelvine și înmoaie colul uterin pentru naștere","Stimulează laptele matern","Menține tensiunea arterială","Stimulează creșterea fetală"]'::jsonb,
  1,
  'Relaxin softens the cervix and relaxes pelvic ligaments to widen the birth canal, and inhibits uterine contractions during pregnancy.',
  'Relaxina înmoaie colul uterin și relaxează ligamentele pelvine pentru a lărgi canalul de naștere, și inhibă contracțiile uterine în timpul sarcinii.',
  'repro-female',
  8
) ON CONFLICT (id) DO UPDATE SET
