INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF73',
  'med-admission-barrons',
  'hard',
  'What is the vaginal pH and why is it important?',
  'Care este pH-ul vaginal și de ce este important?',
  '["Alkaline pH 8-9","Acidic pH 3.8-4.5, maintained by lactobacilli, protects against infection","Neutral pH 7","Variable pH 2-10","Alkaline pH for sperm survival"]'::jsonb,
  '["pH alcalin 8-9","pH acid 3,8-4,5, menținut de lactobacili, protejează împotriva infecției","pH neutru 7","pH variabil 2-10","pH alcalin pentru supraviețuirea spermatozoizilor"]'::jsonb,
  1,
  'Vaginal pH is acidic (3.8-4.5) due to lactic acid produced by lactobacilli, which protects against pathogenic bacteria and yeast.',
  'pH-ul vaginal este acid (3,8-4,5) datorită acidului lactic produs de lactobacili, care protejează împotriva bacteriilor patogene și drojdiilor.',
  'repro-female',
  8
) ON CONFLICT (id) DO UPDATE SET
