INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF79',
  'med-admission-barrons',
  'hard',
  'What is the clinical significance of the relationship between uterine artery and ureter?',
  'Care este semnificația clinică a relației dintre artera uterină și ureter?',
  '["No clinical significance","Ureter can be injured during hysterectomy when ligating uterine artery","Artery supplies ureter","Ureter supplies uterus","They do not cross"]'::jsonb,
  '["Fără semnificație clinică","Ureterul poate fi lezat în timpul histerectomiei când se ligaturează artera uterină","Artera alimentează ureterul","Ureterul alimentează uterul","Nu se încrucișează"]'::jsonb,
  1,
  'The uterine artery crosses over the ureter approximately 2 cm lateral to the cervix; the ureter is at risk of injury during hysterectomy.',
  'Artera uterină trece peste ureter la aproximativ 2 cm lateral de col; ureterul este în pericol de lezare în timpul histerectomiei.',
  'repro-female',
  8
) ON CONFLICT (id) DO UPDATE SET
