  'repF83',
  'med-admission-barrons',
  'hard',
  'What is the most common gynecological malignancy?',
  'Care este cea mai frecventă afecțiune malignă ginecologică?',
  '["Cervical cancer","Endometrial (uterine) cancer","Ovarian cancer","Vulvar cancer","Vaginal cancer"]'::jsonb,
  '["Cancer cervical","Cancer endometrial (uterin)","Cancer ovarian","Cancer vulvar","Cancer vaginal"]'::jsonb,
  1,
  'Endometrial cancer is the most common gynecological malignancy in developed countries, often presenting with postmenopausal bleeding.',
  'Cancerul endometrial este cea mai frecventă afecțiune malignă ginecologică în țările dezvoltate, prezentându-se adesea cu sângerare postmenopauzală.',
  'repro-female',
  9
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
