INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF93',
  'med-admission-barrons',
  'hard',
  'What is the difference between primary and secondary amenorrhea?',
  'Care este diferența dintre amenoreea primară și secundară?',
  '["No difference","Primary: never had periods; Secondary: periods stopped after previous occurrence","Primary is more serious","Secondary occurs earlier in life","Primary is always pathological"]'::jsonb,
  '["Nicio diferență","Primară: nu a avut niciodată perioade; Secundară: perioadele s-au oprit după ce au avut loc anterior","Primara este mai gravă","Secundara apare mai devreme în viață","Primara este întotdeauna patologică"]'::jsonb,
  1,
  'Primary amenorrhea is absence of menarche by age 15; secondary is cessation of periods for ≥3 months after previously normal cycles.',
  'Amenoreea primară este absența menarhei până la 15 ani; secundara este încetarea perioadelor pentru ≥3 luni după cicluri anterioare normale.',
  'repro-female',
  10
) ON CONFLICT (id) DO UPDATE SET
