INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'repF98',
  'med-admission-barrons',
  'hard',
  'What is dysfunctional uterine bleeding (DUB)?',
  'Ce este sângerarea uterină disfuncțională (SUD)?',
  '["Normal menstruation","Abnormal uterine bleeding without organic pathology, usually anovulatory","Cancer bleeding","Pregnancy bleeding","Infection bleeding"]'::jsonb,
  '["Menstruație normală","Sângerare uterină anormală fără patologie organică, de obicei anovulatorie","Sângerare din cancer","Sângerare din sarcină","Sângerare din infecție"]'::jsonb,
  1,
  'DUB (now called abnormal uterine bleeding-ovulatory dysfunction) is irregular bleeding without structural cause, often due to anovulation.',
  'SUD (acum numită sângerare uterină anormală-disfuncție ovulatorie) este sângerare neregulată fără cauză structurală, adesea din cauza anovulației.',
  'repro-female',
