  '["Amnion","Placentă","Sacul vitelin","Doar cordonul ombilical (fără placentă)","Doar corion"]'::jsonb,
  1,
  'The placenta is the organ that forms from fetal and maternal tissues; it allows gas, nutrient, and waste exchange and produces hormones.',
  'Placenta este organul format din țesuturi fetale și materne; permite schimbul de gaze, nutrienți și deșeuri și produce hormoni.',
  'embryology',
  1
) ON CONFLICT (id) DO UPDATE SET
