INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb3',
  'med-admission-barrons',
  'easy',
  'Which germ layer gives rise to the nervous system and the epidermis of the skin?',
  'Care strat germinal dă naștere sistemului nervos și epidermei pielii?',
  '["Endoderm","Mesoderm","Ectoderm","Trophoblast","Hypoblast"]'::jsonb,
  '["Endoderm","Mezoderm","Ectoderm","Trofoblast","Hypoblast"]'::jsonb,
  2,
  'The ectoderm gives rise to the epidermis, nervous system (brain, spinal cord, nerves), and some other structures.',
  'Ectodermul dă naștere epidermei, sistemului nervos (creier, măduvă spinării, nervi) și unor alte structuri.',
  'embryology',
  1
) ON CONFLICT (id) DO UPDATE SET
