INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb4',
  'med-admission-barrons',
  'medium',
  'Which germ layer gives rise to the muscles, bones, cardiovascular system, and kidneys?',
  'Care strat germinal dă naștere mușchilor, oaselor, sistemului cardiovascular și rinichilor?',
  '["Ectoderm","Endoderm","Mesoderm","Trophoblast","Epiblast"]'::jsonb,
  '["Ectoderm","Endoderm","Mezoderm","Trofoblast","Epiblast"]'::jsonb,
  2,
  'The mesoderm gives rise to muscle, bone, connective tissue, the heart and blood vessels, kidneys, and parts of the reproductive system.',
  'Mezodermul dă naștere mușchilor, oaselor, țesutului conjunctiv, inimii și vaselor, rinichilor și părților sistemului reproducător.',
  'embryology',
  1
) ON CONFLICT (id) DO UPDATE SET
