INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb5',
  'med-admission-barrons',
  'medium',
  'Which structure surrounds the embryo and fetus and is filled with amniotic fluid?',
  'Care structură înconjoară embrionul și fetusul și este umplută cu lichid amniotic?',
  '["Placenta","Yolk sac","Amniotic sac (amnion)","Chorion only","Allantois"]'::jsonb,
  '["Placentă","Sacul vitelin","Sacul amniotic (amnion)","Doar corion","Alantois"]'::jsonb,
  2,
  'The amniotic sac (formed by the amnion) contains amniotic fluid, which cushions the fetus and allows movement and development.',
  'Sacul amniotic (format de amnion) conține lichidul amniotic, care amortizează fetusul și permite mișcarea și dezvoltarea.',
  'embryology',
  1
) ON CONFLICT (id) DO UPDATE SET
