  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb6',
  'med-admission-barrons',
  'medium',
  'What is the process by which the three germ layers (ectoderm, mesoderm, endoderm) are formed?',
  'Care este procesul prin care se formează cele trei straturi germinale (ectoderm, mezoderm, endoderm)?',
  '["Cleavage","Gastrulation","Neurulation","Implantation","Organogenesis only"]'::jsonb,
  '["Segmentare","Gastrulare","Neurulare","Implantare","Doar organogeneză"]'::jsonb,
  1,
  'Gastrulation is the process during which the embryo forms the three germ layers (ectoderm, mesoderm, endoderm) that give rise to all tissues.',
  'Gastrularea este procesul în timpul căruia embrionul formează cele trei straturi germinale care dau naștere tuturor țesuturilor.',
  'embryology',
  1
) ON CONFLICT (id) DO UPDATE SET
