  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb7',
  'med-admission-barrons',
  'medium',
  'Which germ layer gives rise to the lining of the digestive tract, respiratory tract, and associated glands (e.g., liver, pancreas)?',
  'Care strat germinal dă naștere mucoasei tractului digestiv, a tractului respirator și glandelor asociate (ex. ficat, pancreas)?',
  '["Ectoderm","Mesoderm","Endoderm","Trophoblast","Mesenchyme"]'::jsonb,
  '["Ectoderm","Mezoderm","Endoderm","Trofoblast","Mezenchim"]'::jsonb,
  2,
  'The endoderm forms the epithelial lining of the gut, respiratory tract, and derivatives such as the liver, pancreas, and thyroid.',
  'Endodermul formează mucoasa epitelială a intestinului, tractului respirator și derivate precum ficatul, pancreasul și tiroida.',
  'embryology',
  1
) ON CONFLICT (id) DO UPDATE SET
