  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb8',
  'med-admission-barrons',
  'hard',
  'At what stage does the embryo typically implant into the uterine endometrium?',
  'În ce stadiu embrionul se implantează de obicei în endometrul uterin?',
  '["At the zygote stage","At the morula stage","At the blastocyst stage","At the gastrula stage","After organogenesis"]'::jsonb,
  '["În stadiul de zigot","În stadiul de morulă","În stadiul de blastocist","În stadiul de gastrulă","După organogeneză"]'::jsonb,
  2,
  'Implantation usually occurs when the embryo is a blastocyst; the blastocyst attaches to and invades the endometrium about 6–7 days after fertilization.',
  'Implantarea are loc de obicei când embrionul este un blastocist; blastocistul se atașează și invadează endometrul la circa 6–7 zile după fertilizare.',
  'embryology',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb9',
  'med-admission-barrons',
  'hard',
  'What is the inner cell mass of the blastocyst destined to become?',
  'Ce este destinat să devină masa celulară internă a blastocistului?',
  '["The placenta only","The embryo proper (and later the fetus)","The amniotic sac only","The trophoblast only","The yolk sac only"]'::jsonb,
  '["Doar placentă","Embrionul propriu-zis (și mai târziu fetusul)","Doar sacul amniotic","Doar trofoblastul","Doar sacul vitelin"]'::jsonb,
  1,
  'The inner cell mass (embryoblast) of the blastocyst gives rise to the embryo and later the fetus; the trophoblast contributes to the placenta.',
  'Masa celulară internă (embrioblast) a blastocistului dă naștere embrionului și mai târziu fetusului; trofoblastul contribuie la placentă.',
  'embryology',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb10',
  'med-admission-barrons',
  'hard',
  'Which process leads to the formation of the neural tube, which will become the brain and spinal cord?',
  'Care proces conduce la formarea tubului neural, care va deveni creierul și măduva spinării?',
  '["Gastrulation","Neurulation","Implantation","Cleavage","Placentation"]'::jsonb,
  '["Gastrulare","Neurulare","Implantare","Segmentare","Placentare"]'::jsonb,
  1,
  'Neurulation is the process by which the neural plate folds to form the neural tube, the precursor of the central nervous system.',
  'Neurularea este procesul prin care placa neurală se pliază pentru a forma tubul neural, precursorul sistemului nervos central.',
  'embryology',
  1
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
