  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

-- Set 2 (Easy)
INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb11',
  'med-admission-barrons',
  'easy',
  'What is the term for the developing organism from fertilization to the end of week 8?',
  'Cum se numește organismul în dezvoltare de la fertilizare până la sfârșitul săptămânii 8?',
  '["Fetus","Embryo","Neonate","Infant","Zygote only"]'::jsonb,
  '["Făt","Embrion","Nou-născut","Sugar","Doar zigot"]'::jsonb,
  1,
  'The developing organism is called an embryo from fertilization through week 8; from week 9 until birth it is called a fetus.',
  'Organismul în dezvoltare se numește embrion de la fertilizare până în săptămâna 8; din săptămâna 9 până la naștere se numește făt.',
  'embryology',
  2
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
