  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb12',
  'med-admission-barrons',
  'easy',
  'What forms from the inner cell mass of the blastocyst?',
  'Ce se formează din masa celulară internă a blastocistului?',
  '["Placenta","Embryo proper","Chorion","Amnion only","Umbilical cord"]'::jsonb,
  '["Placentă","Embrionul propriu-zis","Corion","Doar amnios","Cordon ombilical"]'::jsonb,
  1,
  'The inner cell mass (embryoblast) gives rise to the embryo proper and some extraembryonic membranes; the outer trophoblast forms the placenta.',
  'Masa celulară internă (embrioblast) dă naștere embrionului propriu-zis și unor membrane extraembrionare; trofoblastul extern formează placenta.',
  'embryology',
  2
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
