  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb13',
  'med-admission-barrons',
  'easy',
  'Where does implantation normally occur?',
  'Unde are loc în mod normal implantarea?',
  '["Fallopian tube","Posterior wall of uterine body","Cervix","Ovary","Vagina"]'::jsonb,
  '["Trompa uterină","Peretele posterior al corpului uterin","Colul uterin","Ovar","Vagin"]'::jsonb,
  1,
  'Normal implantation occurs in the endometrium of the uterine body, usually on the posterior wall.',
  'Implantarea normală are loc în endometrul corpului uterin, de obicei pe peretele posterior.',
  'embryology',
  2
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
