  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb14',
  'med-admission-barrons',
  'easy',
  'What is the function of the placenta?',
  'Care este funcția placentei?',
  '["Only produces hormones","Exchange of gases, nutrients, and wastes between mother and fetus","Stores fetal blood","Produces fetal urine","Forms the umbilical cord"]'::jsonb,
  '["Doar produce hormoni","Schimb de gaze, nutrienți și deșeuri între mamă și făt","Stochează sângele fetal","Produce urina fetală","Formează cordonul ombilical"]'::jsonb,
  1,
  'The placenta provides exchange of oxygen, nutrients, and wastes, produces hormones (hCG, progesterone, estrogen), and provides immunological protection.',
  'Placenta asigură schimbul de oxigen, nutrienți și deșeuri, produce hormoni (hCG, progesteron, estrogen) și oferă protecție imunologică.',
  'embryology',
  2
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb15',
  'med-admission-barrons',
  'easy',
  'How many vessels are in a normal umbilical cord?',
  'Câte vase sunt într-un cordon ombilical normal?',
  '["One artery, one vein","Two arteries, one vein","One artery, two veins","Two arteries, two veins","Three veins"]'::jsonb,
  '["O arteră, o venă","Două artere, o venă","O arteră, două vene","Două artere, două vene","Trei vene"]'::jsonb,
  1,
  'A normal umbilical cord contains two arteries (carrying deoxygenated blood to placenta) and one vein (carrying oxygenated blood to fetus).',
  'Un cordon ombilical normal conține două artere (transportând sânge dezoxigenat la placentă) și o venă (transportând sânge oxigenat la făt).',
  'embryology',
  2
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb16',
  'med-admission-barrons',
  'easy',
  'What is the amniotic fluid?',
  'Ce este lichidul amniotic?',
  '["Maternal blood","Fluid surrounding the fetus within the amnion","Placental secretion only","Fetal blood","Uterine mucus"]'::jsonb,
  '["Sânge matern","Lichid care înconjoară fătul în amnios","Doar secreție placentară","Sânge fetal","Mucus uterin"]'::jsonb,
  1,
  'Amniotic fluid cushions the fetus, maintains temperature, allows movement for development, and prevents adhesions.',
  'Lichidul amniotic amortizează fătul, menține temperatura, permite mișcarea pentru dezvoltare și previne aderențele.',
  'embryology',
  2
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
