  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb17',
  'med-admission-barrons',
  'easy',
  'What is the normal duration of human pregnancy?',
  'Care este durata normală a sarcinii umane?',
  '["32 weeks","36 weeks","40 weeks (280 days)","44 weeks","48 weeks"]'::jsonb,
  '["32 săptămâni","36 săptămâni","40 săptămâni (280 zile)","44 săptămâni","48 săptămâni"]'::jsonb,
  2,
  'Normal pregnancy duration is approximately 40 weeks (280 days) from the last menstrual period, or 38 weeks from conception.',
  'Durata normală a sarcinii este aproximativ 40 săptămâni (280 zile) de la ultima menstruație, sau 38 săptămâni de la concepție.',
  'embryology',
  2
) ON CONFLICT (id) DO UPDATE SET
