  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb18',
  'med-admission-barrons',
  'easy',
  'What is colostrum?',
  'Ce este colostrul?',
  '["Mature breast milk","First milk produced, rich in antibodies","Placental secretion","Amniotic fluid","Vaginal discharge"]'::jsonb,
  '["Lapte matern matur","Primul lapte produs, bogat în anticorpi","Secreție placentară","Lichid amniotic","Secreție vaginală"]'::jsonb,
  1,
  'Colostrum is the first milk produced after birth, rich in antibodies (especially IgA) that provide passive immunity to the newborn.',
  'Colostrul este primul lapte produs după naștere, bogat în anticorpi (în special IgA) care oferă imunitate pasivă nou-născutului.',
  'embryology',
  2
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
