  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb19',
  'med-admission-barrons',
  'easy',
  'What is the function of hCG in early pregnancy?',
  'Care este funcția hCG în sarcina timpurie?',
  '["Stimulates labor","Maintains corpus luteum to produce progesterone","Causes implantation","Triggers ovulation","Produces milk"]'::jsonb,
  '["Stimulează travaliul","Menține corpul galben să producă progesteron","Cauzează implantarea","Declanșează ovulația","Produce lapte"]'::jsonb,
  1,
  'hCG from the trophoblast maintains the corpus luteum, ensuring continued progesterone production until the placenta takes over.',
  'hCG de la trofoblast menține corpul galben, asigurând producția continuă de progesteron până când placenta preia.',
  'embryology',
  2
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
