  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb20',
  'med-admission-barrons',
  'easy',
  'What are the three trimesters of pregnancy?',
  'Care sunt cele trei trimestre ale sarcinii?',
  '["Weeks 1-10, 11-20, 21-40","Weeks 1-12, 13-28, 29-40","Weeks 1-8, 9-20, 21-40","Weeks 1-14, 15-28, 29-40","Months 1-2, 3-6, 7-9"]'::jsonb,
  '["Săptămânile 1-10, 11-20, 21-40","Săptămânile 1-12, 13-28, 29-40","Săptămânile 1-8, 9-20, 21-40","Săptămânile 1-14, 15-28, 29-40","Lunile 1-2, 3-6, 7-9"]'::jsonb,
  1,
  'Pregnancy is divided into first trimester (weeks 1-12), second trimester (weeks 13-28), and third trimester (weeks 29-40).',
  'Sarcina este împărțită în primul trimestru (săptămânile 1-12), al doilea trimestru (săptămânile 13-28) și al treilea trimestru (săptămânile 29-40).',
  'embryology',
  2
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

-- Set 3 (Easy)
INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb21',
  'med-admission-barrons',
  'medium',
  'What is the morula stage of development?',
  'Ce este stadiul de morulă al dezvoltării?',
  '["Single cell","Solid ball of 16-32 cells","Hollow ball with cavity","Two-layered disc","Three-layered structure"]'::jsonb,
  '["Celulă unică","Bilă solidă de 16-32 celule","Bilă goală cu cavitate","Disc cu două straturi","Structură cu trei straturi"]'::jsonb,
  1,
  'The morula is a solid ball of about 16-32 cells formed by day 3-4 after fertilization, before the blastocyst stage.',
  'Morula este o bilă solidă de aproximativ 16-32 celule formată în zilele 3-4 după fertilizare, înainte de stadiul de blastocist.',
  'embryology',
  3
) ON CONFLICT (id) DO UPDATE SET
