INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb23',
  'med-admission-barrons',
  'medium',
  'What is gastrulation?',
  'Ce este gastrulația?',
  '["Fertilization","Formation of three germ layers from bilaminar disc","Neural tube formation","Cell division","Implantation"]'::jsonb,
  '["Fertilizare","Formarea celor trei straturi germinale din discul bilaminar","Formarea tubului neural","Diviziune celulară","Implantare"]'::jsonb,
  1,
  'Gastrulation transforms the bilaminar embryonic disc into a trilaminar disc with ectoderm, mesoderm, and endoderm.',
  'Gastrulația transformă discul embrionar bilaminar într-un disc trilaminar cu ectoderm, mezoderm și endoderm.',
  'embryology',
  3
