INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb27',
  'med-admission-barrons',
  'medium',
  'What is the primitive streak?',
  'Ce este linia primitivă?',
  '["First blood vessel","Structure that initiates gastrulation and establishes body axes","Neural tube precursor","Heart tube","Somite"]'::jsonb,
  '["Primul vas de sânge","Structură care inițiază gastrulația și stabilește axele corpului","Precursorul tubului neural","Tubul cardiac","Somit"]'::jsonb,
  1,
  'The primitive streak is a groove that forms on the embryonic disc and is the site of gastrulation where cells migrate inward.',
