INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb28',
  'med-admission-barrons',
  'medium',
  'What is the notochord?',
  'Ce este notocordul?',
  '["Permanent structure","Rod-like structure that induces neural tube formation and becomes nucleus pulposus","Blood vessel","Nerve","Muscle"]'::jsonb,
  '["Structură permanentă","Structură în formă de tijă care induce formarea tubului neural și devine nucleus pulposus","Vas de sânge","Nerv","Mușchi"]'::jsonb,
  1,
  'The notochord induces neural tube formation, defines the body axis, and eventually becomes the nucleus pulposus of intervertebral discs.',
  'Notocordul induce formarea tubului neural, definește axa corpului și devine în cele din urmă nucleus pulposus al discurilor intervertebrale.',
