INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb30',
  'med-admission-barrons',
  'medium',
  'When does the heart begin to beat in the embryo?',
  'Când începe inima să bată în embrion?',
  '["Week 1","Week 3-4","Week 8","Week 12","Week 20"]'::jsonb,
  '["Săptămâna 1","Săptămâna 3-4","Săptămâna 8","Săptămâna 12","Săptămâna 20"]'::jsonb,
  1,
  'The heart begins beating around day 22-23 (week 3-4), making it the first functional organ in the embryo.',
  'Inima începe să bată în jurul zilelor 22-23 (săptămâna 3-4), făcând-o primul organ funcțional în embrion.',
