INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb31',
  'med-admission-barrons',
  'medium',
  'What is neural crest?',
  'Ce este creasta neurală?',
  '["Part of brain","Cells that migrate from neural tube to form diverse structures","Spinal cord","Meninges only","Blood vessels"]'::jsonb,
  '["Parte a creierului","Celule care migrează de la tubul neural pentru a forma structuri diverse","Măduvă spinării","Doar meninge","Vase de sânge"]'::jsonb,
  1,
  'Neural crest cells migrate throughout the body, forming melanocytes, peripheral nerves, adrenal medulla, craniofacial bones, and heart structures.',
  'Celulele crestei neurale migrează în tot corpul, formând melanocite, nervi periferici, medulara suprarenală, oase craniofaciale și structuri cardiace.',
