INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb32',
  'med-admission-barrons',
  'medium',
  'What is organogenesis?',
  'Ce este organogeneza?',
  '["Cell division","Formation and development of organs from germ layers","Fertilization","Implantation","Birth"]'::jsonb,
  '["Diviziune celulară","Formarea și dezvoltarea organelor din straturile germinale","Fertilizare","Implantare","Naștere"]'::jsonb,
  1,
  'Organogenesis is the process of organ formation occurring primarily during weeks 3-8, making this a critical period for teratogen exposure.',
  'Organogeneza este procesul de formare a organelor care are loc în principal în săptămânile 3-8, făcând aceasta o perioadă critică pentru expunerea la teratogeni.',
  'embryology',
  4
) ON CONFLICT (id) DO UPDATE SET
