  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb33',
  'med-admission-barrons',
  'medium',
  'What is a teratogen?',
  'Ce este un teratogen?',
  '["Normal hormone","Agent that causes birth defects","Beneficial nutrient","Immune cell","Growth factor"]'::jsonb,
  '["Hormon normal","Agent care cauzează defecte congenitale","Nutrient benefic","Celulă imunitară","Factor de creștere"]'::jsonb,
  1,
  'A teratogen is any agent (drug, chemical, infection, radiation) that can cause developmental abnormalities in the embryo or fetus.',
  'Un teratogen este orice agent (medicament, substanță chimică, infecție, radiație) care poate cauza anomalii de dezvoltare în embrion sau făt.',
  'embryology',
  4
) ON CONFLICT (id) DO UPDATE SET
