  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb34',
  'med-admission-barrons',
  'medium',
  'What are the stages of labor?',
  'Care sunt etapele travaliului?',
  '["Two stages","Three stages: cervical dilation, delivery of baby, delivery of placenta","Four stages","Five stages","One continuous stage"]'::jsonb,
  '["Două etape","Trei etape: dilatarea cervicală, nașterea copilului, nașterea placentei","Patru etape","Cinci etape","O singură etapă continuă"]'::jsonb,
  1,
  'Labor has three stages: Stage 1 (cervical dilation), Stage 2 (delivery of infant), and Stage 3 (delivery of placenta).',
  'Travaliul are trei etape: Etapa 1 (dilatarea cervicală), Etapa 2 (nașterea copilului) și Etapa 3 (nașterea placentei).',
  'embryology',
  4
) ON CONFLICT (id) DO UPDATE SET
