  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb35',
  'med-admission-barrons',
  'medium',
  'What hormone initiates labor?',
  'Ce hormon inițiază travaliul?',
  '["Estrogen alone","Oxytocin and prostaglandins","Progesterone","hCG","Prolactin"]'::jsonb,
  '["Doar estrogen","Oxitocină și prostaglandine","Progesteron","hCG","Prolactină"]'::jsonb,
  1,
  'Labor is initiated by rising oxytocin (from pituitary) and prostaglandins (from uterus and membranes), with declining progesterone.',
  'Travaliul este inițiat de creșterea oxitocinei (de la hipofiză) și prostaglandinelor (de la uter și membrane), cu scăderea progesteronului.',
  'embryology',
  4
) ON CONFLICT (id) DO UPDATE SET
