  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb36',
  'med-admission-barrons',
  'medium',
  'What is the function of surfactant in the fetal lungs?',
  'Care este funcția surfactantului în plămânii fetali?',
  '["Provides oxygen","Reduces surface tension allowing alveoli to expand","Filters blood","Produces mucus","Kills bacteria"]'::jsonb,
  '["Furnizează oxigen","Reduce tensiunea superficială permițând alveolelor să se expandeze","Filtrează sângele","Produce mucus","Ucide bacterii"]'::jsonb,
  1,
  'Surfactant, produced by type II pneumocytes starting around week 24, reduces alveolar surface tension, preventing collapse at birth.',
  'Surfactantul, produs de pneumocitele de tip II începând cu săptămâna 24, reduce tensiunea superficială alveolară, prevenind colapsul la naștere.',
  'embryology',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
