  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb37',
  'med-admission-barrons',
  'medium',
  'What is the ductus arteriosus?',
  'Ce este ductul arterial?',
  '["Vein to liver","Fetal shunt connecting pulmonary artery to aorta","Artery to placenta","Connection to umbilicus","Cardiac valve"]'::jsonb,
  '["Venă către ficat","Șunt fetal care conectează artera pulmonară la aortă","Arteră către placentă","Conexiune către ombelic","Valvă cardiacă"]'::jsonb,
  1,
  'The ductus arteriosus shunts blood from the pulmonary artery to the aorta, bypassing the non-functional fetal lungs.',
  'Ductul arterial șuntează sângele de la artera pulmonară la aortă, ocolind plămânii fetali nefuncționali.',
  'embryology',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
