  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb38',
  'med-admission-barrons',
  'medium',
  'What is the foramen ovale?',
  'Ce este foramen ovale?',
  '["Opening in brain","Fetal opening between right and left atria","Hole in diaphragm","Opening in skull","Valve in vein"]'::jsonb,
  '["Deschidere în creier","Deschidere fetală între atriul drept și stâng","Gaură în diafragm","Deschidere în craniu","Valvă în venă"]'::jsonb,
  1,
  'The foramen ovale is an opening between the atria that shunts oxygenated blood from the right atrium directly to the left atrium, bypassing the lungs.',
  'Foramen ovale este o deschidere între atrii care șuntează sângele oxigenat din atriul drept direct în atriul stâng, ocolind plămânii.',
  'embryology',
  4
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
