  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb39',
  'med-admission-barrons',
  'medium',
  'What happens to fetal circulation at birth?',
  'Ce se întâmplă cu circulația fetală la naștere?',
  '["No changes","Shunts close, lung circulation begins","Heart stops briefly","Blood flow reverses","New vessels form"]'::jsonb,
  '["Nicio schimbare","Șunturile se închid, circulația pulmonară începe","Inima se oprește scurt","Fluxul sanguin se inversează","Se formează vase noi"]'::jsonb,
  1,
  'At birth, the foramen ovale and ductus arteriosus close, lung circulation begins with first breath, and umbilical vessels close.',
  'La naștere, foramen ovale și ductul arterial se închid, circulația pulmonară începe cu prima respirație și vasele ombilicale se închid.',
  'embryology',
  4
) ON CONFLICT (id) DO UPDATE SET
