INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb42',
  'med-admission-barrons',
  'hard',
  'What is the critical period for neural tube development?',
  'Care este perioada critică pentru dezvoltarea tubului neural?',
  '["Week 1","Weeks 3-4","Weeks 8-12","Weeks 20-24","Third trimester"]'::jsonb,
  '["Săptămâna 1","Săptămânile 3-4","Săptămânile 8-12","Săptămânile 20-24","Al treilea trimestru"]'::jsonb,
  1,
  'The neural tube closes by day 28 (week 4); folic acid deficiency during this period can cause neural tube defects like spina bifida.',
  'Tubul neural se închide până în ziua 28 (săptămâna 4); deficiența de acid folic în această perioadă poate cauza defecte de tub neural precum spina bifida.',
  'embryology',
  5
) ON CONFLICT (id) DO UPDATE SET
