INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb43',
  'med-admission-barrons',
  'hard',
  'What is spina bifida?',
  'Ce este spina bifidă?',
  '["Heart defect","Neural tube defect with incomplete closure of vertebral arch","Kidney abnormality","Liver disease","Lung abnormality"]'::jsonb,
  '["Defect cardiac","Defect de tub neural cu închidere incompletă a arcului vertebral","Anomalie renală","Boală hepatică","Anomalie pulmonară"]'::jsonb,
  1,
  'Spina bifida is failure of the neural tube to close posteriorly, ranging from hidden (occulta) to severe with meningocele or myelomeningocele.',
  'Spina bifidă este eșecul tubului neural de a se închide posterior, variind de la ascuns (ocultă) la severă cu meningocel sau mielomeningocel.',
  'embryology',
  5
) ON CONFLICT (id) DO UPDATE SET
