INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb44',
  'med-admission-barrons',
  'hard',
  'What causes anencephaly?',
  'Ce cauzează anencefalia?',
  '["Heart defect","Failure of anterior neural tube closure","Kidney defect","Liver failure","Lung defect"]'::jsonb,
  '["Defect cardiac","Eșecul închiderii anterioare a tubului neural","Defect renal","Insuficiență hepatică","Defect pulmonar"]'::jsonb,
  1,
  'Anencephaly results from failure of the anterior neural tube to close, causing absence of brain and skull vault; it is incompatible with life.',
  'Anencefalia rezultă din eșecul închiderii anterioare a tubului neural, cauzând absența creierului și calotei craniene; este incompatibilă cu viața.',
  'embryology',
  5
