INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb45',
  'med-admission-barrons',
  'hard',
  'What is fetal alcohol syndrome?',
  'Ce este sindromul de alcoolism fetal?',
  '["Liver disease","Birth defects from maternal alcohol consumption including facial abnormalities and intellectual disability","Kidney defect","Heart murmur only","Skin condition"]'::jsonb,
  '["Boală hepatică","Defecte congenitale din consumul matern de alcool inclusiv anomalii faciale și dizabilitate intelectuală","Defect renal","Doar suflu cardiac","Afecțiune cutanată"]'::jsonb,
  1,
  'FAS includes growth restriction, facial abnormalities (smooth philtrum, thin upper lip), and CNS defects causing intellectual disability.',
  'SAF include restricție de creștere, anomalii faciale (filtru neted, buză superioară subțire) și defecte SNC cauzând dizabilitate intelectuală.',
