INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb46',
  'med-admission-barrons',
  'hard',
  'What is the TORCH complex?',
  'Ce este complexul TORCH?',
  '["Genetic disorders","Infections causing congenital defects: Toxoplasma, Other, Rubella, CMV, Herpes","Metabolic diseases","Chromosomal abnormalities","Nutritional deficiencies"]'::jsonb,
  '["Tulburări genetice","Infecții cauzând defecte congenitale: Toxoplasma, Altele, Rubeola, CMV, Herpes","Boli metabolice","Anomalii cromozomiale","Deficiențe nutriționale"]'::jsonb,
  1,
  'TORCH infections (Toxoplasma, Other [syphilis, HIV], Rubella, CMV, Herpes) can cross the placenta and cause congenital abnormalities.',
  'Infecțiile TORCH (Toxoplasma, Altele [sifilis, HIV], Rubeola, CMV, Herpes) pot traversa placenta și cauza anomalii congenitale.',
