INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb47',
  'med-admission-barrons',
  'hard',
  'What is congenital rubella syndrome?',
  'Ce este sindromul rubeolic congenital?',
  '["Skin rash only","Birth defects from maternal rubella including deafness, cataracts, heart defects","Liver disease","Kidney defect","Lung abnormality"]'::jsonb,
  '["Doar erupție cutanată","Defecte congenitale din rubeola maternă inclusiv surditate, cataractă, defecte cardiace","Boală hepatică","Defect renal","Anomalie pulmonară"]'::jsonb,
  1,
  'Congenital rubella syndrome causes the classic triad of sensorineural deafness, cataracts, and heart defects (especially patent ductus arteriosus).',
  'Sindromul rubeolic congenital cauzează triada clasică de surditate neurosenzorială, cataractă și defecte cardiace (în special ductus arteriosus patent).',
