INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb48',
  'med-admission-barrons',
  'hard',
  'What is preeclampsia?',
  'Ce este preeclampsia?',
  '["Normal pregnancy finding","Pregnancy hypertension with proteinuria after 20 weeks","Early labor","Placenta previa","Miscarriage"]'::jsonb,
  '["Constatare normală în sarcină","Hipertensiune de sarcină cu proteinurie după 20 săptămâni","Travaliu precoce","Placentă previa","Avort spontan"]'::jsonb,
  1,
  'Preeclampsia is new hypertension (≥140/90) with proteinuria or end-organ damage after 20 weeks of pregnancy; it can progress to eclampsia (seizures).',
  'Preeclampsia este hipertensiune nouă (≥140/90) cu proteinurie sau afectare de organ țintă după 20 săptămâni de sarcină; poate progresa în eclampsie (convulsii).',
  'embryology',
  5
) ON CONFLICT (id) DO UPDATE SET
