  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb49',
  'med-admission-barrons',
  'hard',
  'What is gestational diabetes?',
  'Ce este diabetul gestațional?',
  '["Type 1 diabetes in pregnancy","Glucose intolerance first diagnosed during pregnancy","Pre-existing diabetes","Fetal diabetes","Placental disorder"]'::jsonb,
  '["Diabet tip 1 în sarcină","Intoleranță la glucoză diagnosticată prima dată în sarcină","Diabet preexistent","Diabet fetal","Tulburare placentară"]'::jsonb,
  1,
  'Gestational diabetes is carbohydrate intolerance with onset during pregnancy, caused by placental hormones antagonizing insulin.',
  'Diabetul gestațional este intoleranță la carbohidrați cu debut în sarcină, cauzat de hormoni placentari care antagonizează insulina.',
  'embryology',
  5
) ON CONFLICT (id) DO UPDATE SET
