  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb50',
  'med-admission-barrons',
  'hard',
  'What is placenta previa?',
  'Ce este placenta previa?',
  '["Normal placental position","Placenta covering or near the internal cervical os","Placental abruption","Placental tumor","Absent placenta"]'::jsonb,
  '["Poziție placentară normală","Placentă care acoperă sau este aproape de orificiul cervical intern","Abrupție placentară","Tumoare placentară","Placentă absentă"]'::jsonb,
  1,
  'Placenta previa is abnormal implantation where the placenta partially or completely covers the internal cervical os, causing painless bleeding.',
  'Placenta previa este implantare anormală unde placenta acoperă parțial sau complet orificiul cervical intern, cauzând sângerare nedureroasă.',
  'embryology',
  5
) ON CONFLICT (id) DO UPDATE SET
