INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb51',
  'med-admission-barrons',
  'hard',
  'What is placental abruption?',
  'Ce este abrupția placentară?',
  '["Normal placental separation at birth","Premature separation of placenta from uterine wall","Placenta previa","Retained placenta","Placental tumor"]'::jsonb,
  '["Separarea placentară normală la naștere","Separarea prematură a placentei de peretele uterin","Placenta previa","Placentă reținută","Tumoare placentară"]'::jsonb,
  1,
  'Placental abruption is premature separation of a normally implanted placenta, causing painful bleeding and fetal compromise.',
  'Abrupția placentară este separarea prematură a unei placente normal implantate, cauzând sângerare dureroasă și compromitere fetală.',
