INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb53',
  'med-admission-barrons',
  'hard',
  'What causes cleft lip and palate?',
  'Ce cauzează despicătura labială și palatină?',
  '["Heart defect","Failure of facial processes to fuse","Lung abnormality","Kidney defect","Liver disease"]'::jsonb,
  '["Defect cardiac","Eșecul proceselor faciale de a fuziona","Anomalie pulmonară","Defect renal","Boală hepatică"]'::jsonb,
  1,
  'Cleft lip results from failure of maxillary and medial nasal processes to fuse; cleft palate from failure of palatine shelves to fuse.',
  'Despicătura labială rezultă din eșecul proceselor maxilare și nazale mediale de a fuziona; despicătura palatină din eșecul lamelor palatine de a fuziona.',
  'embryology',
  6
