INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb54',
  'med-admission-barrons',
  'hard',
  'What is oligohydramnios?',
  'Ce este oligohidramniosul?',
  '["Excess amniotic fluid","Decreased amniotic fluid","Normal fluid level","Bloody amniotic fluid","Infected fluid"]'::jsonb,
  '["Lichid amniotic în exces","Lichid amniotic scăzut","Nivel normal de lichid","Lichid amniotic sângeros","Lichid infectat"]'::jsonb,
  1,
  'Oligohydramnios is decreased amniotic fluid, often due to fetal renal problems or ruptured membranes, associated with pulmonary hypoplasia.',
  'Oligohidramniosul este lichid amniotic scăzut, adesea din cauza problemelor renale fetale sau membranelor rupte, asociat cu hipoplazie pulmonară.',
  'embryology',
  6
) ON CONFLICT (id) DO UPDATE SET
