  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb55',
  'med-admission-barrons',
  'hard',
  'What is polyhydramnios?',
  'Ce este polihidramniosul?',
  '["Decreased amniotic fluid","Excess amniotic fluid","Normal pregnancy","Bloody fluid","Absent fluid"]'::jsonb,
  '["Lichid amniotic scăzut","Lichid amniotic în exces","Sarcină normală","Lichid sângeros","Lichid absent"]'::jsonb,
  1,
  'Polyhydramnios is excess amniotic fluid, often due to fetal swallowing problems (esophageal atresia) or maternal diabetes.',
  'Polihidramniosul este lichid amniotic în exces, adesea din cauza problemelor de înghițire fetală (atrezie esofagiană) sau diabet matern.',
  'embryology',
  6
) ON CONFLICT (id) DO UPDATE SET
