INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb56',
  'med-admission-barrons',
  'hard',
  'What is the function of folic acid in pregnancy?',
  'Care este funcția acidului folic în sarcină?',
  '["Provides energy","Prevents neural tube defects","Causes labor","Produces breast milk","Maintains blood pressure"]'::jsonb,
  '["Furnizează energie","Previne defectele de tub neural","Cauzează travaliul","Produce lapte matern","Menține tensiunea arterială"]'::jsonb,
  1,
  'Folic acid is essential for DNA synthesis and neural tube closure; supplementation before and during early pregnancy prevents neural tube defects.',
  'Acidul folic este esențial pentru sinteza ADN și închiderea tubului neural; suplimentarea înainte și în timpul sarcinii timpurii previne defectele de tub neural.',
  'embryology',
  6
) ON CONFLICT (id) DO UPDATE SET
