  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb57',
  'med-admission-barrons',
  'hard',
  'What is amniocentesis?',
  'Ce este amniocenteza?',
  '["Blood test","Sampling amniotic fluid for fetal testing","Ultrasound","Urine test","Cervical exam"]'::jsonb,
  '["Analiză de sânge","Prelevare de lichid amniotic pentru testarea fetală","Ecografie","Test de urină","Examinare cervicală"]'::jsonb,
  1,
  'Amniocentesis is sampling amniotic fluid (usually at 15-20 weeks) for genetic testing, determining lung maturity, or other diagnostics.',
  'Amniocenteza este prelevarea lichidului amniotic (de obicei la 15-20 săptămâni) pentru testare genetică, determinarea maturității pulmonare sau alte diagnostice.',
  'embryology',
  6
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
