  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb58',
  'med-admission-barrons',
  'hard',
  'What is chorionic villus sampling (CVS)?',
  'Ce este biopsia de vilozități coriale (BVC)?',
  '["Blood test","Sampling placental tissue for early genetic testing","Amniotic fluid test","Cervical swab","Ultrasound"]'::jsonb,
  '["Analiză de sânge","Prelevare de țesut placentar pentru testare genetică timpurie","Test de lichid amniotic","Frotiu cervical","Ecografie"]'::jsonb,
  1,
  'CVS samples placental chorionic villi (10-13 weeks) for earlier genetic testing than amniocentesis, providing fetal chromosomal information.',
  'BVC prelevează vilozități coriale placentare (10-13 săptămâni) pentru testare genetică mai timpurie decât amniocenteza, furnizând informații cromozomiale fetale.',
  'embryology',
  6
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
