  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb59',
  'med-admission-barrons',
  'hard',
  'What is the lecithin/sphingomyelin (L/S) ratio used for?',
  'Pentru ce este folosit raportul lecitină/sfingomielină (L/S)?',
  '["Detecting infection","Assessing fetal lung maturity","Diagnosing genetic disorders","Measuring growth","Testing blood type"]'::jsonb,
  '["Detectarea infecției","Evaluarea maturității pulmonare fetale","Diagnosticarea tulburărilor genetice","Măsurarea creșterii","Testarea grupei sanguine"]'::jsonb,
  1,
  'L/S ratio ≥2 in amniotic fluid indicates mature fetal lungs with adequate surfactant production, reducing risk of respiratory distress syndrome.',
  'Raportul L/S ≥2 în lichidul amniotic indică plămâni fetali maturi cu producție adecvată de surfactant, reducând riscul de sindrom de detresă respiratorie.',
  'embryology',
  6
) ON CONFLICT (id) DO UPDATE SET
