  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb60',
  'med-admission-barrons',
  'hard',
  'What is trisomy 21 (Down syndrome)?',
  'Ce este trisomia 21 (sindromul Down)?',
  '["Missing chromosome","Three copies of chromosome 21 causing intellectual disability and characteristic features","Sex chromosome abnormality","Single gene disorder","Mitochondrial disease"]'::jsonb,
  '["Cromozom lipsă","Trei copii ale cromozomului 21 cauzând dizabilitate intelectuală și trăsături caracteristice","Anomalie de cromozom sexual","Tulburare cu o singură genă","Boală mitocondrială"]'::jsonb,
  1,
  'Down syndrome results from trisomy 21, causing characteristic facial features, intellectual disability, and increased risk of heart defects and leukemia.',
  'Sindromul Down rezultă din trisomia 21, cauzând trăsături faciale caracteristice, dizabilitate intelectuală și risc crescut de defecte cardiace și leucemie.',
  'embryology',
  6
) ON CONFLICT (id) DO UPDATE SET
