INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb63',
  'med-admission-barrons',
  'hard',
  'What is an omphalocele?',
  'Ce este omfalocelul?',
  '["Heart defect","Abdominal wall defect with herniation of bowel covered by peritoneum","Kidney defect","Lung abnormality","Brain defect"]'::jsonb,
  '["Defect cardiac","Defect de perete abdominal cu hernie de intestin acoperit de peritoneu","Defect renal","Anomalie pulmonară","Defect cerebral"]'::jsonb,
  1,
  'Omphalocele is midline abdominal wall defect at the umbilicus with herniated viscera covered by peritoneum, often associated with other anomalies.',
  'Omfalocelul este un defect de perete abdominal median la ombelic cu viscere herniate acoperite de peritoneu, adesea asociat cu alte anomalii.',
  'embryology',
  7
) ON CONFLICT (id) DO UPDATE SET
