  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb64',
  'med-admission-barrons',
  'hard',
  'What is gastroschisis?',
  'Ce este gastroschizisul?',
  '["Covered abdominal defect","Lateral abdominal wall defect with exposed bowel not covered by membrane","Heart defect","Kidney defect","Lung defect"]'::jsonb,
  '["Defect abdominal acoperit","Defect de perete abdominal lateral cu intestin expus neacoperit de membrană","Defect cardiac","Defect renal","Defect pulmonar"]'::jsonb,
  1,
  'Gastroschisis is a lateral (usually right) abdominal wall defect with exposed intestines not covered by peritoneum, usually isolated.',
  'Gastroschizisul este un defect de perete abdominal lateral (de obicei drept) cu intestine expuse neacoperite de peritoneu, de obicei izolat.',
  'embryology',
  7
) ON CONFLICT (id) DO UPDATE SET
