INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb65',
  'med-admission-barrons',
  'hard',
  'What is esophageal atresia?',
  'Ce este atrezia esofagiană?',
  '["Normal esophagus","Congenital absence of part of esophagus, often with tracheoesophageal fistula","Esophageal cancer","Acid reflux","Esophageal spasm"]'::jsonb,
  '["Esofag normal","Absența congenitală a unei părți a esofagului, adesea cu fistulă traheo-esofagiană","Cancer esofagian","Reflux acid","Spasm esofagian"]'::jsonb,
  1,
  'Esophageal atresia is incomplete formation of the esophagus, often with a tracheoesophageal fistula connecting esophagus to trachea.',
  'Atrezia esofagiană este formarea incompletă a esofagului, adesea cu o fistulă traheo-esofagiană care conectează esofagul la trahee.',
  'embryology',
  7
) ON CONFLICT (id) DO UPDATE SET
