INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb66',
  'med-admission-barrons',
  'hard',
  'What is the most common congenital heart defect?',
  'Care este cel mai frecvent defect cardiac congenital?',
  '["Tetralogy of Fallot","Ventricular septal defect (VSD)","Atrial septal defect","Patent ductus arteriosus","Coarctation of aorta"]'::jsonb,
  '["Tetralogia Fallot","Defect septal ventricular (DSV)","Defect septal atrial","Ductus arteriosus patent","Coarctația aortei"]'::jsonb,
  1,
  'VSD is the most common congenital heart defect, ranging from small defects that close spontaneously to large defects requiring surgery.',
  'DSV este cel mai frecvent defect cardiac congenital, variind de la defecte mici care se închid spontan la defecte mari care necesită intervenție chirurgicală.',
  'embryology',
  7
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
