  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb67',
  'med-admission-barrons',
  'hard',
  'What is the tetralogy of Fallot?',
  'Ce este tetralogia Fallot?',
  '["Single heart defect","Four defects: VSD, overriding aorta, pulmonary stenosis, right ventricular hypertrophy","Two defects","Three defects","Five defects"]'::jsonb,
  '["Defect cardiac unic","Patru defecte: DSV, aortă călare, stenoză pulmonară, hipertrofie ventriculară dreaptă","Două defecte","Trei defecte","Cinci defecte"]'::jsonb,
  1,
  'Tetralogy of Fallot includes VSD, overriding aorta, pulmonary stenosis, and right ventricular hypertrophy, causing cyanosis ("blue baby").',
  'Tetralogia Fallot include DSV, aortă călare, stenoză pulmonară și hipertrofie ventriculară dreaptă, cauzând cianoză ("copil albastru").',
  'embryology',
  7
) ON CONFLICT (id) DO UPDATE SET
