  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb68',
  'med-admission-barrons',
  'hard',
  'What causes congenital diaphragmatic hernia?',
  'Ce cauzează hernia diafragmatică congenitală?',
  '["Muscle weakness","Failure of diaphragm to close allowing abdominal organs into chest","Lung disease","Heart defect","Rib abnormality"]'::jsonb,
  '["Slăbiciune musculară","Eșecul diafragmului de a se închide permițând organelor abdominale să intre în torace","Boală pulmonară","Defect cardiac","Anomalie costală"]'::jsonb,
  1,
  'Congenital diaphragmatic hernia results from failure of the pleuroperitoneal membrane to close, allowing abdominal contents to herniate into chest and compress lungs.',
  'Hernia diafragmatică congenitală rezultă din eșecul membranei pleuroperitoneale de a se închide, permițând conținutului abdominal să hernieze în torace și să comprime plămânii.',
  'embryology',
  7
) ON CONFLICT (id) DO UPDATE SET
