  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb69',
  'med-admission-barrons',
  'hard',
  'What is meconium?',
  'Ce este meconiul?',
  '["Breast milk","First fetal stool, composed of swallowed amniotic fluid and GI secretions","Amniotic fluid","Vernix","Lanugo"]'::jsonb,
  '["Lapte matern","Primul scaun fetal, compus din lichid amniotic înghițit și secreții GI","Lichid amniotic","Vernix","Lanugo"]'::jsonb,
  1,
  'Meconium is the first stool of the newborn, composed of intestinal epithelial cells, lanugo, mucus, and swallowed amniotic fluid.',
  'Meconiul este primul scaun al nou-născutului, compus din celule epiteliale intestinale, lanugo, mucus și lichid amniotic înghițit.',
  'embryology',
  7
) ON CONFLICT (id) DO UPDATE SET
