INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb70',
  'med-admission-barrons',
  'hard',
  'What is vernix caseosa?',
  'Ce este vernix caseosa?',
  '["First stool","Waxy coating protecting fetal skin in utero","Amniotic fluid","Fetal hair","Placental membrane"]'::jsonb,
  '["Primul scaun","Înveliș ceros care protejează pielea fetală în uter","Lichid amniotic","Păr fetal","Membrană placentară"]'::jsonb,
  1,
  'Vernix caseosa is a waxy, cheese-like substance that coats and protects fetal skin from the aqueous amniotic environment.',
  'Vernix caseosa este o substanță ceroasă, ca brânza, care acoperă și protejează pielea fetală de mediul apos amniotic.',
