INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb71',
  'med-admission-barrons',
  'hard',
  'What is lanugo?',
  'Ce este lanugo?',
  '["Fetal stool","Fine hair covering the fetus that is usually shed before birth","Waxy coating","Amniotic fluid","Vernix"]'::jsonb,
  '["Scaun fetal","Păr fin care acoperă fătul și care este de obicei pierdut înainte de naștere","Înveliș ceros","Lichid amniotic","Vernix"]'::jsonb,
  1,
  'Lanugo is fine, downy hair covering the fetus from about week 14, usually shed by term; persistence may indicate prematurity.',
  'Lanugo este păr fin, pufos care acoperă fătul de la aproximativ săptămâna 14, de obicei pierdut la termen; persistența poate indica prematuritate.',
