INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb72',
  'med-admission-barrons',
  'hard',
  'What is intrauterine growth restriction (IUGR)?',
  'Ce este restricția de creștere intrauterină (RCIU)?',
  '["Large baby","Fetus smaller than expected for gestational age","Normal growth","Postterm pregnancy","Multiple pregnancy"]'::jsonb,
  '["Copil mare","Făt mai mic decât așteptat pentru vârsta gestațională","Creștere normală","Sarcină postterm","Sarcină multiplă"]'::jsonb,
  1,
  'IUGR is fetal growth below the 10th percentile for gestational age, often due to placental insufficiency, maternal disease, or genetic factors.',
  'RCIU este creșterea fetală sub percentila 10 pentru vârsta gestațională, adesea din cauza insuficienței placentare, bolii materne sau factorilor genetici.',
  'embryology',
  8
) ON CONFLICT (id) DO UPDATE SET
