  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb73',
  'med-admission-barrons',
  'hard',
  'What is macrosomia?',
  'Ce este macrosomia?',
  '["Small baby","Fetus/newborn larger than 4000-4500g","Normal size","Premature baby","Postmature baby"]'::jsonb,
  '["Copil mic","Făt/nou-născut mai mare de 4000-4500g","Dimensiune normală","Copil prematur","Copil postmatur"]'::jsonb,
  1,
  'Macrosomia is birth weight >4000-4500g, often associated with maternal diabetes, increasing risk of birth trauma and cesarean delivery.',
  'Macrosomia este greutate la naștere >4000-4500g, adesea asociată cu diabetul matern, crescând riscul de traumă la naștere și naștere prin cezariană.',
  'embryology',
  8
) ON CONFLICT (id) DO UPDATE SET
