  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb74',
  'med-admission-barrons',
  'hard',
  'What is preterm birth?',
  'Ce este nașterea prematură?',
  '["Birth after 42 weeks","Birth before 37 completed weeks","Birth at 40 weeks","Birth at term","Post-term birth"]'::jsonb,
  '["Naștere după 42 săptămâni","Naștere înainte de 37 săptămâni complete","Naștere la 40 săptămâni","Naștere la termen","Naștere post-termen"]'::jsonb,
  1,
  'Preterm birth is delivery before 37 completed weeks of gestation, increasing risks of respiratory distress, infection, and developmental problems.',
  'Nașterea prematură este nașterea înainte de 37 săptămâni complete de gestație, crescând riscurile de detresă respiratorie, infecție și probleme de dezvoltare.',
  'embryology',
  8
) ON CONFLICT (id) DO UPDATE SET
