  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb75',
  'med-admission-barrons',
  'hard',
  'What is respiratory distress syndrome (RDS) in newborns?',
  'Ce este sindromul de detresă respiratorie (SDR) la nou-născuți?',
  '["Lung infection","Surfactant deficiency causing alveolar collapse in premature infants","Heart failure","Pneumonia","Asthma"]'::jsonb,
  '["Infecție pulmonară","Deficiență de surfactant cauzând colapsul alveolar la prematuri","Insuficiență cardiacă","Pneumonie","Astm"]'::jsonb,
  1,
  'RDS (hyaline membrane disease) results from insufficient surfactant in premature lungs, causing atelectasis and respiratory failure.',
  'SDR (boala membranelor hialine) rezultă din surfactant insuficient în plămânii prematuri, cauzând atelectazie și insuficiență respiratorie.',
  'embryology',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
