  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb76',
  'med-admission-barrons',
  'hard',
  'What is erythroblastosis fetalis?',
  'Ce este eritroblastoza fetală?',
  '["Fetal infection","Hemolytic disease from maternal antibodies attacking fetal red blood cells","Fetal anemia from blood loss","Sickle cell disease","Thalassemia"]'::jsonb,
  '["Infecție fetală","Boală hemolitică din anticorpi materni care atacă globulele roșii fetale","Anemie fetală din pierdere de sânge","Anemie falciformă","Talasemie"]'::jsonb,
  1,
  'Erythroblastosis fetalis occurs when maternal anti-Rh antibodies cross the placenta and destroy Rh-positive fetal red blood cells.',
  'Eritroblastoza fetală apare când anticorpii anti-Rh materni traversează placenta și distrug globulele roșii fetale Rh-pozitive.',
  'embryology',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
