  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb77',
  'med-admission-barrons',
  'hard',
  'What is RhoGAM used for?',
  'Pentru ce este folosit RhoGAM?',
  '["Treat anemia","Prevent Rh sensitization in Rh-negative mothers","Treat infection","Induce labor","Stop bleeding"]'::jsonb,
  '["Tratează anemia","Previne sensibilizarea Rh la mamele Rh-negative","Tratează infecția","Induce travaliul","Oprește sângerarea"]'::jsonb,
  1,
  'RhoGAM (anti-D immunoglobulin) is given to Rh-negative mothers to prevent formation of antibodies against Rh-positive fetal blood cells.',
  'RhoGAM (imunoglobulină anti-D) se administrează mamelor Rh-negative pentru a preveni formarea de anticorpi împotriva celulelor sanguine fetale Rh-pozitive.',
  'embryology',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
