  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb78',
  'med-admission-barrons',
  'hard',
  'What is a molar pregnancy?',
  'Ce este o sarcină molară?',
  '["Normal pregnancy","Abnormal placental development with no viable fetus","Twin pregnancy","Ectopic pregnancy","Late pregnancy"]'::jsonb,
  '["Sarcină normală","Dezvoltare placentară anormală fără făt viabil","Sarcină gemelară","Sarcină ectopică","Sarcină tardivă"]'::jsonb,
  1,
  'Hydatidiform mole is abnormal trophoblast proliferation creating grape-like vesicles; complete mole has no fetus, partial mole may have abnormal fetus.',
  'Mola hidatiformă este proliferarea anormală a trofoblastului creând vezicule ca strugurii; mola completă nu are făt, mola parțială poate avea făt anormal.',
  'embryology',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
