  options_ro = EXCLUDED.options_ro,
  correct_answer = EXCLUDED.correct_answer,
  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb79',
  'med-admission-barrons',
  'hard',
  'What is choriocarcinoma?',
  'Ce este coriocarcinomul?',
  '["Benign tumor","Malignant tumor arising from trophoblastic tissue","Ovarian cyst","Uterine fibroid","Normal placenta"]'::jsonb,
  '["Tumoare benignă","Tumoare malignă provenind din țesut trofoblastic","Chist ovarian","Fibrom uterin","Placentă normală"]'::jsonb,
  1,
  'Choriocarcinoma is a highly malignant tumor of trophoblastic cells that can follow molar pregnancy, normal pregnancy, or abortion; it is very responsive to chemotherapy.',
  'Coriocarcinomul este o tumoare foarte malignă a celulelor trofoblastice care poate urma unei sarcini molare, sarcini normale sau avort; este foarte responsiv la chimioterapie.',
  'embryology',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
