  explanation = EXCLUDED.explanation,
  explanation_ro = EXCLUDED.explanation_ro;

INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb80',
  'med-admission-barrons',
  'hard',
  'What is the biophysical profile?',
  'Ce este profilul biofizic?',
  '["Blood test","Ultrasound assessment of fetal well-being using five parameters","Genetic test","Cervical exam","Urine test"]'::jsonb,
  '["Analiză de sânge","Evaluare ecografică a bunăstării fetale folosind cinci parametri","Test genetic","Examinare cervicală","Test de urină"]'::jsonb,
  1,
  'The biophysical profile assesses fetal breathing, movement, tone, amniotic fluid volume, and non-stress test to evaluate fetal well-being.',
  'Profilul biofizic evaluează respirația fetală, mișcarea, tonusul, volumul de lichid amniotic și testul non-stress pentru a evalua bunăstarea fetală.',
  'embryology',
  8
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
