INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb81',
  'med-admission-barrons',
  'hard',
  'What is the non-stress test (NST)?',
  'Ce este testul non-stress (TNS)?',
  '["Blood pressure test","Monitoring fetal heart rate response to fetal movement","Genetic test","Ultrasound","Cervical exam"]'::jsonb,
  '["Test de tensiune arterială","Monitorizarea răspunsului frecvenței cardiace fetale la mișcarea fetală","Test genetic","Ecografie","Examinare cervicală"]'::jsonb,
  1,
  'NST monitors fetal heart rate accelerations with fetal movement; a reactive (normal) test shows accelerations, indicating fetal well-being.',
  'TNS monitorizează accelerațiile frecvenței cardiace fetale cu mișcarea fetală; un test reactiv (normal) arată accelerații, indicând bunăstarea fetală.',
  'embryology',
  9
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
