INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb82',
  'med-admission-barrons',
  'hard',
  'What hormones maintain pregnancy in the first trimester?',
  'Ce hormoni mențin sarcina în primul trimestru?',
  '["Oxytocin","hCG maintaining corpus luteum progesterone production","Prolactin","FSH","Estrogen only"]'::jsonb,
  '["Oxitocină","hCG menținând producția de progesteron a corpului galben","Prolactină","FSH","Doar estrogen"]'::jsonb,
  1,
  'hCG from the trophoblast maintains the corpus luteum to produce progesterone until the placenta takes over at about 10 weeks.',
  'hCG de la trofoblast menține corpul galben să producă progesteron până când placenta preia la aproximativ 10 săptămâni.',
  'embryology',
  9
) ON CONFLICT (id) DO UPDATE SET
  question = EXCLUDED.question,
  question_ro = EXCLUDED.question_ro,
  options = EXCLUDED.options,
  options_ro = EXCLUDED.options_ro,
