INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb95',
  'med-admission-barrons',
  'hard',
  'What is the difference between monozygotic and dizygotic twins?',
  'Care este diferența dintre gemenii monozigoți și dizigoți?',
  '["Same age difference","Monozygotic from one egg (identical); dizygotic from two eggs (fraternal)","Same genetics","Same placenta always","No difference"]'::jsonb,
  '["Aceeași diferență de vârstă","Monozigoți dintr-un ovul (identici); dizigoți din două ovule (fraterni)","Aceleași genetici","Întotdeauna aceeași placentă","Nicio diferență"]'::jsonb,
  1,
  'Monozygotic twins result from one fertilized egg splitting (genetically identical); dizygotic twins from two eggs fertilized by different sperm.',
  'Gemenii monozigoți rezultă dintr-un ovul fertilizat care se divide (identici genetic); gemenii dizigoți din două ovule fertilizate de spermatozoizi diferiți.',
