INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb96',
  'med-admission-barrons',
  'hard',
  'What determines if monozygotic twins share a placenta?',
  'Ce determină dacă gemenii monozigoți împărtășesc o placentă?',
  '["Genetics","Timing of embryo splitting","Maternal age","Fetal sex","Placental position"]'::jsonb,
  '["Genetica","Momentul diviziunii embrionului","Vârsta maternă","Sexul fetal","Poziția placentei"]'::jsonb,
  1,
  'If splitting occurs before day 4, twins have separate placentas; days 4-8, shared placenta but separate amnions; after day 8, shared amnion (rare).',
  'Dacă diviziunea are loc înainte de ziua 4, gemenii au placente separate; zilele 4-8, placentă comună dar amnios separat; după ziua 8, amnios comun (rar).',
  'embryology',
  10
) ON CONFLICT (id) DO UPDATE SET
