INSERT INTO questions (id, category, difficulty, question, question_ro, options, options_ro, correct_answer, explanation, explanation_ro, chapter_id, set_number) VALUES (
  'emb97',
  'med-admission-barrons',
  'hard',
  'What is twin-twin transfusion syndrome?',
  'Ce este sindromul de transfuzie feto-fetală?',
  '["Normal twin pregnancy","Blood flow imbalance between monochorionic twins through placental vessels","Genetic disorder","Infection","Maternal disease"]'::jsonb,
  '["Sarcină gemelară normală","Dezechilibru al fluxului sanguin între gemeni monocoriali prin vase placentare","Tulburare genetică","Infecție","Boală maternă"]'::jsonb,
  1,
  'TTTS occurs in monochorionic twins when blood flows unequally through shared placental vessels, causing one twin to be anemic and one to be polycythemic.',
  'SFTT apare la gemenii monocoriali când sângele curge inegal prin vase placentare comune, cauzând un geamăn să fie anemic și unul să fie policitemici.',
  'embryology',
  10
